function renderSaleLines() {
  const wrap = $('#sale-lines');
  if (!wrap) return;
  const products = state.products || [];
  if (!window._saleLines.length) {
    wrap.innerHTML = '';
    const hint = $('#sale-empty-hint');
    if (hint) hint.style.display = 'block';
  } else {
    const hint = $('#sale-empty-hint');
    if (hint) hint.style.display = 'none';
    // Grid template: name fills, qty/price/total fixed widths, ✕ fixed.
    // Using fixed widths instead of fr units prevents the Product name from
    // being squeezed when the column container is narrow.
    const ROW_GRID = 'minmax(0,1fr) 70px 90px 80px 36px';
    const headerRow = `
      <div style="display:grid;grid-template-columns:${ROW_GRID};gap:6px;align-items:center;padding:0 6px 4px;font-size:10px;font-weight:600;color:var(--text-mute);text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid var(--border);margin-bottom:4px">
        <div>Product</div>
        <div style="text-align:center">Qty</div>
        <div style="text-align:right">Unit price</div>
        <div style="text-align:right">Total</div>
        <div></div>
      </div>
    `;
    wrap.innerHTML = headerRow + window._saleLines.map((line, i) => {
      const inStock = line.productId ? productCurrentStock(line.productId) : 0;
      const overStock = line.productId && line.qty > inStock;
      const opts = products.map(p => `<option value="${p.id}" ${line.productId === p.id ? 'selected' : ''}>${escapeHtml(p.name)} · ${fmt(p.price)} · ${productCurrentStock(p.id)} in stock</option>`).join('');
      return `
        <div style="display:grid;grid-template-columns:${ROW_GRID};gap:6px;align-items:center;padding:4px 6px;background:${overStock ? 'rgba(239,68,68,.08)' : 'transparent'};border-radius:6px;min-width:0">
          <select data-line-i="${i}" data-line-k="productId" style="font-size:12px;min-width:0;width:100%;padding:6px 4px">
            <option value="">— pick product —</option>
            ${opts}
          </select>
          <input type="number" min="1" step="1" data-line-i="${i}" data-line-k="qty" value="${line.qty}" style="text-align:center;padding:6px 4px;width:100%;min-width:0" />
          <input type="number" min="0" step="0.01" data-line-i="${i}" data-line-k="unitPrice" value="${line.unitPrice}" style="text-align:right;padding:6px 4px;width:100%;min-width:0" />
          <div class="num font-bold text-right" style="padding:6px 4px;color:var(--green)">${fmt(line.qty * line.unitPrice)}</div>
          <button type="button" class="btn ghost sm" data-line-remove="${i}" style="color:var(--red);padding:4px;min-width:0;width:100%" title="Remove line">✕</button>
        </div>
        ${line.productId ? (() => {
          const p = products.find(x => x.id === line.productId) || {};
          const threshold = p.lowStockThreshold || 3;
          const color = (overStock || inStock === 0) ? 'var(--red)' : (inStock <= threshold ? 'var(--accent-2)' : 'var(--text-mute)');
          const note = overStock ? ` — only ${inStock} available, reduce qty` : (inStock === 0 ? ' — out of stock' : (inStock <= threshold ? ' · low' : ''));
          return `<div style="font-size:10px;color:${color};padding:0 8px;margin-top:-2px;font-weight:${overStock || inStock === 0 ? '600' : '400'}">📦 ${inStock} in stock${note}</div>`;
        })() : ''}
      `;
    }).join('');
    // Wire line inputs
    wrap.querySelectorAll('[data-line-i]').forEach(el => {
      el.addEventListener('change', e => {
        const i = parseInt(el.dataset.lineI);
        const k = el.dataset.lineK;
        if (k === 'productId') {
          const pid = parseInt(el.value) || null;
          window._saleLines[i].productId = pid;
          if (pid) {
            const p = (state.products || []).find(x => x.id === pid);
            if (p) {
              window._saleLines[i].name = p.name;
              window._saleLines[i].unitPrice = p.price;
            }
          }
        } else if (k === 'qty') {
          window._saleLines[i].qty = parseInt(el.value) || 0;
        } else if (k === 'unitPrice') {
          window._saleLines[i].unitPrice = parseFloat(el.value) || 0;
        }
        renderSaleLines();
        recalcSaleTotals();
      });
      // Also fire on input for unitPrice/qty so totals stay live
      if (el.type === 'number') {
        el.addEventListener('input', e => {
          const i = parseInt(el.dataset.lineI);
          const k = el.dataset.lineK;
          if (k === 'qty') window._saleLines[i].qty = parseInt(el.value) || 0;
          if (k === 'unitPrice') window._saleLines[i].unitPrice = parseFloat(el.value) || 0;
          recalcSaleTotals();
        });
      }
    });
    wrap.querySelectorAll('[data-line-remove]').forEach(b => {
      b.addEventListener('click', () => {
        const i = parseInt(b.dataset.lineRemove);
        window._saleLines.splice(i, 1);
        renderSaleLines();
        recalcSaleTotals();
      });
    });
  }
  recalcSaleTotals();
}

function recalcSaleTotals() {
  const subtotal = window._saleLines.reduce((s, l) => s + (l.qty || 0) * (l.unitPrice || 0), 0);
  const discount = parseFloat($('#sale-discount')?.value) || 0;
  const total = Math.max(0, subtotal - discount);
  const paid = parseFloat($('#sale-paid')?.value) || 0;
  const balance = Math.max(0, total - paid);
  if ($('#sale-subtotal')) $('#sale-subtotal').textContent = fmt(subtotal);
  if ($('#sale-total')) $('#sale-total').textContent = fmt(total);
  if ($('#sale-balance')) $('#sale-balance').textContent = fmt(balance);
}

function wireSaleModal() {
  // Add line button
  $('#sale-add-line').addEventListener('click', () => {
    window._saleLines.push({ productId: null, name: '', qty: 1, unitPrice: 0 });
    renderSaleLines();
  });
  // Discount + paid recalc
  $('#sale-discount').addEventListener('input', recalcSaleTotals);
  $('#sale-paid').addEventListener('input', recalcSaleTotals);

  // Customer tab switching
  function switchCust(type) {
    window._saleCust.type = type;
    $('#cust-member-fields').style.display = type === 'member' ? 'block' : 'none';
    $('#cust-walkin-fields').style.display = type === 'walkin' ? 'block' : 'none';
    $('#cust-tab-member').style.background = type === 'member' ? 'var(--accent)' : '';
    $('#cust-tab-member').style.color = type === 'member' ? 'white' : '';
    $('#cust-tab-walkin').style.background = type === 'walkin' ? 'var(--accent)' : '';
    $('#cust-tab-walkin').style.color = type === 'walkin' ? 'white' : '';
  }
  $('#cust-tab-member').addEventListener('click', () => switchCust('member'));
  $('#cust-tab-walkin').addEventListener('click', () => switchCust('walkin'));

  bindMemberPicker('sale-cust', { placeholder: 'Search member...' });

  // Start with one empty line
  window._saleLines.push({ productId: null, name: '', qty: 1, unitPrice: 0 });
  renderSaleLines();
}

function completeSale(onDone) {
  // Validate lines
  const validLines = window._saleLines
    .filter(l => l.productId && l.qty > 0 && l.unitPrice >= 0)
    .map(l => ({
      productId: l.productId,
      name: l.name,
      qty: l.qty,
      unitPrice: l.unitPrice,
      lineTotal: l.qty * l.unitPrice,
    }));
  if (!validLines.length) { toast('Add at least one item to the cart', 'error'); return; }

  // Validate customer
  let customerType, customerId, customerName, customerPhone;
  if (window._saleCust.type === 'member') {
    const mid = parseInt($('#sale-cust').value);
    if (!mid) { toast('Pick a member or switch to Walk-in', 'error'); return; }
    const m = state.members.find(x => x.id === mid);
    customerType = 'member';
    customerId = m.id;
    customerName = m.name;
    customerPhone = m.phone || null;
  } else {
    customerName = $('#sale-walkin-name').value.trim();
    const phoneInput = readPhoneInput('sale-walkin-phone');
    customerPhone = phoneInput.phone;
    if (!customerName) { toast('Walk-in customer name required', 'error'); $('#sale-walkin-name')?.focus(); return; }
    if (!phoneInput.valid) {
      toast(phoneInput.error || 'Walk-in mobile is invalid', 'error');
      document.getElementById('sale-walkin-phone-digits')?.focus();
      return;
    }
    // Auto-link to existing member if same mobile
    const matchedMember = (state.members || []).find(m => m.phone && m.phone === customerPhone);
    if (matchedMember) {
      customerType = 'member';
      customerId = matchedMember.id;
      customerName = matchedMember.name;  // use canonical name
    } else {
      customerType = 'walkin';
      customerId = null;
    }
  }

  // Stock check
  for (const line of validLines) {
    const stock = productCurrentStock(line.productId);
    if (line.qty > stock) {
      const p = state.products.find(x => x.id === line.productId);
      if (!confirm(`Only ${stock} ${p?.name || ''} in stock — you're selling ${line.qty}. Proceed anyway?`)) return;
      break;
    }
  }

  const subtotal = validLines.reduce((s,l) => s + l.lineTotal, 0);
  const discount = parseFloat($('#sale-discount').value) || 0;
  const total = Math.max(0, subtotal - discount);
  const paid = parseFloat($('#sale-paid').value) || total;   // default to fully paid
  const balance = Math.max(0, total - paid);
  const date = $('#sale-date').value || TODAY;
  const month = date.slice(0, 7);
  const method = $('#sale-method-pos').value || 'cash';
  const notes = $('#sale-notes').value.trim() || null;

  // Auto-create linked invoice
  const ref = nextInvoiceRef();
  const desc = `Sale: ${validLines.map(l => `${l.qty}× ${l.name}`).join(' · ')}${customerName ? ' — ' + customerName : ''}`;
  const newInv = {
    id: nextId(state.invoices),
    date, description: desc, amount: total, method, month, ref,
    category: 'Product', activityType: 'sale',
    sport: null, coach: null, coachId: null,
    customerId, customerName,
  };
  stampUpdate(newInv); state.invoices.push(newInv);

  const saleId = nextId(state.sales || []);
  state.sales.push({
    id: saleId, date, month,
    items: validLines, subtotal, discount, total, paid, balance,
    method, customerType, customerId, customerName, customerPhone, notes,
    invoiceId: newInv.id,
    createdAt: new Date().toISOString(),
  });

  save();
  closeModal();
  toast(`Sale complete · ${fmt(total)} QAR · invoice ${ref}` + (balance > 0 ? ` · ${fmt(balance)} balance` : ''), 'success');
  if (onDone) onDone(); else render();
}

window.viewSaleDetail = function(id) {
  const s = (state.sales || []).find(x => x.id === id);
  if (!s) return;
  const inv = s.invoiceId ? state.invoices.find(i => i.id === s.invoiceId) : null;
  const cust = customerInfo(s);
  showModal({
    title: `🛒 Sale Detail` + (inv ? ` · ${inv.ref}` : ''),
    body: `
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
        <div>
          <div class="text-mute" style="font-size:11px">Date</div>
          <div class="font-bold">${fmtDate(s.date)}</div>
        </div>
        <div>
          <div class="text-mute" style="font-size:11px">Customer</div>
          <div class="font-bold" style="${cust.isDeleted ? 'text-decoration:line-through;color:var(--text-mute)' : ''}">${escapeHtml(cust.name || 'Walk-in')}${cust.phone ? ` · ${phoneCell(cust.phone, { stop: false })}` : ''}</div>
          <div class="text-mute" style="font-size:11px">${s.historical ? 'Historical (imported)' : s.customerType === 'member' ? '🎟 Member' : '🚶 Walk-in'}${cust.nationality ? ' · 🌍 ' + escapeHtml(cust.nationality) : ''}</div>
        </div>
      </div>
      <div class="table-wrap" style="margin-bottom:12px">
        <table>
          <thead><tr><th>Item</th><th class="text-right">Qty</th><th class="text-right">Unit</th><th class="text-right">Total</th></tr></thead>
          <tbody>
            ${(s.items || []).map(it => `<tr><td>${escapeHtml(it.name)}</td><td class="text-right num">${it.qty}</td><td class="text-right num">${fmt(it.unitPrice)}</td><td class="text-right num font-bold">${fmt(it.lineTotal)}</td></tr>`).join('')}
          </tbody>
        </table>
      </div>
      <div style="background:var(--surface-2);border-radius:8px;padding:12px;font-size:13px">
        <div style="display:flex;justify-content:space-between;padding:2px 0"><span class="text-mute">Subtotal</span><span>${fmt(s.subtotal || 0)}</span></div>
        ${s.discount ? `<div style="display:flex;justify-content:space-between;padding:2px 0;color:var(--accent-2)"><span class="text-mute">Discount</span><span>−${fmt(s.discount)}</span></div>` : ''}
        <div style="display:flex;justify-content:space-between;padding:4px 0;border-top:1px solid var(--border);margin-top:4px;font-size:15px"><span class="font-bold">Total</span><span class="font-bold" style="color:var(--green)">${fmt(s.total || 0)}</span></div>
        <div style="display:flex;justify-content:space-between;padding:2px 0;margin-top:4px"><span class="text-mute">Paid</span><span>${fmt(s.paid || 0)}</span></div>
        ${(s.balance || 0) > 0 ? `<div style="display:flex;justify-content:space-between;padding:2px 0;color:var(--accent-2)"><span class="text-mute">Balance</span><span class="font-bold">${fmt(s.balance)}</span></div>` : ''}
      </div>
      ${s.notes ? `<div class="text-mute" style="font-size:12px;margin-top:10px">📝 ${escapeHtml(s.notes)}</div>` : ''}
    `,
    actions: [
      ...(inv ? [{ label: '📄 Print Invoice', class: 'btn ghost', onclick: () => { closeModal(); printInvoicePDF(inv.id); } }] : []),
      { label: 'Close', class: 'btn primary', onclick: closeModal },
    ],
  });
};

window.deleteSale = function(id) {
  if (currentRole() !== 'admin') { toast('Only admins can delete sales', 'error'); return; }
  const s = (state.sales || []).find(x => x.id === id);
  if (!s) return;
  const label = s.historical ? 'historical sale' : 'sale transaction';
  if (!confirm(`Delete this ${label}? Linked invoice (if any) will also be deleted.`)) return;
  if (s.invoiceId) state.invoices = state.invoices.filter(i => i.id !== s.invoiceId);
  state.sales = state.sales.filter(x => x.id !== id);
  save();
  render();
  toast('Sale deleted');
};

// ─── SPORTS MANAGEMENT ────────────────────────────────────────────
// Admin can add, rename, disable sports. Disabled sports remain in
// historical records but won't show in any new-registration dropdown.
PAGES.sports = (main) => {
  if (!state.settings) state.settings = {};
  if (!Array.isArray(state.settings.sports) || !state.settings.sports.length) {
    state.settings.sports = ['MMA','Boxing','Kick Boxing','Karate','Taekwondo','Gymnastic','Football','Swimming','Zumba']
      .map((name, i) => ({ name, enabled: true, order: i }));
    save();
  }

  function countUsage(sportName) {
    // Count DISTINCT members currently registered for this sport — matching the
    // Camp Members / member lists (headline sport or an active enrollment). Past
    // sports that survive only in subscription history are NOT counted here, so
    // the figure lines up with what those pages show (no double-counting).
    let count = 0;
    let hasHistory = false;
    for (const m of (state.members || [])) {
      if (m.deleted) continue;
      const current = m.sport === sportName || (m.enrollments || []).some(e => e.sport === sportName);
      if (current) count++;
      else if ((m.subscriptions || []).some(s => s.activity === sportName)) hasHistory = true;
    }
    // Stash whether ANY historical reference exists (used by the delete guard so
    // a sport with old invoices/attendance still can't be hard-deleted).
    countUsage._hasHistory = hasHistory || count > 0;
    return count;
  }

  function refresh() {
    const sports = state.settings.sports.slice().sort((a, b) => (a.order ?? 999) - (b.order ?? 999));
    const tbody = $('#sports-tbody');
    if (!tbody) return;
    tbody.innerHTML = sports.length ? sports.map((s, idx) => {
      const usage = countUsage(s.name);
      const hasHistory = countUsage._hasHistory;   // any historical reference, even if current count is 0
      const isEnabled = s.enabled !== false;
      return `
        <tr>
          <td>
            <div style="display:flex;align-items:center;gap:10px">
              <span style="font-size:18px">🥋</span>
              <div>
                <div class="font-bold">${escapeHtml(s.name)}</div>
                ${!isEnabled ? '<div class="text-mute" style="font-size:10px;color:var(--accent)">Disabled — hidden from new registrations</div>' : ''}
              </div>
            </div>
          </td>
          <td class="text-right num text-mute">${usage}</td>
          <td>
            <span class="badge ${isEnabled ? 'active' : ''}" style="${!isEnabled ? 'background:var(--surface-2);color:var(--text-mute)' : ''}">${isEnabled ? '✓ Enabled' : '✗ Disabled'}</span>
          </td>
          <td class="text-right" style="white-space:nowrap">
            <button class="btn ghost sm" onclick="moveSport('${escapeHtml(s.name)}', -1)" title="Move up" ${idx === 0 ? 'disabled' : ''}>↑</button>
            <button class="btn ghost sm" onclick="moveSport('${escapeHtml(s.name)}', 1)" title="Move down" ${idx === sports.length - 1 ? 'disabled' : ''}>↓</button>
            <button class="btn ghost sm" onclick="editSport('${escapeHtml(s.name)}')" title="Rename">✏️</button>
            ${(!isPrivateSport(s.name) && s.name !== SUMMER_CAMP) ? `<button class="btn ghost sm" onclick="makePrivateVariant('${escapeHtml(s.name)}')" title="Create a private (1:1) variant of this sport">🔒+</button>` : ''}
            <button class="btn ghost sm" onclick="toggleSport('${escapeHtml(s.name)}')" title="${isEnabled ? 'Disable (hide from new registrations)' : 'Re-enable'}">${isEnabled ? '🚫' : '✅'}</button>
            ${(usage === 0 && !hasHistory) ? `<button class="btn ghost sm" onclick="deleteSport('${escapeHtml(s.name)}')" title="Delete (only allowed when no one is registered)" style="color:var(--red)">🗑</button>` : `<button class="btn ghost sm" disabled title="Cannot delete — ${usage > 0 ? usage + ' members registered' : 'historical records reference this sport'}" style="opacity:.4">🔒</button>`}
          </td>
        </tr>
      `;
    }).join('') : `<tr><td colspan="4" class="empty">No sports defined. Click "+ Add Sport" to start.</td></tr>`;
    $('#sports-count').textContent = `${sports.length} sport${sports.length === 1 ? '' : 's'} · ${sports.filter(s => s.enabled !== false).length} enabled`;
  }

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>Sports</h1>
        <div class="subtitle"><span id="sports-count">Loading...</span></div>
      </div>
      <div class="topbar-actions">
        <button class="btn primary" onclick="addSport()">+ Add Sport</button>
      </div>
    </div>
    <div style="background:rgba(91,141,239,.06);border:1px solid rgba(91,141,239,.2);border-radius:8px;padding:12px;margin-bottom:14px;display:flex;gap:10px;align-items:flex-start">
      <div style="font-size:20px">💡</div>
      <div style="font-size:12px;color:var(--text-dim);line-height:1.5">
        Add or rename sports here. <b>Disabled sports</b> stay in historical records (past attendance, old invoices) but won't appear in new member registration. <b>Delete</b> is only allowed when no one is registered for that sport. Renaming a sport updates every historical reference too.
      </div>
    </div>
    <div class="card">
      <div class="table-wrap">
        <table>
          <thead><tr>
            <th>Sport</th>
            <th class="text-right">Members</th>
            <th>Status</th>
            <th></th>
          </tr></thead>
          <tbody id="sports-tbody"></tbody>
        </table>
      </div>
    </div>

    <div class="card" style="margin-top:14px">
      <div class="card-header">
        <div>
          <div class="card-title">🌞 Summer Camp Pricing</div>
          <div class="card-subtitle">Default prices per duration. Editable per registration. Changes here only affect future enrollments.</div>
        </div>
      </div>
      <div id="camp-prices-body" style="padding:14px"></div>
    </div>
  `;
  refresh();
  refreshCampPrices();

  function refreshCampPrices() {
    const body = $('#camp-prices-body');
    if (!body) return;
    const prices = state.settings.summerCampPrices || [];
    body.innerHTML = `
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:10px;font-size:10px;color:var(--text-mute);text-transform:uppercase;letter-spacing:.5px;font-weight:600">
        <div>Duration label</div>
        <div>Days</div>
        <div>Price (QAR)</div>
      </div>
      ${prices.map((p, i) => `
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:8px">
          <div class="field" style="margin:0"><input type="text" data-camp-i="${i}" data-camp-k="label" value="${escapeHtml(p.label)}" /></div>
          <div class="field" style="margin:0"><input type="number" min="1" step="1" data-camp-i="${i}" data-camp-k="days" value="${p.days}" /></div>
          <div class="field" style="margin:0"><input type="number" min="0" step="0.01" data-camp-i="${i}" data-camp-k="price" value="${p.price}" /></div>
        </div>
      `).join('')}
      <div style="display:flex;gap:8px;margin-top:10px">
        <button type="button" class="btn ghost sm" id="camp-add-row">+ Add tier</button>
        <button type="button" class="btn primary sm" id="camp-save">Save prices</button>
        <button type="button" class="btn ghost sm" id="camp-reset" style="color:var(--text-mute);margin-left:auto">Reset to defaults</button>
      </div>
    `;
    body.querySelectorAll('[data-camp-i]').forEach(inp => {
      inp.addEventListener('input', e => {
        const i = parseInt(e.target.dataset.campI);
        const k = e.target.dataset.campK;
        const v = e.target.value;
        if (!state.settings.summerCampPrices[i]) return;
        state.settings.summerCampPrices[i][k] = (k === 'label') ? v : (parseFloat(v) || 0);
      });
    });
    $('#camp-add-row').addEventListener('click', () => {
      state.settings.summerCampPrices.push({ label: '', days: 0, price: 0 });
      refreshCampPrices();
    });
    $('#camp-save').addEventListener('click', () => {
      // Clean: drop rows with empty label or 0 days
      state.settings.summerCampPrices = state.settings.summerCampPrices.filter(p =>
        p.label && p.label.trim() && p.days > 0
      );
      save();
      toast(`Saved ${state.settings.summerCampPrices.length} Summer Camp tiers`);
      refreshCampPrices();
    });
    $('#camp-reset').addEventListener('click', () => {
      if (!confirm('Reset Summer Camp prices to the original defaults (1d=175, 1w=650, 1m=1750, 2m=3000)?')) return;
      state.settings.summerCampPrices = [
        { label: '1 day',    days: 1,  price: 175  },
        { label: '1 week',   days: 7,  price: 650  },
        { label: '1 month',  days: 30, price: 1750 },
        { label: '2 months', days: 60, price: 3000 },
      ];
      save();
      refreshCampPrices();
      toast('Summer Camp prices reset to defaults');
    });
  }
};

window.addSport = function() {
  showModal({
    title: 'Add New Sport',
    body: `
      <div class="field">
        <label>Sport name</label>
        <input id="new-sport-name" placeholder="e.g. Jiu-Jitsu" autofocus />
      </div>
      <div class="text-mute" style="font-size:11px;margin-top:6px">
        💡 Will appear in all new-member dropdowns. Don't include emojis or special characters.
      </div>
    `,
    actions: [
      { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
      { label: 'Add', class: 'btn primary', onclick: () => {
        const name = $('#new-sport-name').value.trim();
        if (!name) { toast('Sport name required', 'error'); return; }
        if (state.settings.sports.some(s => s.name.toLowerCase() === name.toLowerCase())) {
          toast(`"${name}" already exists`, 'error');
          return;
        }
        const maxOrder = Math.max(0, ...state.settings.sports.map(s => s.order ?? 0));
        state.settings.sports.push({ name, enabled: true, order: maxOrder + 1 });
        save(); closeModal(); render();
        toast(`Sport added: ${name}`);
      }},
    ],
  });
};

// Create a "(Private)" variant of an existing sport — shares the base sport's
// icon/colour but is a separate, separately-priced sport.
window.makePrivateVariant = function(name) {
  const variant = baseSportName(name) + ' (Private)';
  if (!Array.isArray(state.settings.sports)) state.settings.sports = [];
  if (state.settings.sports.some(s => (typeof s === 'string' ? s : s.name) === variant)) { toast(`"${variant}" already exists`, 'error'); return; }
  const maxOrder = Math.max(0, ...state.settings.sports.map(s => s.order ?? 0));
  state.settings.sports.push({ name: variant, enabled: true, order: maxOrder + 1 });
  if (typeof audit === 'function') audit('sport.create', 'sport:' + variant, 'private variant of ' + name);
  save(); render();
  toast(`Added ${variant} 🔒`);
};

window.editSport = function(oldName) {
  const s = state.settings.sports.find(x => x.name === oldName);
  if (!s) return;
  showModal({
    title: `Rename Sport`,
    body: `
      <div class="field">
        <label>Current name</label>
        <input value="${escapeHtml(oldName)}" disabled style="opacity:.5" />
      </div>
      <div class="field">
        <label>New name</label>
        <input id="edit-sport-name" value="${escapeHtml(oldName)}" autofocus />
      </div>
      <div class="text-mute" style="font-size:11px;margin-top:6px">
        ⚠️ Renaming updates this sport in <b>every</b> historical record (enrollments, attendance, invoices, schedule). This is destructive — make sure you want to do this.
      </div>
    `,
    actions: [
      { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
      { label: 'Rename', class: 'btn primary', onclick: () => {
        const newName = $('#edit-sport-name').value.trim();
        if (!newName) { toast('Name required', 'error'); return; }
        if (newName === oldName) { closeModal(); return; }
        if (state.settings.sports.some(x => x.name === newName && x !== s)) {
          toast(`"${newName}" already exists`, 'error');
          return;
        }
        // Cascade rename
        s.name = newName;
        let changedCount = 0;
        for (const m of (state.members || [])) {
          if (m.sport === oldName) { m.sport = newName; changedCount++; }
          for (const e of (m.enrollments || [])) {
            if (e.sport === oldName) { e.sport = newName; changedCount++; }
          }
          for (const sub of (m.subscriptions || [])) {
            if (sub.activity === oldName) { sub.activity = newName; changedCount++; }
          }
          // Rename within attendance keys
          if (m.dailyAttendance) {
            for (const mk of Object.keys(m.dailyAttendance)) {
              const mo = m.dailyAttendance[mk];
              if (mo && typeof mo === 'object' && mo[oldName]) {
                mo[newName] = mo[oldName];
                delete mo[oldName];
                changedCount++;
              }
            }
          }
          // Rename in sport switches
          for (const sw of (m.sportSwitches || [])) {
            if (sw.fromSport === oldName) sw.fromSport = newName;
            if (sw.toSport === oldName) sw.toSport = newName;
          }
        }
        for (const c of (state.coaches || [])) {
          if (Array.isArray(c.sports)) {
            c.sports = c.sports.map(s => s === oldName ? newName : s);
          }
        }
        for (const inv of (state.invoices || [])) {
          if (inv.sport === oldName) inv.sport = newName;
          for (const li of (inv.lineItems || [])) {
            if (li.sport === oldName) li.sport = newName;
          }
        }
        for (const sc of (state.schedule || [])) {
          if (sc.sport === oldName) sc.sport = newName;
        }
        save(); closeModal(); render();
        toast(`Renamed → "${newName}" (${changedCount} record${changedCount === 1 ? '' : 's'} updated)`);
      }},
    ],
  });
};

window.toggleSport = function(name) {
  const s = state.settings.sports.find(x => x.name === name);
  if (!s) return;
  s.enabled = !(s.enabled !== false); // flip
  save(); render();
  toast(`${name} ${s.enabled ? 'enabled' : 'disabled'}`);
};

window.deleteSport = function(name) {
  if (!confirm(`Delete sport "${name}"? This is only allowed because no member is currently enrolled in it. This cannot be undone.`)) return;
  state.settings.sports = state.settings.sports.filter(s => s.name !== name);
  save(); render();
  toast(`Deleted: ${name}`);
};

window.moveSport = function(name, delta) {
  const sports = state.settings.sports;
  sports.sort((a, b) => (a.order ?? 999) - (b.order ?? 999));
  const idx = sports.findIndex(s => s.name === name);
  if (idx < 0) return;
  const newIdx = idx + delta;
  if (newIdx < 0 || newIdx >= sports.length) return;
  // Swap
  [sports[idx], sports[newIdx]] = [sports[newIdx], sports[idx]];
  // Re-number
  sports.forEach((s, i) => s.order = i);
  save(); render();
};

// ─── SETTINGS ──────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════
// AUDIT LOG PAGE — view who changed what, when.
// Read-only. Records hooked from key actions in app.js audit() helper.
// ═══════════════════════════════════════════════════════════════════
PAGES.audit = (main) => {
  // Admin-only, hard guard (req #8) — Reception/Coach/Member never see this.
  if (currentRole() !== 'admin') {
    main.innerHTML = `<div class="card" style="text-align:center;padding:40px"><div style="font-size:40px">🔒</div><h2>${t('Admins only', 'للمسؤولين فقط')}</h2><div class="text-mute">${t('The Audit Trail is restricted to administrators.', 'سجل التدقيق متاح للمسؤولين فقط.')}</div></div>`;
    return;
  }
  let filter = { search: '', module: 'all', action: 'all', user: 'all', from: '', to: '' };
  const pg = makePager(50);

  // Short display of an old/new value (primitive or small object).
  const fmtVal = (v) => {
    if (v == null) return '';
    if (typeof v === 'object') { try { return Object.entries(v).map(([k, x]) => `${k}: ${x}`).join(', '); } catch (_) { return JSON.stringify(v); } }
    return String(v);
  };
  // Everything an entry can be searched by (req #8 search: member name, mobile, invoice#, username).
  const hayOf = (e) => {
    const d = e.details || {};
    return [e.action, e.module, e.target, e.summary, e.user, e.userName, e.role, e.recordName, e.recId,
      d.mobile, d.phone, d.membershipNo, d.invoiceRef, d.ref, e.recType].filter(Boolean).join(' ').toLowerCase();
  };
  // Rows for export (CSV / Excel / PDF) — full detail.
  const HEADER = ['When', 'Username', 'Full Name', 'Role', 'Module', 'Action', 'Record ID', 'Record Name', 'Description', 'Previous Value', 'New Value'];
  const exportRow = (e) => [
    e.ts || '', e.user || '', e.userName || '', e.role || '', e.module || (e.action || '').split('.')[0],
    e.action || '', e.recId || '', e.recordName || '', e.summary || '', fmtVal(e.oldValue), fmtVal(e.newValue),
  ];

  function currentAll() {
    const log = Array.isArray(state.auditLog) ? state.auditLog : [];
    const sorted = [...log].sort((a, b) => (b.ts || '').localeCompare(a.ts || ''));   // newest first
    const fromISO = filter.from ? filter.from + 'T00:00:00.000Z' : null;
    const toISO = filter.to ? filter.to + 'T23:59:59.999Z' : null;
    return sorted.filter(e => {
      if (fromISO && (e.ts || '') < fromISO) return false;
      if (toISO && (e.ts || '') > toISO) return false;
      if (filter.module !== 'all' && (e.module || (e.action || '').split('.')[0]) !== filter.module) return false;
      if (filter.action !== 'all' && e.action !== filter.action) return false;
      if (filter.user !== 'all' && e.user !== filter.user) return false;
      if (filter.search && !hayOf(e).includes(filter.search.toLowerCase())) return false;
      return true;
    });
  }

  function refresh() {
    const all = currentAll();
    const rows = paginate(all, pg);
    $('#audit-count').textContent = `${all.length} ${t('entries', 'سجل')}`;
    $('#audit-tbody').innerHTML = rows.length ? rows.map(e => {
      const ts = new Date(e.ts);
      const dateStr = isNaN(ts) ? '—' : ts.toLocaleString('en-GB', { day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit', hour12:false });
      const act = e.action || '';
      const actionColor = /delete|archive|purge|cancel|refund|unfreeze/.test(act) ? 'var(--red)'
                       : /create|restore|paid|add/.test(act) ? 'var(--green)'
                       : /freeze|withdraw/.test(act) ? 'var(--accent-2)' : 'var(--blue)';
      const change = (e.oldValue != null || e.newValue != null)
        ? `<div class="text-mute" style="font-size:10px;margin-top:2px">${e.oldValue != null ? `<span style="color:var(--red)">${escapeHtml(fmtVal(e.oldValue))}</span> → ` : ''}<span style="color:var(--green)">${escapeHtml(fmtVal(e.newValue))}</span></div>`
        : '';
      return `
        <tr>
          <td class="text-mute" style="white-space:nowrap;font-size:11px">${dateStr}</td>
          <td style="font-size:11px"><div class="font-bold">${escapeHtml(e.userName || e.user || 'unknown')}</div><div class="text-mute" style="font-size:10px">${escapeHtml(e.user || '')}${e.role ? ` · ${escapeHtml(e.role)}` : ''}</div></td>
          <td><span class="badge" style="font-size:10px">${escapeHtml(e.module || act.split('.')[0])}</span></td>
          <td><span class="badge" style="font-family:'JetBrains Mono',monospace;font-size:10px;color:${actionColor}">${escapeHtml(act)}</span></td>
          <td style="font-size:11px">${e.recordName ? `<div class="font-bold">${escapeHtml(e.recordName)}</div>` : ''}${e.recId ? `<div class="text-mute" style="font-family:monospace;font-size:10px">#${escapeHtml(String(e.recId))}</div>` : ''}</td>
          <td style="font-weight:500;font-size:12px">${escapeHtml(e.summary || '—')}${change}</td>
        </tr>`;
    }).join('') : `<tr><td colspan="6" class="empty"><div class="empty-icon">📋</div>${t('No audit entries match these filters', 'لا توجد سجلات مطابقة')}</td></tr>`;
    $('#audit-pagination').innerHTML = paginationBar(pg, all.length, 'audit');
    bindPagination('audit', pg, all.length, refresh);
  }

  const log = Array.isArray(state.auditLog) ? state.auditLog : [];
  const modules = [...new Set(log.map(e => e.module || (e.action || '').split('.')[0]))].filter(Boolean).sort();
  const actions = [...new Set(log.map(e => e.action))].filter(Boolean).sort();
  const users = [...new Set(log.map(e => e.user))].filter(Boolean).sort();

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>📋 ${t('Audit Trail', 'سجل التدقيق')}</h1>
        <div class="subtitle"><span id="audit-count">Loading…</span> · ${t('immutable — records cannot be edited or deleted', 'غير قابل للتعديل — لا يمكن تحرير السجلات أو حذفها')}</div>
      </div>
      <div class="topbar-actions">
        <button class="btn ghost" id="audit-xlsx">📊 ${t('Excel', 'إكسل')}</button>
        <button class="btn ghost" id="audit-pdf">📄 ${t('PDF', 'PDF')}</button>
        <button class="btn ghost" id="audit-csv">📥 ${t('CSV', 'CSV')}</button>
      </div>
    </div>
    <div class="card">
      <div class="filter-bar" style="flex-wrap:wrap;gap:8px">
        <div class="search"><input id="audit-search" type="text" placeholder="${t('Search member, mobile, invoice #, username…', 'ابحث بالعضو أو الجوال أو رقم الفاتورة أو المستخدم…')}" /></div>
        <select id="audit-module" class="btn ghost">
          <option value="all">${t('All modules', 'كل الوحدات')}</option>
          ${modules.map(p => `<option value="${escapeHtml(p)}">${escapeHtml(p)}</option>`).join('')}
        </select>
        <select id="audit-action" class="btn ghost">
          <option value="all">${t('All actions', 'كل الإجراءات')}</option>
          ${actions.map(p => `<option value="${escapeHtml(p)}">${escapeHtml(p)}</option>`).join('')}
        </select>
        <select id="audit-user" class="btn ghost">
          <option value="all">${t('All users', 'كل المستخدمين')}</option>
          ${users.map(p => `<option value="${escapeHtml(p)}">${escapeHtml(p)}</option>`).join('')}
        </select>
        <div style="display:flex;align-items:center;gap:4px" title="${t('Date range', 'نطاق التاريخ')}">
          <span class="text-mute" style="font-size:11px">${t('From', 'من')}</span>
          <input id="audit-from" type="date" class="btn ghost" style="padding:6px 8px" />
          <span class="text-mute" style="font-size:11px">${t('To', 'إلى')}</span>
          <input id="audit-to" type="date" class="btn ghost" style="padding:6px 8px" />
        </div>
        <button id="audit-clear-filters" class="btn ghost" title="${t('Clear filters', 'مسح الفلاتر')}">✕ ${t('Clear', 'مسح')}</button>
      </div>
      <div class="table-wrap">
        <table>
          <thead><tr>
            <th style="width:130px">${t('When', 'الوقت')}</th>
            <th style="width:130px">${t('User', 'المستخدم')}</th>
            <th style="width:90px">${t('Module', 'الوحدة')}</th>
            <th style="width:130px">${t('Action', 'الإجراء')}</th>
            <th style="width:140px">${t('Record', 'السجل')}</th>
            <th>${t('Description', 'الوصف')}</th>
          </tr></thead>
          <tbody id="audit-tbody"></tbody>
        </table>
      </div>
      <div id="audit-pagination"></div>
    </div>
  `;
  $('#audit-search').addEventListener('input', e => { filter.search = e.target.value; pg.page = 1; refresh(); });
  attachRecentSearch('audit-search', 'audit');
  $('#audit-module').addEventListener('change', e => { filter.module = e.target.value; pg.page = 1; refresh(); });
  $('#audit-action').addEventListener('change', e => { filter.action = e.target.value; pg.page = 1; refresh(); });
  $('#audit-user').addEventListener('change', e => { filter.user = e.target.value; pg.page = 1; refresh(); });
  $('#audit-from').addEventListener('change', e => { filter.from = e.target.value; pg.page = 1; refresh(); });
  $('#audit-to').addEventListener('change', e => { filter.to = e.target.value; pg.page = 1; refresh(); });
  $('#audit-clear-filters').addEventListener('click', () => { filter = { search: '', module: 'all', action: 'all', user: 'all', from: '', to: '' }; pg.page = 1; PAGES.audit(main); });
  $('#audit-csv').addEventListener('click', () => {
    const all = currentAll();
    if (!all.length) { toast('Nothing to export', 'error'); return; }
    const csv = [HEADER, ...all.map(exportRow)]
      .map(r => r.map(c => `"${String(c == null ? '' : c).replace(/"/g, '""')}"`).join(',')).join('\n');
    downloadFile(`audit-trail-${TODAY}.csv`, csv, 'text/csv');
    toast(`Exported ${all.length} entries`);
  });
  $('#audit-xlsx').addEventListener('click', async () => {
    const all = currentAll();
    if (!all.length) { toast('Nothing to export', 'error'); return; }
    if (!window.XlsxMini) { toast('Excel export unavailable', 'error'); return; }
    try {
      await window.XlsxMini.downloadFile(`audit-trail-${TODAY}.xlsx`, { sheets: [{ name: 'Audit Trail', rows: [HEADER, ...all.map(exportRow)] }] });
      toast(`📊 Exported ${all.length} entries to Excel`);
    } catch (err) { toast('Excel export failed: ' + (err.message || err), 'error'); }
  });
  $('#audit-pdf').addEventListener('click', () => {
    const all = currentAll();
    if (!all.length) { toast('Nothing to export', 'error'); return; }
    const esc = (s) => String(s == null ? '' : s).replace(/[&<>]/g, c => ({ '&':'&amp;','<':'&lt;','>':'&gt;' }[c]));
    const body = all.map(e => `<tr><td>${esc((e.ts||'').replace('T',' ').slice(0,16))}</td><td>${esc(e.userName||e.user)}<br><small>${esc(e.user)} · ${esc(e.role||'')}</small></td><td>${esc(e.module||'')}</td><td>${esc(e.action||'')}</td><td>${esc(e.recordName||'')}${e.recId?(' #'+esc(e.recId)):''}</td><td>${esc(e.summary||'')}${(e.oldValue!=null||e.newValue!=null)?`<br><small>${esc(fmtVal(e.oldValue))} → ${esc(fmtVal(e.newValue))}</small>`:''}</td></tr>`).join('');
    const html = `<!doctype html><html><head><meta charset="utf-8"><title>Audit Trail ${TODAY}</title>
      <style>@page{size:landscape;margin:10mm}body{font-family:Arial,sans-serif;color:#111;padding:6px}h1{font-size:16px}table{width:100%;border-collapse:collapse;font-size:9px}th,td{border:1px solid #ccc;padding:3px 5px;text-align:left;vertical-align:top}th{background:#f0f0f0}small{color:#666}</style>
      </head><body onload="window.print()"><h1>Black Stars Sports — Audit Trail (${all.length} entries · ${TODAY})</h1>
      <table><thead><tr><th>When</th><th>User</th><th>Module</th><th>Action</th><th>Record</th><th>Description</th></tr></thead><tbody>${body}</tbody></table></body></html>`;
    const w = window.open('', '_blank');
    if (w) { w.document.write(html); w.document.close(); } else { toast('Allow pop-ups to export PDF', 'error'); }
  });
  refresh();
};

PAGES.settings = (main, section) => {
  // Ensure settings exists
  if (!state.settings) state.settings = {};
  const cur = state.settings;

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>Settings</h1>
        <div class="subtitle">Application configuration</div>
      </div>
    </div>

    <div class="card" data-sset="preferences">
      <div class="card-header"><div><div class="card-title">${t('Appearance', 'المظهر')}</div><div class="card-subtitle">Choose how the app looks — your selection is saved per browser</div></div></div>
      <div id="theme-picker" style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-top:6px">
        <div class="theme-card" data-theme-value="dark" style="cursor:pointer;border:2px solid ${getTheme()==='dark'?'var(--accent)':'var(--border)'};border-radius:10px;padding:14px;background:#0a0e1a;color:#e8eaf0">
          <div style="display:flex;gap:6px;margin-bottom:10px">
            <span style="width:18px;height:18px;border-radius:50%;background:#f26060"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#f2a33c"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#5b8def"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#10b981"></span>
          </div>
          <div style="font-weight:700;font-size:14px">🌙 Dark</div>
          <div style="font-size:11px;opacity:.7;margin-top:2px">Default · easy at night</div>
          ${getTheme()==='dark'?'<div style="margin-top:8px;font-size:11px;color:#f26060;font-weight:600">✓ Active</div>':''}
        </div>
        <div class="theme-card" data-theme-value="light" style="cursor:pointer;border:2px solid ${getTheme()==='light'?'var(--accent)':'var(--border)'};border-radius:10px;padding:14px;background:#f5f6fa;color:#1a1d2b">
          <div style="display:flex;gap:6px;margin-bottom:10px">
            <span style="width:18px;height:18px;border-radius:50%;background:#e54d4d"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#e89331"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#3a6fd6"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#0d8f63"></span>
          </div>
          <div style="font-weight:700;font-size:14px">☀️ Light</div>
          <div style="font-size:11px;opacity:.7;margin-top:2px">Bright · daytime work</div>
          ${getTheme()==='light'?'<div style="margin-top:8px;font-size:11px;color:#e54d4d;font-weight:600">✓ Active</div>':''}
        </div>
        <div class="theme-card" data-theme-value="cream" style="cursor:pointer;border:2px solid ${getTheme()==='cream'?'var(--accent)':'var(--border)'};border-radius:10px;padding:14px;background:#f7f2e8;color:#2d2a1f">
          <div style="display:flex;gap:6px;margin-bottom:10px">
            <span style="width:18px;height:18px;border-radius:50%;background:#4a7c3a"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#c97a2a"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#2f6d8f"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#a8842a"></span>
          </div>
          <div style="font-weight:700;font-size:14px">📜 Soft Cream</div>
          <div style="font-size:11px;opacity:.7;margin-top:2px">Paper-like · easy reading</div>
          ${getTheme()==='cream'?'<div style="margin-top:8px;font-size:11px;color:#4a7c3a;font-weight:600">✓ Active</div>':''}
        </div>
        <div class="theme-card" data-theme-value="colorful" style="cursor:pointer;border:2px solid ${getTheme()==='colorful'?'var(--accent)':'var(--border)'};border-radius:10px;padding:14px;background:linear-gradient(135deg,#1a0f2e,#2f1d44);color:#f5e9ff">
          <div style="display:flex;gap:6px;margin-bottom:10px">
            <span style="width:18px;height:18px;border-radius:50%;background:#ff4d8d"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#ffb340"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#5cd6ff"></span>
            <span style="width:18px;height:18px;border-radius:50%;background:#c77dff"></span>
          </div>
          <div style="font-weight:700;font-size:14px">🎨 Colorful</div>
          <div style="font-size:11px;opacity:.7;margin-top:2px">Vibrant · energetic</div>
          ${getTheme()==='colorful'?'<div style="margin-top:8px;font-size:11px;color:#ff4d8d;font-weight:600">✓ Active</div>':''}
        </div>
      </div>
    </div>

    <div class="card" data-sset="preferences">
      <div class="card-header"><div><div class="card-title">${t('Preferences', 'التفضيلات')}</div><div class="card-subtitle">Customize alerts and thresholds</div></div></div>
      <div class="form-row">
        <div class="field">
          <label>Expiring-soon alert (days before expiry)</label>
          <input id="pref-expdays" type="number" min="1" max="60" value="${cur.expiringSoonDays || 3}" />
          <div class="text-mute" style="font-size:11px;margin-top:4px">Members are flagged as "expiring soon" this many days before their expiry date.</div>
        </div>
        <div class="field">
          <label>Recently-expired window (days)</label>
          <input id="pref-recentexp" type="number" min="1" max="90" value="${cur.recentlyExpiredDays || 15}" />
          <div class="text-mute" style="font-size:11px;margin-top:4px">The Expiring page's "Recently expired" button shows members who expired within this many days (win-back window).</div>
        </div>
        <div class="field">
          <label>Low stock threshold (units)</label>
          <input id="pref-lowstock" type="number" min="0" max="100" value="${cur.lowStockThreshold ?? 3}" />
          <div class="text-mute" style="font-size:11px;margin-top:4px">Inventory items at or below this count are flagged LOW.</div>
        </div>
      </div>
      <div class="form-row">
        <div class="field">
          <label>Duplicate QID handling</label>
          <select id="pref-qidmode">
            <option value="block" ${(cur.qidDuplicateMode || 'block') === 'block' ? 'selected' : ''}>Block &amp; open the existing member (recommended)</option>
            <option value="warn" ${cur.qidDuplicateMode === 'warn' ? 'selected' : ''}>Warn only — allow saving after confirmation</option>
          </select>
          <div class="text-mute" style="font-size:11px;margin-top:4px">A national ID belongs to one person. "Block" reopens the existing record; "Warn" lets you save anyway after a confirmation. (Mobile + Name duplicates are always blocked.)</div>
        </div>
      </div>
      <div class="form-row">
        <div class="field">
          <label>Refund grace period (days)</label>
          <input id="pref-refundgrace" type="number" min="0" max="90" value="${cur.refundGraceDays ?? 7}" />
          <div class="text-mute" style="font-size:11px;margin-top:4px">Within this many days of a sport's start, a withdrawal refunds the full unused amount (no admin fee).</div>
        </div>
        <div class="field">
          <label>Admin fee after grace (%)</label>
          <input id="pref-refundfee" type="number" min="0" max="100" value="${cur.refundFeePct ?? 20}" />
          <div class="text-mute" style="font-size:11px;margin-top:4px">After the grace period, this % of the unused amount is kept as an admin fee on withdrawals. (You can still override the refund per withdrawal.)</div>
        </div>
      </div>
      ${currentRole() === 'admin' ? `
      <div class="form-row">
        <div class="field">
          <label>🔒 ${t('Auto sign-out after inactivity (minutes)', 'تسجيل خروج تلقائي بعد الخمول (دقائق)')}</label>
          <input id="pref-idlemin" type="number" min="0" max="240" step="1" value="${cur.idleLogoutMin ?? 10}" />
          <div class="text-mute" style="font-size:11px;margin-top:4px">${t('When the app sits idle this long, a dialog asks to Continue the session or Log out (auto sign-out if ignored). Active use — clicks, typing, mouse movement — never triggers it. Set 0 to disable auto sign-out.', 'عند خمول التطبيق لهذه المدة يظهر مربع لمتابعة الجلسة أو تسجيل الخروج (خروج تلقائي إذا تُرك). الاستخدام النشط لا يفعّله. اضبط 0 للتعطيل.')}</div>
        </div>
      </div>` : ''}
      <div style="margin-top:12px"><button class="btn primary" id="save-prefs">💾 Save preferences</button></div>
    </div>

    <div class="card" data-sset="club">
      <div class="card-header"><div><div class="card-title">${t('Coach Commission Rates', 'نسب عمولة المدربين')}</div><div class="card-subtitle">Commission is calculated as this % of each coach's total paid amount (subscription value)</div></div></div>
      <div style="background:var(--surface-2);border-radius:8px;padding:12px;margin-bottom:14px">
        <label style="font-weight:600;font-size:13px;display:block;margin-bottom:6px">Commission basis</label>
        <select id="pref-commbasis" style="min-width:300px">
          <option value="payment" ${(cur.commissionBasis || 'payment') === 'payment' ? 'selected' : ''}>By payment — full fee counts in the month paid (current)</option>
          <option value="attendance" ${cur.commissionBasis === 'attendance' ? 'selected' : ''}>By attendance — per class attended; the rest shows as pending</option>
        </select>
        <div class="text-mute" style="font-size:11px;margin-top:6px;line-height:1.5">
          <b>By payment</b> is the original behaviour. <b>By attendance</b> pays each coach per class the member actually attends, in the month attended; paid-but-unattended classes appear as <b>pending</b> and pay out as they're attended or when the membership ends. Memberships with no class count and sport-switch credits stay on the payment basis. This changes how payroll is calculated from now on — it does <b>not</b> rewrite past payments. <b>Requires attendance to be marked each month.</b>
        </div>
      </div>
      <div class="table-wrap">
        <table>
          <thead><tr><th>Coach</th><th>Status</th><th style="width:160px">Commission rate (%)</th></tr></thead>
          <tbody>
            ${state.coaches.map(c => `
              <tr style="${isCoachActive(c) ? '' : 'opacity:.55'}">
                <td>
                  <div style="display:flex;align-items:center;gap:10px">
                    <div class="avatar" style="width:28px;height:28px;font-size:10px;background:linear-gradient(135deg,var(--blue),var(--purple))">${initials(c.name)}</div>
                    <span class="font-bold">${escapeHtml(c.name)}</span>
                  </div>
                </td>
                <td><span class="badge ${isCoachActive(c) ? 'active' : 'expired'}" style="font-size:9px">${isCoachActive(c) ? 'Active' : 'Inactive'}</span></td>
                <td><input class="comm-rate" data-coach="${c.id}" type="number" min="0" max="100" step="0.5" value="${c.rate}" style="width:120px" /></td>
              </tr>`).join('')}
          </tbody>
        </table>
      </div>
      <div style="margin-top:12px"><button class="btn primary" id="save-commissions">💾 Save commission rates</button></div>
    </div>

    <div class="card" data-sset="club">
      <div class="card-header"><div><div class="card-title">💸 Expense Categories</div><div class="card-subtitle">Customize the categories shown in the New Expense form. "Others" is always available and cannot be removed.</div></div></div>
      <div id="cat-rows" style="display:flex;flex-direction:column;gap:6px;margin-bottom:12px">
        ${EXP_CATS.map((c, i) => {
          const usage = (state.expenses || []).filter(e => e.category === c).length;
          const isReserved = RESERVED_EXPENSE_CATEGORIES.includes(c);
          const canDelete = !isReserved && usage === 0;
          return `
            <div class="cat-row" data-cat="${escapeHtml(c)}" style="display:flex;align-items:center;gap:10px;padding:8px 12px;background:var(--surface-2);border-radius:8px;border:1px solid var(--border)">
              <span style="font-size:14px;font-weight:600;flex:1">${escapeHtml(c)}${isReserved ? ' <span class="badge" style="font-size:9px;padding:1px 6px;margin-left:6px">RESERVED</span>' : ''}</span>
              <span class="text-mute" style="font-size:11px">${usage} use${usage === 1 ? '' : 's'}</span>
              ${canDelete
                ? `<button class="btn ghost sm" data-cat-delete="${escapeHtml(c)}" style="color:var(--red)" title="Delete this category">🗑</button>`
                : `<button class="btn ghost sm" disabled style="opacity:.4" title="${isReserved ? 'Reserved — cannot be deleted' : usage + ' expense' + (usage === 1 ? '' : 's') + ' use this category — cannot be deleted'}">🔒</button>`}
            </div>
          `;
        }).join('')}
      </div>
      <div style="display:flex;gap:8px;align-items:center;margin-top:8px">
        <input id="cat-new" type="text" placeholder="New category name..." style="flex:1;padding:9px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text)" />
        <button class="btn primary" id="cat-add">+ Add category</button>
      </div>
    </div>

    <div class="card" data-sset="club">
      <div class="card-header"><div><div class="card-title">💬 WhatsApp Reminder Templates</div><div class="card-subtitle">Bilingual messages auto-sent from the Expiring page. Tokens: <code style="background:var(--surface-2);padding:1px 5px;border-radius:3px;font-size:11px">{name}</code> <code style="background:var(--surface-2);padding:1px 5px;border-radius:3px;font-size:11px">{nameArabic}</code> <code style="background:var(--surface-2);padding:1px 5px;border-radius:3px;font-size:11px">{sport}</code> <code style="background:var(--surface-2);padding:1px 5px;border-radius:3px;font-size:11px">{coach}</code> <code style="background:var(--surface-2);padding:1px 5px;border-radius:3px;font-size:11px">{expiry}</code> <code style="background:var(--surface-2);padding:1px 5px;border-radius:3px;font-size:11px">{daysAgo}</code> <code style="background:var(--surface-2);padding:1px 5px;border-radius:3px;font-size:11px">{daysLeft}</code></div></div></div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(239,68,68,.15);color:var(--red);padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">EXPIRED</span> English</label>
          <textarea id="tpl-expired-en" rows="8" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('expired_en'))}</textarea>
        </div>
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(239,68,68,.15);color:var(--red);padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">EXPIRED</span> العربية</label>
          <textarea id="tpl-expired-ar" rows="8" dir="rtl" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('expired_ar'))}</textarea>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(245,158,11,.15);color:var(--accent-2);padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">EXPIRING SOON</span> English</label>
          <textarea id="tpl-expiring-en" rows="8" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('expiring_en'))}</textarea>
        </div>
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(245,158,11,.15);color:var(--accent-2);padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">EXPIRING SOON</span> العربية</label>
          <textarea id="tpl-expiring-ar" rows="8" dir="rtl" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('expiring_ar'))}</textarea>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(139,92,246,.15);color:#8b5cf6;padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">COMPLETED</span> English</label>
          <textarea id="tpl-completed-en" rows="8" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('completed_en'))}</textarea>
        </div>
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(139,92,246,.15);color:#8b5cf6;padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">COMPLETED</span> العربية</label>
          <textarea id="tpl-completed-ar" rows="8" dir="rtl" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('completed_ar'))}</textarea>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(16,185,129,.15);color:#10b981;padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">TRIAL FOLLOW-UP</span> English</label>
          <textarea id="tpl-trial-en" rows="8" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('trial_en'))}</textarea>
        </div>
        <div class="field" style="margin:0">
          <label style="display:flex;align-items:center;gap:6px"><span style="background:rgba(16,185,129,.15);color:#10b981;padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700">TRIAL FOLLOW-UP</span> العربية</label>
          <textarea id="tpl-trial-ar" rows="8" dir="rtl" style="width:100%;padding:10px 12px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:inherit;font-size:12px;line-height:1.5;resize:vertical">${escapeHtml(reminderTemplate('trial_ar'))}</textarea>
        </div>
      </div>

      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
        <button class="btn primary" id="save-tpls">💾 Save templates</button>
        <button class="btn ghost" id="reset-tpls" title="Restore the default English + Arabic messages">↻ Restore defaults</button>
        <button class="btn ghost" id="preview-tpl" title="Open WhatsApp with a sample message using the first member">👁 Preview</button>
        <span class="text-mute" style="font-size:11px;margin-left:auto">If a member has no Arabic name, only the English section is sent.</span>
      </div>
    </div>

    <div class="card" data-sset="data" style="border:1px solid var(--accent);background:var(--surface)">
      <div class="card-header"><div><div class="card-title" style="color:var(--accent)">🔍 Diagnostic</div><div class="card-subtitle">If the data looks wrong (old coaches showing, stale numbers), use Hard Reset below</div></div></div>
      <table style="width:100%">
        <tbody>
          <tr><td style="padding:4px 0">App version (code)</td><td class="text-right" style="font-family:monospace;font-size:12px">${SEED_VERSION}</td></tr>
          <tr><td style="padding:4px 0">Storage backend</td><td class="text-right font-bold" style="font-size:12px">${isCloudStorage() ? '☁️ Firebase (cloud, syncs across devices)' : '💾 This browser (localStorage)'}</td></tr>
          <tr><td style="padding:4px 0">Data version (${isCloudStorage() ? 'local cache' : 'localStorage'})</td><td class="text-right" style="font-family:monospace;font-size:12px;color:${localStorage.getItem(LS_VERSION_KEY)===SEED_VERSION?'var(--green)':'var(--accent-2)'}">${localStorage.getItem(LS_VERSION_KEY) || '(none — using seed)'}</td></tr>
          <tr><td style="padding:4px 0">Coaches loaded</td><td class="text-right font-bold">${state.coaches.length} ${state.coaches.length===7?'✓':'⚠️ expected 7'}</td></tr>
          <tr><td style="padding:4px 0">Members loaded</td><td class="text-right font-bold">${state.members.length}</td></tr>
        </tbody>
      </table>
      <div class="text-mute" style="font-size:11px;margin-top:8px">
        If the data looks wrong, the destructive recovery tools (Hard Reset, Clear all data) now live on the <b>Danger Zone</b> page. <b>Always make a backup first.</b>
      </div>
    </div>

    <div class="card" data-sset="data">
      <div class="card-header"><div><div class="card-title">${t('Data Management', 'إدارة البيانات')}</div><div class="card-subtitle">Full backup &amp; restore · daily backups</div></div></div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        <button class="btn primary" id="backup-btn">💾 Backup all data (1 JSON file)</button>
        <button class="btn ghost" id="restore-btn">📂 Restore from backup</button>
        <button class="btn ghost" id="autobackup-btn" title="Rolling automatic snapshots kept on this device — roll back to an earlier point">🛟 ${t('Auto-backups (this device)', 'النسخ التلقائية (هذا الجهاز)')}</button>
        ${isCloudStorage() ? `<button class="btn ghost" id="synccheck-btn" title="Compare this device's data against the cloud and flag anything not yet synced">🔍 ${t('Verify against cloud', 'التحقق من السحابة')}</button>` : ''}
        <button class="btn ghost" id="fixnames-btn" title="Correct member English names to Title Case (anas madni → Anas Madni)">Aa Fix name capitalisation</button>
        <input type="file" id="restore-file" accept=".json" style="display:none" />
      </div>
      <div class="text-mute mt-3" style="font-size:12px">
        ${isCloudStorage()
          ? `<b>☁️ Cloud storage is active.</b> Your data is stored in Firebase and syncs across every device you sign in on — it is <b>not</b> tied to this browser. <b>Backup all data</b> still lets you save a single <code>blackstars-backup-${TODAY}.json</code> file as an independent offline copy (handy if the cloud copy is ever changed by mistake). <b>Restore from backup</b> loads such a file back in and replaces the current data (it auto-saves a safety copy first).`
          : `<b>Backup all data</b> saves your <b>entire</b> database — every member, invoice, payment, attendance record, product, expense, salary and setting — into a single <code>blackstars-backup-${TODAY}.json</code> file. Do this <b>daily</b> and keep the file safe; if the app ever crashes or data is lost, use <b>Restore from backup</b> to load that file and you're back exactly where you were. Restore replaces all current data, but it auto-downloads a safety copy of what's there first, so it's reversible.`}
      </div>
    </div>

    <div class="card" data-sset="data">
      <div class="card-header"><div><div class="card-title">🧩 ${t('Cloud structure (multi-document)', 'بنية السحابة (متعددة المستندات)')}</div><div class="card-subtitle">Concurrent multi-user · no conflicts · no 1&nbsp;MB limit</div></div></div>
      ${isCloudStorage() ? `
        <div id="migrate-status" style="font-size:13px;margin-bottom:10px"></div>
        <div style="display:flex;gap:8px;flex-wrap:wrap">
          <button class="btn primary" id="migrate-btn">🧩 ${t('Migrate to multi-document', 'الترحيل إلى متعدد المستندات')}</button>
        </div>
        <div id="migrate-progress" class="text-mute" style="font-size:12px;margin-top:8px"></div>
        <div class="text-mute mt-3" style="font-size:12px">
          ${t('The multi-document model stores each member, invoice and record as its OWN cloud document, and member attendance is deep-merged field-by-field. This lets reception, coaches and the owner all edit at the same time — even marking attendance for different members at once — with no conflicts or lost data, and removes Firestore’s 1 MB single-document limit. Run this once — it downloads a full backup first and is safe to re-run.', 'يخزّن نموذج المستندات المتعددة كل عضو وفاتورة وسجل كمستند سحابي مستقل، ويتم دمج حضور الأعضاء حقلاً بحقل. يتيح ذلك للاستقبال والمدربين والمالك التعديل في الوقت نفسه — حتى تسجيل الحضور لأعضاء مختلفين معاً — دون تعارض أو فقدان بيانات، ويزيل حدّ 1 ميجابايت للمستند الواحد. شغّله مرة واحدة — يقوم بتنزيل نسخة احتياطية أولاً وآمن لإعادة التشغيل.')}
        </div>
      ` : `<div class="text-mute" style="font-size:12px">${t('Sign in to cloud (Firebase) to manage cloud storage structure. In offline (localStorage) mode there is a single device, so no migration is needed.', 'سجّل الدخول للسحابة (Firebase) لإدارة بنية التخزين. في الوضع دون اتصال يوجد جهاز واحد فقط، فلا حاجة للترحيل.')}</div>`}
    </div>

    <div class="card" data-sset="danger" style="border:1px solid var(--red);background:color-mix(in srgb, var(--red) 5%, var(--surface))">
      <div class="card-header"><div><div class="card-title" style="color:var(--red)">⚠️ Danger Zone</div><div class="card-subtitle">Destructive actions. Each one downloads a backup first and asks twice before running.</div></div></div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:6px">
        <button class="btn danger" id="reset-btn">🗑 Clear all data (start empty)</button>
        <button class="btn danger" id="hard-reset-btn">🔥 Hard Reset (wipe local cache + reload)</button>
        <button class="btn ghost" id="demo-btn" title="Replace your current data with the bundled demo data (207 sample members). For exploring features.">🧪 Load demo data</button>
      </div>
      <div class="text-mute" style="font-size:11px;margin-top:10px;line-height:1.6">
        <b>Clear all data</b> permanently empties the entire database${isCloudStorage() ? ' (including the cloud copy)' : ''}. <b>Hard Reset</b> wipes this browser's local cache and reloads${isCloudStorage() ? ' — the cloud copy syncs back on reload' : ''}. <b>Load demo data</b> overwrites your real data with sample data.<br>
        Each button downloads a full backup automatically, then asks for confirmation <b>twice</b> before doing anything.
      </div>
    </div>
      <table>
        <tbody>
          <tr><td>Members</td><td class="text-right font-bold num">${state.members.length}</td></tr>
          <tr><td>Coaches</td><td class="text-right font-bold num">${state.coaches.length}</td></tr>
          <tr><td>Trials</td><td class="text-right font-bold num">${(state.trials || []).length}</td></tr>
          <tr><td>Invoices</td><td class="text-right font-bold num">${state.invoices.length}</td></tr>
          <tr><td>Expenses</td><td class="text-right font-bold num">${state.expenses.length}</td></tr>
          <tr><td>Salaries</td><td class="text-right font-bold num">${state.salaries.length}</td></tr>
          <tr><td>Sales items</td><td class="text-right font-bold num">${state.sales.length}</td></tr>
          <tr><td>localStorage size</td><td class="text-right font-bold num">${fmt((localStorage.getItem(LS_KEY) || '').length / 1024)} KB</td></tr>
        </tbody>
      </table>
    </div>

    <div class="card" data-sset="data">
      <div class="card-header"><div><div class="card-title">${t('About', 'حول التطبيق')}</div></div></div>
      <table>
        <tbody>
          <tr><td>Application</td><td class="text-right">Black Stars CRM</td></tr>
          <tr><td>Version</td><td class="text-right">1.0.0</td></tr>
          <tr><td>Data period</td><td class="text-right">${(() => {
            const months = [...new Set(state.invoices.map(i => i.month).filter(Boolean))].sort();
            if (!months.length) return '—';
            if (months.length === 1) return fmtMonth(months[0]);
            return fmtMonth(months[0]) + ' – ' + fmtMonth(months[months.length-1]);
          })()}</td></tr>
          <tr><td>Today</td><td class="text-right">${fmtDate(TODAY)}</td></tr>
        </tbody>
      </table>
    </div>
  `;

  $('#save-prefs').addEventListener('click', () => {
    const days = parseInt($('#pref-expdays').value);
    const lowStock = parseInt($('#pref-lowstock').value);
    if (isNaN(days) || days < 1) { toast('Days must be ≥ 1', 'error'); return; }
    state.settings.expiringSoonDays = days;
    const recentExp = parseInt($('#pref-recentexp')?.value);
    if (!isNaN(recentExp) && recentExp >= 1) state.settings.recentlyExpiredDays = recentExp;
    state.settings.lowStockThreshold = isNaN(lowStock) ? 3 : lowStock;
    const qidMode = $('#pref-qidmode')?.value;
    if (qidMode === 'block' || qidMode === 'warn') state.settings.qidDuplicateMode = qidMode;
    const grace = parseInt($('#pref-refundgrace')?.value);
    const fee = parseFloat($('#pref-refundfee')?.value);
    if (!isNaN(grace) && grace >= 0) state.settings.refundGraceDays = grace;
    if (!isNaN(fee) && fee >= 0 && fee <= 100) state.settings.refundFeePct = fee;
    const idleEl = $('#pref-idlemin');
    if (idleEl && currentRole() === 'admin') {
      const idle = parseInt(idleEl.value);
      if (!isNaN(idle) && idle >= 0 && idle <= 240) {
        state.settings.idleLogoutMin = idle;
        if (typeof _idleReset === 'function') _idleReset();  // apply the new timeout immediately
      }
    }
    save();
    toast(`Preferences saved (alert ${days} days before expiry)`);
  });

  // Theme picker
  $$('.theme-card').forEach(card => {
    card.addEventListener('click', () => {
      const name = card.dataset.themeValue;
      setTheme(name);
      render();   // re-render so the "Active" badges and borders update
      toast(`Theme: ${name.charAt(0).toUpperCase() + name.slice(1)}`);
    });
  });

  $('#save-commissions').addEventListener('click', () => {
    let changed = 0;
    $$('.comm-rate').forEach(inp => {
      const id = parseInt(inp.dataset.coach);
      const rate = parseFloat(inp.value);
      if (isNaN(rate) || rate < 0 || rate > 100) return;
      const c = state.coaches.find(x => x.id === id);
      if (c && c.rate !== rate) { c.rate = rate; changed++; }
    });
    if (!state.settings) state.settings = {};
    const basisSel = $('#pref-commbasis');
    const newBasis = basisSel && basisSel.value === 'attendance' ? 'attendance' : 'payment';
    const basisChanged = state.settings.commissionBasis !== newBasis;
    state.settings.commissionBasis = newBasis;
    save();
    render();
    toast(changed || basisChanged ? `Saved${changed ? ` · ${changed} rate${changed !== 1 ? 's' : ''}` : ''}${basisChanged ? ` · basis: ${newBasis}` : ''}` : 'No changes to save');
  });

  // ── Expense categories management ─────────────────────────────
  // Lazy-init from defaults on first edit if not yet set
  function ensureCategories() {
    if (!state.settings) state.settings = {};
    if (!Array.isArray(state.settings.expenseCategories) || !state.settings.expenseCategories.length) {
      state.settings.expenseCategories = [...DEFAULT_EXPENSE_CATEGORIES];
    }
  }
  $('#cat-add')?.addEventListener('click', () => {
    const inp = $('#cat-new');
    const name = (inp?.value || '').trim();
    if (!name) { toast('Enter a category name', 'error'); inp?.focus(); return; }
    if (name.length > 40) { toast('Category name is too long (max 40 chars)', 'error'); return; }
    ensureCategories();
    // Case-insensitive duplicate check
    if (state.settings.expenseCategories.some(c => c.toLowerCase() === name.toLowerCase())) {
      toast(`"${name}" already exists`, 'error');
      return;
    }
    state.settings.expenseCategories.push(name);
    save();
    render();
    toast(`Added category: ${name}`);
  });
  document.querySelectorAll('[data-cat-delete]').forEach(btn => {
    btn.addEventListener('click', e => {
      const name = e.currentTarget.dataset.catDelete;
      if (RESERVED_EXPENSE_CATEGORIES.includes(name)) {
        toast(`"${name}" is reserved and cannot be deleted`, 'error');
        return;
      }
      const usage = (state.expenses || []).filter(x => x.category === name).length;
      if (usage > 0) {
        toast(`"${name}" is used by ${usage} expense${usage === 1 ? '' : 's'} — cannot delete`, 'error');
        return;
      }
      if (!confirm(`Delete category "${name}"?\n\nThis only removes it from the dropdown. No expense data is affected.`)) return;
      ensureCategories();
      state.settings.expenseCategories = state.settings.expenseCategories.filter(c => c !== name);
      save();
      render();
      toast(`Deleted: ${name}`);
    });
  });
  // Allow Enter key in the new-category input to trigger Add
  $('#cat-new')?.addEventListener('keydown', e => {
    if (e.key === 'Enter') { e.preventDefault(); $('#cat-add')?.click(); }
  });

  // ── Reminder templates ─────────────────────────────────────────
  $('#save-tpls')?.addEventListener('click', () => {
    if (!state.settings) state.settings = {};
    state.settings.reminderTemplates = {
      expired_en:  $('#tpl-expired-en').value,
      expired_ar:  $('#tpl-expired-ar').value,
      expiring_en: $('#tpl-expiring-en').value,
      expiring_ar: $('#tpl-expiring-ar').value,
      completed_en: $('#tpl-completed-en')?.value ?? reminderTemplate('completed_en'),
      completed_ar: $('#tpl-completed-ar')?.value ?? reminderTemplate('completed_ar'),
      trial_en: $('#tpl-trial-en')?.value ?? reminderTemplate('trial_en'),
      trial_ar: $('#tpl-trial-ar')?.value ?? reminderTemplate('trial_ar'),
    };
    save();
    toast('💬 Reminder templates saved');
  });
  $('#reset-tpls')?.addEventListener('click', () => {
    if (!confirm('Restore default reminder templates?\n\nYour current customizations will be replaced with the bundled English + Arabic defaults.')) return;
    if (state.settings) delete state.settings.reminderTemplates;
    save();
    render();
    toast('Templates restored to defaults');
  });
  $('#preview-tpl')?.addEventListener('click', () => {
    // Pick the first non-archived member with an expiry to demo with
    const sample = activeMembers().find(m => m.expiryDate) || activeMembers()[0];
    if (!sample) { toast('No members to preview with', 'error'); return; }
    const days = sample.expiryDate ? (daysUntil(sample.expiryDate) ?? 0) : -3;
    const kind = days < 0 ? 'expired' : 'expiring';
    // Use the LIVE textarea values, not the saved settings (so preview reflects edits)
    const liveTemplates = {
      expired_en:  $('#tpl-expired-en').value,
      expired_ar:  $('#tpl-expired-ar').value,
      expiring_en: $('#tpl-expiring-en').value,
      expiring_ar: $('#tpl-expiring-ar').value,
      completed_en: $('#tpl-completed-en')?.value ?? reminderTemplate('completed_en'),
      completed_ar: $('#tpl-completed-ar')?.value ?? reminderTemplate('completed_ar'),
    };
    // Temporarily inject live values
    const prevSaved = state.settings?.reminderTemplates;
    if (!state.settings) state.settings = {};
    state.settings.reminderTemplates = liveTemplates;
    const msg = buildReminderMessage(sample, kind, days);
    state.settings.reminderTemplates = prevSaved;  // restore — don't persist
    // Show in a modal so admin can read before sending
    showModal({
      title: `💬 Preview · ${sample.name} (${kind === 'expired' ? 'Expired' : 'Expiring'})`,
      wide: true,
      body: `
        <div class="text-mute" style="font-size:12px;margin-bottom:10px">This is what the WhatsApp message will look like for <b>${escapeHtml(sample.name)}</b>. Tokens have been filled in with this member's actual data.</div>
        <pre style="background:var(--surface-2);border:1px solid var(--border);border-radius:8px;padding:14px;white-space:pre-wrap;font-family:inherit;font-size:13px;line-height:1.6;max-height:400px;overflow-y:auto">${escapeHtml(msg)}</pre>
      `,
      actions: [
        { label: 'Close', class: 'btn ghost', onclick: closeModal },
        ...(sample.phone && !sample.phone.startsWith('+9747000') ? [{
          label: '💬 Open in WhatsApp', class: 'btn primary', onclick: () => {
            const ph = sample.phone.replace(/[^\d]/g, '');
            window.open(`https://wa.me/${ph}?text=${encodeURIComponent(msg)}`, '_blank');
            closeModal();
          }
        }] : []),
      ],
    });
  });

  $('#backup-btn').addEventListener('click', () => window.downloadBackup());
  $('#autobackup-btn')?.addEventListener('click', () => window.showLocalBackupsUI());
  $('#synccheck-btn')?.addEventListener('click', () => window.runSyncCheck());
  $('#fixnames-btn')?.addEventListener('click', () => window.fixNameCapitalization());

  // ── Multi-document migration (one-click) ──────────────────────────────────
  (function setupMigration() {
    const btn = $('#migrate-btn');
    const statusEl = $('#migrate-status');
    const prog = $('#migrate-progress');
    if (!btn) return;   // offline mode: no card rendered
    const S = window.Storage;
    const cloud = !!(S && S.isCloud && S.isCloud());
    const needs = cloud && S.needsMigration && S.needsMigration();
    if (statusEl) {
      statusEl.innerHTML = needs
        ? `<b style="color:var(--red)">⚠ ${t('Legacy single-document detected.', 'تم اكتشاف نموذج المستند الواحد القديم.')}</b> ${t('All your data is currently in ONE cloud document. Migrate now to enable safe concurrent multi-user editing.', 'كل بياناتك حالياً في مستند سحابي واحد. رحّل الآن لتفعيل تعديل متعدد المستخدمين بأمان.')}`
        : `<b style="color:var(--green,#16a34a)">✓ ${t('Multi-document is active.', 'نموذج المستندات المتعددة مُفعّل.')}</b> ${t('Each record is stored separately — concurrent editing is safe.', 'كل سجل مخزّن على حدة — التعديل المتزامن آمن.')}`;
    }
    if (!needs) {
      btn.disabled = true;
      btn.classList.remove('primary'); btn.classList.add('ghost');
      btn.textContent = '✓ ' + t('Already multi-document', 'متعدد المستندات بالفعل');
    }
    btn.addEventListener('click', async () => {
      if (!cloud) { toast(t('Migration requires cloud sign-in', 'الترحيل يتطلب تسجيل دخول السحابة'), 'error'); return; }
      try { window.downloadBackup(); } catch (_) {}
      if (!confirm(t('Migrate all cloud data to the multi-document model?\n\nA backup was just downloaded. This copies every record into its own cloud document, then enables concurrent multi-user editing. It is safe to run and re-run.', 'ترحيل كل بيانات السحابة إلى نموذج المستندات المتعددة؟\n\nتم تنزيل نسخة احتياطية للتو. سيتم نسخ كل سجل إلى مستند سحابي مستقل ثم تفعيل التعديل المتزامن. آمن للتشغيل وإعادة التشغيل.'))) return;
      const original = btn.textContent;
      btn.disabled = true; btn.textContent = '⏳ ' + t('Migrating…', 'جارٍ الترحيل…');
      try {
        const res = await S.migrateToMultiDoc(p => {
          if (!prog) return;
          if (p && p.phase === 'writing' && p.written != null) prog.textContent = t('Writing documents… ', 'كتابة المستندات… ') + p.written + '/' + p.totalDocs;
          else if (p && p.phase === 'writing') prog.textContent = t('Preparing ', 'تجهيز ') + p.totalDocs + t(' documents…', ' مستند…');
        });
        if (res && res.migrated) {
          if (prog) prog.textContent = t('Done — ', 'تم — ') + res.totalDocs + t(' documents across ', ' مستند عبر ') + res.collections.length + t(' collections.', ' مجموعة.');
          try { if (typeof audit === 'function') audit('data.migrate', 'cloud', `Migrated to multi-document (${res.totalDocs} docs across ${res.collections.length} collections)`); } catch (_) {}
          toast('✅ ' + t('Migrated to multi-document. Reloading…', 'تم الترحيل. إعادة التحميل…'), 'success');
          setTimeout(() => location.reload(), 1600);
        } else {
          const reason = (res && res.reason) || t('Already migrated', 'تم الترحيل بالفعل');
          if (prog) prog.textContent = reason;
          toast(reason, 'info');
          btn.textContent = original; btn.disabled = false;
        }
      } catch (e) {
        console.error('[migrate] failed', e);
        if (prog) prog.textContent = t('Migration failed: ', 'فشل الترحيل: ') + ((e && e.message) || e);
        toast(t('Migration failed — your data is unchanged. ', 'فشل الترحيل — بياناتك دون تغيير. ') + ((e && e.message) || ''), 'error');
        btn.textContent = original; btn.disabled = false;
      }
    });
  })();

  $('#restore-btn').addEventListener('click', () => $('#restore-file').click());
  $('#restore-file').addEventListener('change', async e => {
    const file = e.target.files[0];
    if (!file) return;
    try {
      const text = await file.text();
      const data = JSON.parse(text);
      if (!Array.isArray(data.members) || !Array.isArray(data.invoices)) throw new Error('This file is not a Black Stars backup');
      const exportedOn = data.exported ? new Date(data.exported).toLocaleString() : 'unknown date';
      const summary = `${(data.members || []).length} members · ${(data.invoices || []).length} invoices · ${(data.coaches || []).length} coaches · ${(data.products || []).length} products`;
      const cur = `${state.members.length} members · ${state.invoices.length} invoices`;
      showModal({
        title: '📂 Restore from backup?',
        body: `<div style="font-size:13px;line-height:1.7">
            <p>This will <b style="color:var(--red)">replace ALL current data</b> with the contents of this backup file. This cannot be undone.</p>
            <div style="margin:10px 0;padding:10px 12px;border:1px solid var(--border);border-radius:8px;background:var(--bg-soft)">
              <div><b>Backup file:</b> ${escapeHtml(file.name)}</div>
              <div><b>Created:</b> ${escapeHtml(exportedOn)}${data.appVersion ? ` · app v${escapeHtml(String(data.appVersion))}` : ''}</div>
              <div><b>Contains:</b> ${summary}</div>
            </div>
            <p class="text-mute">Current data right now: ${cur}.</p>
            <p style="color:var(--green)">✓ A safety copy of your <b>current</b> data will be downloaded first, so you can undo this if needed.</p>
          </div>`,
        actions: [
          { label: 'Cancel', class: 'btn ghost', onclick: () => { closeModal(); e.target.value = ''; } },
          { label: 'Download safety copy & restore', class: 'btn primary', onclick: () => {
              closeModal();
              // 1) safety copy of CURRENT data, clearly named, before we overwrite.
              try {
                const safety = JSON.stringify({ appVersion: APP_VERSION, schemaVersion: SCHEMA_VERSION, exported: new Date().toISOString(), ...state, user: undefined, route: undefined }, null, 2);
                downloadFile(`blackstars-PRE-RESTORE-${TODAY}.json`, safety, 'application/json');
              } catch (_) {}
              // 2) clean replace — drop backup meta keys, keep the live session/route.
              const incoming = { ...data };
              delete incoming.appVersion; delete incoming.schemaVersion; delete incoming.exported;
              delete incoming.user; delete incoming.route;
              Object.assign(state, incoming);
              if (typeof audit === 'function') audit('data.restore', 'backup', `Restored backup (${summary})`, { file: file.name, exported: data.exported });
              window.__allowEmptySave = true;   // explicit restore — honor even if the backup is small
              save();
              window.__allowEmptySave = false;
              render();
              toast(`✓ Restored · ${state.members.length} members · ${state.invoices.length} invoices`);
              e.target.value = '';
            } },
        ],
      });
    } catch (err) {
      toast('Restore failed: ' + err.message, 'error');
      e.target.value = '';
    }
  });

  // Shared guard for destructive actions: admin-only, force a backup download, then
  // require TWO confirmations before running.
  const dangerAction = (firstMsg, secondMsg, run) => {
    if (currentRole() !== 'admin') { toast('Only an admin can perform this action', 'error'); return; }
    if (!confirm(firstMsg)) return;
    try { if (typeof window.downloadBackup === 'function') window.downloadBackup(); } catch (_) {}
    if (!confirm(secondMsg)) return;
    if (currentRole() !== 'admin') { toast('Only an admin can perform this action', 'error'); return; }
    run();
  };

  $('#reset-btn')?.addEventListener('click', () => dangerAction(
    '⚠️ CLEAR ALL DATA — this permanently empties the ENTIRE database (members, invoices, payments, attendance, everything)' + (isCloudStorage() ? ', including the cloud copy' : '') + '.\n\nA backup file will be downloaded first. Continue?',
    'A backup was just downloaded. This is your LAST chance.\n\nPermanently clear ALL data now? This cannot be undone.',
    () => resetData(true),
  ));
  const demoBtn = $('#demo-btn');
  if (demoBtn) demoBtn.addEventListener('click', () => {
    const cur = state.members.length;
    dangerAction(
      (cur > 0
        ? `Replace your ${cur} member${cur === 1 ? '' : 's'} (and ALL invoices/attendance/etc.) with demo sample data?`
        : 'Load demo data (207 sample members, coaches, schedule, etc.)?') + '\n\nA backup file will be downloaded first. Continue?',
      'A backup was just downloaded. This is your LAST chance.\n\nOverwrite your current data with demo data now?',
      () => { loadDemoData(); render(); toast(`Demo data loaded · ${state.members.length} members`); },
    );
  });
  $('#hard-reset-btn')?.addEventListener('click', () => dangerAction(
    '🔥 HARD RESET — wipes this browser\'s local cache and reloads with an empty app' + (isCloudStorage() ? ' (the cloud copy syncs back on reload)' : '') + '.\n\nA backup file will be downloaded first. Continue?',
    'A backup was just downloaded. This is your LAST chance.\n\nWipe the local cache and reload now?',
    () => {
      Object.keys(localStorage).forEach(k => { if (k.startsWith('blackstars-crm')) localStorage.removeItem(k); });
      location.reload();
    },
  ));

  // When opened as a focused sub-page, show only that module's cards (all the
  // controls are still wired — we only hide the other modules) and retitle.
  if (section) {
    const titles = { preferences: 'Preferences', club: 'Club Setup', data: 'Data & Backup', danger: '⚠️ Danger Zone' };
    main.querySelectorAll('.card[data-sset]').forEach(c => { if (c.dataset.sset !== section) c.style.display = 'none'; });
    const h = main.querySelector('.topbar h1'); if (h) h.textContent = titles[section] || 'Settings';
    const sub = main.querySelector('.topbar .subtitle'); if (sub) sub.textContent = 'Settings · ' + (titles[section] || '');
  }
};
PAGES.preferences = (main) => PAGES.settings(main, 'preferences');
PAGES.club = (main) => PAGES.settings(main, 'club');
PAGES.databackup = (main) => PAGES.settings(main, 'data');
PAGES.danger = (main) => PAGES.settings(main, 'danger');

// ─── Modal helpers ──────────────────────────────────────────
// Shows a fixed banner when this browser is running an old cached version while
// the cloud has a newer one. Prompts a hard refresh. Saving is already blocked.
window.showStaleVersionBanner = function (newVer) {
  if (document.getElementById('stale-version-banner')) return;   // only once
  const bar = document.createElement('div');
  bar.id = 'stale-version-banner';
  bar.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:99999;background:#b3261e;color:#fff;padding:10px 16px;display:flex;align-items:center;justify-content:center;gap:14px;font-size:14px;box-shadow:0 2px 10px rgba(0,0,0,.3)';
  bar.innerHTML = `
    <span>⚠️ <b>${t('A newer version is available', 'يتوفر إصدار أحدث')}.</b> ${t('This tab is running old code — saving is paused to protect your data. Please refresh.', 'هذا التبويب يعمل بإصدار قديم — تم إيقاف الحفظ لحماية بياناتك. يرجى التحديث.')}</span>
    <button onclick="location.reload(true)" style="background:#fff;color:#b3261e;border:none;border-radius:6px;padding:6px 14px;font-weight:700;cursor:pointer">🔄 ${t('Refresh now', 'تحديث الآن')}</button>`;
  document.body.appendChild(bar);
  document.body.style.paddingTop = '44px';
};
function showModal({ title, body, actions = [] }) {
  closeModal();
  const backdrop = el('div', { className: 'modal-backdrop', id: 'modal-backdrop' });
  const modal = el('div', { className: 'modal' });
  modal.innerHTML = `
    <div class="modal-header">
      <div class="modal-title">${title}</div>
      <button class="close-x" id="modal-close">✕</button>
    </div>
    <div class="modal-body">${body}</div>
    <div class="modal-footer"></div>
  `;
  const footer = modal.querySelector('.modal-footer');
  for (const a of actions) {
    // Action-button clicks bypass the dirty-check (they're intentional close paths)
    const handler = a.onclick ? (e) => { window._modalBypassDirty = true; try { a.onclick(e); } finally { window._modalBypassDirty = false; } } : null;
    const btn = el('button', { className: a.class || 'btn', onclick: handler }, a.label);
    if (a.id) btn.id = a.id;
    footer.append(btn);
  }
  backdrop.append(modal);
  document.body.append(backdrop);
  modal.querySelector('#modal-close').addEventListener('click', () => tryCloseModal());
  backdrop.addEventListener('click', e => { if (e.target === backdrop) tryCloseModal(); });
  document.addEventListener('keydown', escClose);
  document.body.style.overflow = 'hidden';
  // Snapshot initial form values for dirty-check
  setTimeout(() => { window._modalInitialState = snapshotModalState(modal); }, 0);
}

// Capture all input/select/textarea values inside the modal so we can detect
// whether the user actually changed anything before warning about discard.
function snapshotModalState(modal) {
  const snap = {};
  modal.querySelectorAll('input, select, textarea').forEach((el, i) => {
    const key = (el.id || el.name || `_${i}`);
    if (el.type === 'checkbox' || el.type === 'radio') snap[key] = el.checked;
    else snap[key] = el.value;
  });
  return snap;
}

function isModalDirty() {
  const modal = document.querySelector('.modal');
  if (!modal || !window._modalInitialState) return false;
  const current = snapshotModalState(modal);
  const initial = window._modalInitialState;
  // Different number of fields (e.g. enroll rows added/removed) counts as dirty
  if (Object.keys(current).length !== Object.keys(initial).length) return true;
  for (const k of Object.keys(current)) {
    if (current[k] !== initial[k]) return true;
  }
  return false;
}

// Wrapped close: warns the user if the form has unsaved changes
function tryCloseModal() {
  if (window._modalBypassDirty) { closeModal(); return; }
  if (isModalDirty()) {
    if (!confirm('Discard changes? Your edits will be lost.')) return;
  }
  closeModal();
}

function closeModal() {
  const b = $('#modal-backdrop');
  if (b) b.remove();
  document.removeEventListener('keydown', escClose);
  document.body.style.overflow = '';
  window._modalInitialState = null;
}

function escClose(e) { if (e.key === 'Escape') tryCloseModal(); }

// ─── ATTENDANCE ──────────────────────────────────────────────────
PAGES.attendance = (main) => {
  // Defaults: pick today's month if we have data for it (else latest month with
  // data), and pre-select today's day so marking is one-click for the common
  // "open the page, mark attendance for now" workflow.
  const _now = new Date();
  const _todayMonth = `${_now.getFullYear()}-${String(_now.getMonth()+1).padStart(2,'0')}`;
  const _availMonths = availableMonths({ includeFuture: true });
  const _defaultMonth = _availMonths.includes(_todayMonth) ? _todayMonth : latestDataMonth();
  // filter.days is an array of day-numbers; empty = all days
  const _defaultDays = _defaultMonth === _todayMonth ? [_now.getDate()] : [];
  let filter = { month: _defaultMonth, coach: 'all', search: '', sports: [], memberId: null, days: _defaultDays, att: 'all' };
  // Month MULTI-select: filter.months = [] → summary over ALL months; exactly ONE →
  // the editable day-grid for that month; TWO+ → summary over just those months.
  // filter.month stays derived (single month or 'all') so all the grid logic below
  // is untouched.
  filter.months = (_defaultMonth && _defaultMonth !== 'all') ? [_defaultMonth] : [];
  const syncMonthFromMonths = () => { filter.month = filter.months.length === 1 ? filter.months[0] : 'all'; };
  syncMonthFromMonths();
  // If navigated here from a member profile ("see attendance"), pre-fill the
  // search with that member's name and show all months so their full history is
  // visible. Consumed once.
  if (window._attFocus) {
    filter.search = window._attFocus.name || '';
    filter.days = [];                          // show the whole month, not just today
    window._attFocus = null;
  }

  // When a COACH is signed in, the attendance grid shows ONLY the sports they
  // actually coach (per-enrolment coachId), so a coach can mark their own
  // classes and nobody else's.
  const myCoachId = (typeof currentRole === 'function' && currentRole() === 'coach') ? effectiveCoachId() : null;
  // Coaches may only record TODAY's attendance — lock the grid to the current
  // day so past/future dates can't even be selected (also enforced in applyMark).
  const _coachLockToday = myCoachId != null;
  if (_coachLockToday) {
    filter.months = [_todayMonth];
    filter.month = _todayMonth;
    filter.days = [_now.getDate()];
    filter.search = '';
  }
  function coachSportsFor(m, cid) {
    const set = new Set();
    if (m.coachId === cid && m.sport) set.add(m.sport);
    (m.enrollments || []).forEach(e => { if (e.coachId === cid && e.sport) set.add(e.sport); });
    return set;
  }

  // Collect all sports a member is enrolled in (primary + enrollments + subs)
  function memberSports(m) {
    const set = new Set();
    if (m.sport) set.add(m.sport);
    (m.enrollments || []).forEach(e => { if (e.sport) set.add(e.sport); });
    (m.subscriptions || []).forEach(s => { if (s.activity) set.add(s.activity); });
    return [...set];
  }

  function getRows() {
    // Show every member who has ANY enrollment (active OR expired).
    // The grid is for marking attendance; admin needs to see expired members
    // too so they can be counted after a late renewal.
    // The legacy m.months filter is removed — m.months was an import-time
    // legacy field that didn't track real enrollment.
    const rows = [];
    for (const m of state.members) {
      if (m.deleted) continue;  // archived members are out of the active roster
      if (filter.coach !== 'all' && m.coachId !== parseInt(filter.coach)) continue;
      if (filter.memberId != null && m.id !== filter.memberId) continue;
      const sports = memberSports(m);
      if (!sports.length) sports.push(m.sport || '—');
      let wanted = filter.sports.length ? sports.filter(s => filter.sports.includes(s)) : sports;
      if (myCoachId != null) {
        const mine = coachSportsFor(m, myCoachId);
        wanted = wanted.filter(s => mine.has(s));
      }
      if (!wanted.length) continue;
      if (filter.search) {
        const raw = filter.search.trim();
        const q = raw.toLowerCase();
        const hay = [m.name, m.nameArabic, m.phone, m.phone2, m.qid].filter(Boolean).join(' ').toLowerCase();
        let hit = searchMatchesFields(raw, [m.name, m.nameArabic, m.phone, m.phone2, m.qid], [m.phone, m.phone2]);
        if (!hit && q.length >= 3 && !/\d/.test(q)) hit = fuzzyMatch(m.name, q) || fuzzyMatch(m.nameArabic, q);
        if (!hit) continue;
      }
      for (const sp of wanted) {
        // Attended / Not-attended filter — evaluated over the selected day(s),
        // or the whole grid month when no specific day is picked.
        if (filter.att && filter.att !== 'all') {
          const att = rowAttended(m, sp);
          if (filter.att === 'attended' && !att) continue;
          if (filter.att === 'notattended' && att) continue;
        }
        // Resolve the coach for THIS sport: prefer the matching enrollment, then
        // the matching subscription (a sport may live only in subscriptions, e.g.
        // legacy/imported data), and only fall back to the member's primary coach
        // as a last resort. This prevents showing the wrong coach (the headline
        // coach) for a sport that isn't in enrollments.
        const enr = (m.enrollments || []).find(e => e.sport === sp);
        const sub = (m.subscriptions || []).find(s => s.activity === sp);
        const rowCoachId = (enr && enr.coachId != null) ? enr.coachId
          : (sub && sub.coachId != null) ? sub.coachId
          : m.coachId;
        rows.push({ m, sport: sp, coachId: rowCoachId });
      }
    }
    // Sort: active members first, then expired ones (so admin's attention
    // lands on the active ones, but expired stays accessible)
    rows.sort((a, b) => {
      const aExp = memberStatus(a.m) === 'Expired';
      const bExp = memberStatus(b.m) === 'Expired';
      if (aExp !== bExp) return aExp ? 1 : -1;
      return (a.m.name || '').localeCompare(b.m.name || '');
    });
    return rows;
  }

  // Resolve the month used for the day-grid + marking. "all" widens the row
  // filter (getRows) to every month, but the grid itself shows one concrete
  // month (default May) since day columns are per-month.
  function gridMonth() {
    return filter.month === 'all' ? latestDataMonth() : filter.month;
  }

  // True if the member has at least one "present" (Y) mark for this sport within
  // the current scope: the selected day(s) if any, otherwise the whole month.
  // In "All months" mode, looks across every month.
  function rowAttended(m, sport) {
    if (filter.month === 'all') {
      const da = m.dailyAttendance || {};
      return Object.keys(da).some(mo => Object.values(da[mo]?.[sport] || {}).some(v => v === 'Y'));
    }
    const mo = gridMonth();
    const data = m.dailyAttendance?.[mo]?.[sport] || {};
    const total = daysInMonth(mo);
    const days = (filter.days && filter.days.length)
      ? filter.days.filter(d => d >= 1 && d <= total)
      : Array.from({ length: total }, (_, i) => i + 1);
    return days.some(d => data[String(d)] === 'Y');
  }

  // Months that actually have any attendance marks (for the "All months" summary).
  function monthsWithData() {
    const set = new Set();
    for (const m of state.members) {
      if (m.deleted) continue;
      for (const mo of Object.keys(m.dailyAttendance || {})) {
        const sp = m.dailyAttendance[mo];
        if (sp && Object.values(sp).some(d => d && Object.keys(d).length)) set.add(mo);
      }
    }
    return [...set].sort();
  }

  // Narrow day columns to attended / not-attended days when that filter is set
  // (so "Attended" shows only the days people actually attended).
  function visibleDays(rows, baseDays, mo) {
    if (filter.att === 'attended')
      return baseDays.filter(d => rows.some(r => (r.m.dailyAttendance?.[mo]?.[r.sport] || {})[String(d)] === 'Y'));
    if (filter.att === 'notattended')
      return baseDays.filter(d => rows.some(r => (r.m.dailyAttendance?.[mo]?.[r.sport] || {})[String(d)] === 'N'));
    return baseDays;
  }

  function applyMark(memberId, sport, day, next) {
    const mo = gridMonth();
    // A COACH may only mark attendance for the CURRENT DAY — never a past or
    // future date. (Enforced here as well as in the UI, so it holds even if the
    // grid is manipulated.) Admin/Reception are unrestricted.
    if (typeof currentRole === 'function' && currentRole() === 'coach') {
      const markISO = `${mo}-${String(day).padStart(2, '0')}`;
      if (markISO !== TODAY) {
        toast(t('Coaches can only mark attendance for today.', 'يمكن للمدرب تسجيل الحضور لليوم الحالي فقط.'), 'error');
        return;
      }
    }
    const m = state.members.find(x => x.id === memberId);
    if (!m) return;
    if (!m.dailyAttendance) m.dailyAttendance = {};
    if (!m.dailyAttendance[mo]) m.dailyAttendance[mo] = {};
    if (!m.dailyAttendance[mo][sport]) m.dailyAttendance[mo][sport] = {};
    // Cap "present" marks at the subscription's planned classes for the current
    // period: if this new Y would push attended past the total, warn first so a
    // member can't be marked present more times than classes they paid for.
    if (next === 'Y') {
      // Pick the subscription whose window CONTAINS the marked day (falls back to the
      // latest) so a renewed member's present is counted against the NEW cycle, not
      // an expired one.
      const markISO = `${mo}-${String(day).padStart(2, '0')}`;
      const sub = (typeof subForAttendanceDate === 'function')
        ? subForAttendanceDate(m, sport, markISO)
        : (m.subscriptions || []).filter(s => (s.activity || '') === sport).slice(-1)[0];
      const planned = sub ? (parseInt(sub.totalClasses) || 0) : 0;
      if (planned > 0) {
        // Count present marks ONLY within that subscription's window (start → end).
        // A renewal creates a new subscription with a fresh window, so the count
        // resets — otherwise a renewed (Active) member is wrongly told they already
        // finished their classes because the PREVIOUS cycle's attendance still counted.
        const live = (typeof liveAttendanceCount === 'function') ? liveAttendanceCount(m, sport, sub.start || null, sub.end || null) : { y: 0 };
        const alreadyY = live.y || 0;
        // Only block if this cell isn't already counted as Y (it's a NEW present).
        const cellWasY = m.dailyAttendance[mo][sport][String(day)] === 'Y';
        if (!cellWasY && alreadyY >= planned) {
          const nm = m.name, nmAr = m.nameArabic || m.name;
          if (!confirm(t(
            `${nm} has already attended all ${planned} ${sport} classes for this subscription period.\n\nMark another present anyway? (They may need to renew.)`,
            `${nmAr} حضر بالفعل جميع حصص ${sport} (${planned} حصة) لفترة هذا الاشتراك.\n\nهل تريد تسجيل حضور إضافي على أي حال؟ (قد يحتاج إلى التجديد.)`
          ))) {
            return;
          }
        }
      }
    }
    const _prevMark = m.dailyAttendance[mo][sport][String(day)] || null;
    if (next === null) delete m.dailyAttendance[mo][sport][String(day)];
    else m.dailyAttendance[mo][sport][String(day)] = next;
    // Stamp + audit the attendance change (req #5 last-updated, #8 audit trail —
    // attendance was previously NOT logged).
    const _markISO = `${mo}-${String(day).padStart(2, '0')}`;
    const _label = next === 'Y' ? 'present' : next === 'N' ? 'absent' : 'cleared';
    stampUpdate(m);
    audit('attendance.mark', `member:${m.id}`, `Attendance ${_label}: ${m.name} · ${sport} · ${_markISO}`, {
      name: m.name, memberId: m.id, mobile: m.phone || '', sport, date: _markISO,
      old: _prevMark, new: next || 'cleared',
    });
    save();
    refresh();
  }
  function markCell(memberId, sport, day, current) {
    const next = current === 'Y' ? 'N' : current === 'N' ? null : 'Y';
    // First mark (empty → present) stays one-click for fast roll-call.
    // Changing an EXISTING mark (Y→N, or clearing) asks to confirm, so a stray
    // tap can't silently flip someone's record.
    if (current === 'Y' || current === 'N') {
      const m = state.members.find(x => x.id === memberId);
      const name = m ? m.name : 'this member';
      const fromLabel = current === 'Y' ? 'Present (Y)' : 'Absent (N)';
      const toLabel = next === 'Y' ? 'Present (Y)' : next === 'N' ? 'Absent (N)' : 'cleared (blank)';
      const badge = (txt, kind) => `<span class="badge" style="background:${kind==='Y'?'rgba(16,185,129,.15)':kind==='N'?'rgba(242,96,96,.15)':'rgba(120,120,140,.15)'};color:${kind==='Y'?'var(--green)':kind==='N'?'var(--red)':'var(--text-mute)'}">${txt}</span>`;
      showModal({
        title: 'Change attendance?',
        body: `<div style="font-size:13px;line-height:1.7">
            <p>Change <b>${escapeHtml(name)}</b> · ${escapeHtml(sport)} on <b>day ${day}</b> of ${fmtMonth(gridMonth())}?</p>
            <p style="margin-top:8px">${badge(fromLabel, current)} <span style="opacity:.6">→</span> ${badge(toLabel, next)}</p>
          </div>`,
        actions: [
          { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
          { label: 'Change it', class: 'btn primary', onclick: () => { closeModal(); applyMark(memberId, sport, day, next); } },
        ],
      });
      return;
    }
    applyMark(memberId, sport, day, next);
  }
  window._attMark = markCell;

  function cellRender(memberId, sport, day, mark) {
    const cls = mark === 'Y' ? 'att-y' : mark === 'N' ? 'att-n' : 'att-empty';
    const txt = mark || '·';
    const sportEsc = sport.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '&quot;');
    return `<td class="att-cell ${cls}" onclick="window._attMark(${memberId}, '${sportEsc}', ${day}, ${mark ? `'${mark}'` : 'null'})">${txt}</td>`;
  }

  function refresh() {
    const gMonth = gridMonth();
    window._attCurrentMonth = gMonth;
    const rows = getRows();

    // Club-wide total of attended (present / 'Y') classes across the rows shown.
    // Respects the day filter: if specific day(s) are selected we count only those
    // days, so the total matches what the grid is showing (otherwise the whole
    // grid month, or every month when "All months" is selected).
    // When several months are ticked the summary covers just those; none ticked = all.
    const _summaryMonths = filter.months.length ? filter.months.slice().sort() : monthsWithData();
    const totalMonths = (filter.month === 'all') ? _summaryMonths : [gMonth];
    const dayFilter = (filter.month === 'all') ? [] : (filter.days || []).filter(d => d >= 1 && d <= 31);
    let clubAttended = 0;
    for (const { m, sport } of rows) {
      for (const mk of totalMonths) {
        const dd = m.dailyAttendance?.[mk]?.[sport] || {};
        for (const k in dd) {
          if (dd[k] !== 'Y') continue;
          if (dayFilter.length && !dayFilter.includes(parseInt(k))) continue;
          clubAttended++;
        }
      }
    }
    const grandEl = document.getElementById('att-grand');
    if (grandEl) grandEl.textContent = String(clubAttended);
    const grandLabelEl = document.getElementById('att-grand-label');
    if (grandLabelEl) grandLabelEl.textContent = dayFilter.length === 1 ? 'ATTENDED · DAY ' + dayFilter[0] : dayFilter.length > 1 ? 'ATTENDED · ' + dayFilter.length + ' DAYS' : (filter.month === 'all' ? 'ATTENDED · ALL' : 'ATTENDED · ' + fmtMonth(gMonth).toUpperCase());

    // ── Multi-month summary: one column per month, Y counts + total ──
    if (filter.month === 'all') {
      const months = _summaryMonths;
      const monthHeaders = months.map(mo => `<th class="att-day-h" style="min-width:62px;width:62px">${fmtMonth(mo)}</th>`).join('');
      const body = rows.map(({ m, sport, coachId }) => {
        let grandY = 0;
        const cells = months.map(mo => {
          const dd = m.dailyAttendance?.[mo]?.[sport] || {};
          let y = 0; for (const k in dd) if (dd[k] === 'Y') y++;
          grandY += y;
          return `<td class="att-total" style="text-align:center">${y ? `<span style="color:var(--green);font-weight:600">${y}</span>` : '<span class="text-mute">·</span>'}</td>`;
        }).join('');
        const status = memberStatus(m);
        const isExpired = status === 'Expired';
        const _due2 = (currentRole() === 'coach' || typeof memberOutstanding !== 'function') ? 0 : memberOutstanding(m.id);
        const needsRenewal2 = isExpired && _due2 <= 0.5 && currentRole() !== 'coach';
        const statusBadge = isExpired ? '<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(242,96,96,.15);color:var(--red);margin-left:4px">EXPIRED</span>' : '';
        const renewBadge2 = needsRenewal2 ? `<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(245,158,11,.18);color:var(--accent-2);margin-left:4px" title="Paid up but membership expired — offer a renewal">🔄 ${t('RENEW', 'تجديد')}</span>` : '';
        const unpaidBadge2 = _due2 > 0.5 ? `<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(242,96,96,.15);color:var(--red);margin-left:4px" title="Not fully paid — ${fmt(_due2)} QAR due">💳 ${t('UNPAID', 'غير مدفوع')}</span>` : '';
        const rowStyle2 = needsRenewal2 ? 'background:rgba(245,158,11,.10);box-shadow:inset 3px 0 0 var(--accent-2)' : (isExpired ? 'background:rgba(120,120,140,.06)' : '');
        const sportEsc = sport.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '&quot;');
        return `<tr style="${rowStyle2}">
            <td class="att-name-cell" title="${escapeHtml(m.name)} · ${escapeHtml(sport)}${_due2 > 0.5 ? ' · ' + fmt(_due2) + ' QAR due' : ''}">
              <div style="font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;${isExpired ? 'color:var(--text-mute)' : ''}">${escapeHtml(m.name)}${statusBadge}${renewBadge2}${unpaidBadge2}</div>
              ${m.nameArabic ? `<div dir="rtl" style="font-size:11px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;${isExpired ? 'color:var(--text-mute)' : ''}">${escapeHtml(m.nameArabic)}</div>` : ''}
              <div class="text-mute" style="font-size:10px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(sport)}${sport !== SUMMER_CAMP ? ' · ' + escapeHtml(coachName(coachId)) : ''}</div>
            </td>
            ${cells}
            <td class="att-total"><span style="color:var(--green);font-weight:700">${grandY}</span></td>
            <td class="att-export-cell" style="text-align:center;white-space:nowrap">${needsRenewal2 ? `<button class="btn sm" style="background:var(--accent-2);border-color:var(--accent-2);color:#fff;margin-right:4px" onclick="window.addRenewal(${m.id})" title="Renew ${escapeHtml(m.name)}'s membership">🔄 ${t('Renew', 'تجديد')}</button>` : ''}<button class="btn ghost sm" onclick="window._attPdf(${m.id}, null, '${sportEsc}')" title="Export ${escapeHtml(m.name)} attendance">⬇ PDF</button></td>
          </tr>`;
      }).join('');
      $('#att-table-wrap').innerHTML = `
        <table class="att-table">
          <thead><tr><th class="att-name-h">Student</th>${monthHeaders}<th class="att-total-h">Total Y</th><th class="text-right">Export</th></tr></thead>
          <tbody>${body || `<tr><td colspan="${months.length + 3}" class="empty">No attendance recorded yet.</td></tr>`}</tbody>
        </table>`;
      const distinctMembers = new Set(rows.map(r => r.m.id)).size;
      $('#att-count').textContent = `${rows.length} attendance row${rows.length === 1 ? '' : 's'} · ${distinctMembers} student${distinctMembers === 1 ? '' : 's'} · ${filter.months.length ? filter.months.length + ' month' + (filter.months.length === 1 ? '' : 's') : 'all months (' + months.length + ')'} — present (Y) per month`;
      return;
    }

    const totalDays = daysInMonth(gMonth);
    // Day filter: when specific days are chosen (filter.days non-empty), show
    // only those columns (highlighted). Empty array = all days.
    const selectedDays = (filter.days || []).filter(d => d >= 1 && d <= totalDays);
    const isFiltered = selectedDays.length > 0;
    const baseDays = isFiltered ? [...selectedDays].sort((a, b) => a - b) : Array.from({length: totalDays}, (_, i) => i + 1);
    // Attended/Not-attended filter narrows the visible day columns too.
    const dayList = visibleDays(rows, baseDays, gMonth);
    const attNarrowed = dayList.length !== baseDays.length;
    const dayHeaders = dayList.map(d => `<th class="att-day-h${isFiltered ? ' att-day-active' : ''}">${d}</th>`).join('');

    // One row per (member, sport) — multi-sport members get multiple rows
    const body = rows.map(({ m, sport, coachId }) => {
      const dayData = m.dailyAttendance?.[gMonth]?.[sport] || {};
      let y = 0, n = 0;
      // Totals reflect the full selected scope (baseDays), not just shown columns.
      baseDays.forEach(d => { const mk = dayData[String(d)]; if (mk === 'Y') y++; if (mk === 'N') n++; });
      const cells = dayList.map(d => cellRender(m.id, sport, d, dayData[String(d)])).join('');
      const total = y + n;
      const rate = total ? Math.round(y/total*100) : 0;
      const sportEsc = sport.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '&quot;');
      const status = memberStatus(m);
      const isExpired = status === 'Expired';
      const isCompleted = status === 'Completed';
      // Camp over-limit flag: a Summer Camp member whose total present marks have
      // reached (or passed) their enrolled day count. They've finished their days —
      // flag the row red and surface the "Completed" status so it's obvious.
      let campOver = false, campLimit = 0, campMarked = 0;
      if (sport === SUMMER_CAMP) {
        // Use the CURRENT camp cycle (the one active this month) and count only its
        // window, so a renewed camp member isn't flagged "over limit" by a previous
        // cycle's days.
        const sub = (typeof subForAttendanceDate === 'function')
          ? subForAttendanceDate(m, SUMMER_CAMP, `${gMonth}-15`)
          : (m.subscriptions || []).filter(s => (s.activity || '') === SUMMER_CAMP).slice(-1)[0];
        campLimit = sub ? (parseInt(sub.totalClasses) || 0) : 0;
        if (campLimit > 0 && typeof liveAttendanceCount === 'function') {
          campMarked = liveAttendanceCount(m, SUMMER_CAMP, sub ? (sub.start || null) : null, sub ? (sub.end || null) : null).y || 0;
          campOver = campMarked >= campLimit;
        }
      }
      const _due = (currentRole() === 'coach' || typeof memberOutstanding !== 'function') ? 0 : memberOutstanding(m.id);
      // Expired but fully paid → a renewal candidate: highlight in amber so reception
      // is prompted to extend the membership (distinct from the red UNPAID case).
      const needsRenewal = isExpired && _due <= 0.5 && currentRole() !== 'coach';
      const rowStyle = campOver
        ? 'background:rgba(242,96,96,.12);box-shadow:inset 3px 0 0 var(--red)'
        : needsRenewal
        ? 'background:rgba(245,158,11,.10);box-shadow:inset 3px 0 0 var(--accent-2)'
        : (isExpired ? 'background:rgba(120,120,140,.06)' : '');
      const campOverBadge = campOver
        ? `<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(242,96,96,.18);color:var(--red);margin-left:4px" title="Attended ${campMarked} of ${campLimit} enrolled days — limit reached. Any extra day is over the enrolled count.">🚩 ${t('OVER LIMIT', 'تجاوز الحد')} ${campMarked}/${campLimit}</span>`
        : '';
      const unpaidBadge = _due > 0.5
        ? `<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(242,96,96,.15);color:var(--red);margin-left:4px" title="Not fully paid — ${fmt(_due)} QAR due">💳 ${t('UNPAID', 'غير مدفوع')}</span>`
        : '';
      const renewBadge = needsRenewal
        ? `<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(245,158,11,.18);color:var(--accent-2);margin-left:4px" title="Paid up but membership expired — offer a renewal">🔄 ${t('RENEW', 'تجديد')}</span>`
        : '';
      const statusBadge = isCompleted
        ? '<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(139,92,246,.16);color:var(--purple);margin-left:4px" title="Finished all enrolled camp days">✓ COMPLETED</span>'
        : isExpired
        ? '<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(242,96,96,.15);color:var(--red);margin-left:4px">EXPIRED</span>'
        : (status === 'Frozen'
          ? '<span class="badge" style="font-size:9px;padding:1px 6px;background:rgba(96,165,250,.15);color:var(--blue);margin-left:4px">FROZEN</span>'
          : '');
      return `
        <tr style="${rowStyle}">
          <td class="att-name-cell" title="${escapeHtml(m.name)} · ${escapeHtml(sport)}${sport !== SUMMER_CAMP ? ' · ' + escapeHtml(coachName(coachId)) : ''}${isExpired ? ' · expired ' + fmtDate(m.expiryDate) : ''}${_due > 0.5 ? ' · ' + fmt(_due) + ' QAR due' : ''}">
            <div style="font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;${isExpired ? 'color:var(--text-mute)' : ''}">${escapeHtml(m.name)}${statusBadge}${campOverBadge}${renewBadge}${unpaidBadge}</div>
            ${m.nameArabic ? `<div dir="rtl" style="font-size:11px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;${isExpired ? 'color:var(--text-mute)' : ''}">${escapeHtml(m.nameArabic)}</div>` : ''}
            <div class="text-mute" style="font-size:10px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(sport)}${sport !== SUMMER_CAMP ? ' · ' + escapeHtml(coachName(coachId)) : ''}</div>
          </td>
          ${cells}
          <td class="att-total"><span style="color:var(--green);font-weight:600">${y}</span><span class="text-mute"> / ${total || '—'}</span></td>
          <td class="text-right" style="color:${rate >= 75 ? 'var(--green)' : rate >= 40 ? 'var(--accent-2)' : rate > 0 ? 'var(--red)' : 'var(--text-mute)'};font-weight:600">${total ? rate + '%' : '—'}</td>
          <td class="att-export-cell" style="text-align:center;white-space:nowrap">${needsRenewal ? `<button class="btn sm" style="background:var(--accent-2);border-color:var(--accent-2);color:#fff;margin-right:4px" onclick="window.addRenewal(${m.id})" title="Renew ${escapeHtml(m.name)}'s membership">🔄 ${t('Renew', 'تجديد')}</button>` : ''}<button class="btn ghost sm" onclick="window._attPdf(${m.id}, null, '${sportEsc}')" title="Export ${escapeHtml(m.name)} · ${escapeHtml(sport)} attendance">⬇ PDF</button></td>
        </tr>`;
    }).join('');

    $('#att-table-wrap').innerHTML = `
      <table class="att-table">
        <thead>
          <tr>
            <th class="att-name-h">Student</th>
            ${dayHeaders}
            <th class="att-total-h">Total</th>
            <th class="text-right">Rate</th>
            <th class="text-right">Export</th>
          </tr>
        </thead>
        <tbody>${body || `<tr><td colspan="${dayList.length+4}" class="empty">No members match the current filters.</td></tr>`}</tbody>
      </table>
    `;
    let dayNote;
    if (attNarrowed) {
      dayNote = `${filter.att === 'attended' ? 'attended' : 'absent'} days only · ${dayList.length} day${dayList.length === 1 ? '' : 's'} of ${fmtMonth(gMonth)}`;
    } else if (isFiltered) {
      if (selectedDays.length === 1) dayNote = `showing day ${selectedDays[0]} of ${fmtMonth(gMonth)} only`;
      else dayNote = `showing ${selectedDays.length} days of ${fmtMonth(gMonth)} (${selectedDays.slice(0,5).join(', ')}${selectedDays.length>5?'…':''})`;
    } else {
      dayNote = 'click any cell to toggle Y → N → empty';
    }
    const distinctMembers = new Set(rows.map(r => r.m.id)).size;
    const rowText = `${rows.length} attendance row${rows.length === 1 ? '' : 's'} · ${distinctMembers} student${distinctMembers === 1 ? '' : 's'}`;
    $('#att-count').textContent = `${rowText} · ${dayNote}`;
  }

  main.innerHTML = `
    <style>
      .att-table {
        font-size: 12px;
        border-collapse: separate;
        border-spacing: 0;
        width: auto;
      }
      .att-table th, .att-table td {
        white-space: nowrap;
        padding: 6px 4px;
        border-bottom: 1px solid var(--border);
      }
      .att-name-h, .att-name-cell {
        position: sticky;
        left: 0;
        background: var(--surface);
        text-align: left;
        padding: 6px 12px;
        width: 220px;
        min-width: 200px;
        max-width: 240px;
        z-index: 2;
        border-right: 1px solid var(--border);
        overflow: hidden;
        text-overflow: ellipsis;
      }
      .att-name-h { background: var(--surface-2); z-index: 3; }
      .att-day-h {
        text-align: center;
        font-size: 10px;
        font-weight: 600;
        color: var(--text-mute);
        background: var(--surface-2);
        width: 28px;
        min-width: 28px;
      }
      .att-day-active {
        color: var(--accent);
        background: rgba(242,96,96,.12);
        font-size: 13px;
        width: 60px;
        min-width: 60px;
      }
      .att-total-h {
        position: sticky;
        right: 0;
        background: var(--surface-2);
        text-align: center;
        font-size: 11px;
        color: var(--text-mute);
        z-index: 3;
        width: 80px;
        min-width: 80px;
      }
      .att-table th.text-right { width: 90px; min-width: 80px; }
      .att-cell {
        text-align: center;
        cursor: pointer;
        font-weight: 600;
        font-size: 12px;
        user-select: none;
        transition: all .1s;
        width: 28px;
        height: 28px;
      }
      .att-cell:hover {
        outline: 1px solid var(--accent);
        outline-offset: -1px;
      }
      .att-empty { color: var(--text-mute); opacity: .4; }
      .att-y { background: rgba(16,185,129,.15); color: var(--green); }
      .att-n { background: rgba(239,68,68,.15); color: var(--red); }
      .att-total {
        position: sticky;
        right: 0;
        background: var(--surface);
        text-align: center;
        font-size: 12px;
        z-index: 2;
        border-left: 1px solid var(--border);
      }
      tbody tr:hover .att-name-cell,
      tbody tr:hover .att-total { background: var(--surface-2); }
    </style>

    <div class="topbar">
      <div>
        <h1>Attendance</h1>
        <div class="subtitle"><span id="att-count">Loading...</span></div>
      </div>
      <div class="topbar-actions">
        <div title="Classes attended (present) by students in the current view — respects the day filter" style="display:flex;flex-direction:column;align-items:center;justify-content:center;padding:4px 14px;margin-right:6px;background:rgba(16,185,129,.12);border:1px solid rgba(16,185,129,.35);border-radius:10px">
          <span style="font-size:20px;font-weight:700;color:var(--green);line-height:1"><span id="att-grand">0</span></span>
          <span id="att-grand-label" style="font-size:9px;color:var(--text-mute);text-transform:uppercase;letter-spacing:.5px">${t('Attended', 'إجمالي الحضور')}</span>
        </div>
        <button class="btn ghost" id="att-today">📍 Today</button>
        <button class="btn ghost" id="att-import">📂 Import CSV</button>
        <button class="btn ghost" id="att-export">📥 Export CSV</button>
        <button class="btn ghost" id="att-export-pdf">📄 Export PDF</button>
        <button class="btn ghost" id="att-export-img-en" title="Download the sheet as an image (English)">🖼 Image (EN)</button>
        <button class="btn ghost" id="att-export-img-ar" title="تحميل الورقة كصورة (عربي)">🖼 صورة (AR)</button>
      </div>
    </div>

    <div class="card">
      <div class="filter-bar att-filter-bar" style="flex-wrap:wrap;align-items:stretch">
        ${_coachLockToday ? `<div class="btn ghost" style="pointer-events:none;font-weight:700;background:rgba(16,185,129,.10);border-color:rgba(16,185,129,.4);color:var(--green)">📅 ${t('Today', 'اليوم')} · ${fmtDate(TODAY)}</div>` : ''}
        ${_coachLockToday ? '' : monthMultiHTML('att-month', availableMonths({ includeFuture: true }), filter.months)}
        <div style="position:relative${_coachLockToday ? ';display:none' : ''}">
          <button type="button" id="att-day-btn" class="btn ghost" style="min-width:130px;text-align:left;display:inline-flex;align-items:center;justify-content:space-between;gap:8px" title="Pick one or more days">All days <span style="opacity:.6">▾</span></button>
          <div id="att-day-menu" style="display:none;position:absolute;left:0;top:100%;z-index:50;background:var(--surface);border:1px solid var(--border);border-radius:8px;margin-top:4px;padding:8px;min-width:240px;max-height:340px;overflow-y:auto;box-shadow:0 8px 24px rgba(0,0,0,.4)">
            <div style="display:flex;gap:6px;margin-bottom:8px;padding-bottom:8px;border-bottom:1px solid var(--border)">
              <button type="button" class="btn ghost sm" id="att-day-all">All</button>
              <button type="button" class="btn ghost sm" id="att-day-none">Clear</button>
              <button type="button" class="btn ghost sm" id="att-day-today">Today</button>
            </div>
            <div id="att-day-grid" style="display:grid;grid-template-columns:repeat(7,1fr);gap:4px"></div>
          </div>
        </div>
        <select id="att-week" class="btn ghost" title="Quick-pick a week (selects all 7 days)" ${_coachLockToday ? 'style="display:none"' : ''}>
          <option value="all">All weeks</option>
          <option value="1">Week 1 (1–7)</option>
          <option value="2">Week 2 (8–14)</option>
          <option value="3">Week 3 (15–21)</option>
          <option value="4">Week 4 (22–28)</option>
          <option value="5">Week 5 (29–end)</option>
        </select>
        <select id="att-coach" class="btn ghost" ${myCoachId != null ? 'style="display:none"' : ''}>
          <option value="all">All coaches</option>
          ${state.coaches.map(c => `<option value="${c.id}">${escapeHtml(c.name)}</option>`).join('')}
        </select>
        <select id="att-status" class="btn ghost" title="Show only students who attended (have a present mark) or did not, within the selected day(s) / month">
          <option value="all">All attendance</option>
          <option value="attended">✓ Attended</option>
          <option value="notattended">✗ Not attended</option>
        </select>
        <div style="position:relative">
          <button type="button" id="att-sports-btn" style="min-width:150px;text-align:left;display:inline-flex;align-items:center;justify-content:space-between;gap:8px">All sports <span style="opacity:.6">▾</span></button>
          <div id="att-sports-menu" style="display:none;position:absolute;left:0;top:100%;z-index:50;background:var(--surface);border:1px solid var(--border);border-radius:8px;margin-top:4px;padding:8px;min-width:180px;box-shadow:0 8px 24px rgba(0,0,0,.4)">
            ${SPORTS.map(s => `<label style="display:flex;align-items:center;gap:8px;padding:5px 6px;cursor:pointer;font-size:13px"><input type="checkbox" class="att-sport-cb" value="${s}" /> ${s}</label>`).join('')}
          </div>
        </div>
        <div style="min-width:260px;flex:1;max-width:340px">${memberPickerHtml('att-student', { placeholder: 'All students (type to search)' })}</div>
        <div class="text-mute" style="margin-left:auto;font-size:11px;align-self:center">
          <span class="att-cell att-y" style="display:inline-block;padding:2px 6px;border-radius:3px">Y</span> present ·
          <span class="att-cell att-n" style="display:inline-block;padding:2px 6px;border-radius:3px">N</span> absent ·
          <span class="text-mute">·</span> not marked
        </div>
      </div>
      <div style="overflow-x:auto;max-height:70vh;overflow-y:auto" id="att-table-wrap"></div>
    </div>
  `;

  // Day-grid helper: build the checkbox grid based on the active month
  function buildDayGrid() {
    const dm = filter.month === 'all' ? 31 : daysInMonth(filter.month);
    const grid = $('#att-day-grid');
    if (!grid) return;
    grid.innerHTML = Array.from({length: dm}, (_, i) => {
      const d = i + 1;
      const checked = (filter.days || []).includes(d) ? 'checked' : '';
      return `<label style="display:flex;flex-direction:column;align-items:center;padding:5px 0;cursor:pointer;font-size:11px;border-radius:4px" class="att-day-cell">
        <input type="checkbox" class="att-day-cb" value="${d}" ${checked} style="margin-bottom:2px"/>
        <span>${d}</span>
      </label>`;
    }).join('');
    grid.querySelectorAll('.att-day-cb').forEach(cb => cb.addEventListener('change', applyDays));
  }
  function applyDays() {
    filter.days = $$('.att-day-cb').filter(cb => cb.checked).map(cb => parseInt(cb.value));
    const btn = $('#att-day-btn');
    if (btn) btn.innerHTML = (filter.days.length ? (filter.days.length === 1 ? `Day ${filter.days[0]}` : `${filter.days.length} days`) : 'All days') + ' <span style="opacity:.6">▾</span>';
    refresh();
  }

  bindMonthMulti('att-month', (months) => {
    filter.months = months;
    syncMonthFromMonths();   // 1 month → day-grid; 0 or 2+ → month summary
    const dm = filter.month === 'all' ? 31 : daysInMonth(filter.month);
    filter.days = (filter.days || []).filter(d => d >= 1 && d <= dm);   // drop days outside the new month
    buildDayGrid();
    applyDays();
  });
  $('#att-coach').addEventListener('change', e => { filter.coach = e.target.value; refresh(); });
  $('#att-status').addEventListener('change', e => { filter.att = e.target.value; refresh(); });

  // Day multi-select dropdown
  const dayBtn = $('#att-day-btn');
  const dayMenu = $('#att-day-menu');
  if (dayBtn) {
    dayBtn.addEventListener('click', () => {
      dayMenu.style.display = dayMenu.style.display === 'none' ? 'block' : 'none';
    });
    document.addEventListener('click', e => {
      if (!dayBtn.contains(e.target) && !dayMenu.contains(e.target)) dayMenu.style.display = 'none';
    });
    $('#att-day-all').addEventListener('click', () => {
      const dm = filter.month === 'all' ? 31 : daysInMonth(filter.month);
      filter.days = Array.from({length: dm}, (_, i) => i + 1);
      buildDayGrid(); applyDays();
    });
    $('#att-day-none').addEventListener('click', () => { filter.days = []; buildDayGrid(); applyDays(); });
    $('#att-day-today').addEventListener('click', () => {
      const n = new Date();
      const tm = `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,'0')}`;
      if (tm === filter.month) { filter.days = [n.getDate()]; buildDayGrid(); applyDays(); }
      else toast('Today is not in the selected month');
    });
  }
  buildDayGrid();
  // Initialize button label
  const dbtn = $('#att-day-btn');
  if (dbtn) dbtn.innerHTML = (filter.days.length ? (filter.days.length === 1 ? `Day ${filter.days[0]}` : `${filter.days.length} days`) : 'All days') + ' <span style="opacity:.6">▾</span>';

  // Week quick-pick: selecting a week picks all 7 days of that week
  $('#att-week').addEventListener('change', e => {
    const v = e.target.value;
    if (v === 'all') { filter.days = []; }
    else {
      const w = parseInt(v);
      const start = (w - 1) * 7 + 1;
      const dm = filter.month === 'all' ? 31 : daysInMonth(filter.month);
      const end = Math.min(start + 6, dm);
      filter.days = Array.from({length: end - start + 1}, (_, i) => start + i);
    }
    buildDayGrid(); applyDays();
  });

  // Searchable student dropdown (member picker) — selecting one filters to that student
  bindMemberPicker('att-student', { placeholder: 'All students (type to search)' });
  const attStudentHidden = $('#att-student');
  const attStudentSearch = $('#att-student-search');
  if (attStudentHidden) {
    // Watch the hidden input for a chosen id; also let free typing filter the list
    const applyStudent = () => {
      const v = attStudentHidden.value;
      filter.memberId = v ? parseInt(v) : null;
      // if nothing explicitly chosen, use the typed text as a free search
      filter.search = (!v && attStudentSearch) ? attStudentSearch.value.trim() : '';
      refresh();
    };
    attStudentHidden.addEventListener('change', applyStudent);
    // mousedown selection updates hidden value without firing 'change', so poll on blur/input
    attStudentSearch.addEventListener('input', () => { filter.memberId = null; filter.search = attStudentSearch.value.trim(); refresh(); });
    attStudentSearch.addEventListener('blur', () => setTimeout(applyStudent, 200));
  }

  // Multi-select sports dropdown
  const sportsBtn = $('#att-sports-btn');
  const sportsMenu = $('#att-sports-menu');
  if (sportsBtn) {
    sportsBtn.addEventListener('click', () => {
      sportsMenu.style.display = sportsMenu.style.display === 'none' ? 'block' : 'none';
    });
    document.addEventListener('click', e => {
      if (!sportsBtn.contains(e.target) && !sportsMenu.contains(e.target)) sportsMenu.style.display = 'none';
    });
    $$('.att-sport-cb').forEach(cb => cb.addEventListener('change', () => {
      filter.sports = $$('.att-sport-cb').filter(x => x.checked).map(x => x.value);
      sportsBtn.innerHTML = (filter.sports.length ? `${filter.sports.length} sport${filter.sports.length > 1 ? 's' : ''}` : 'All sports') + ' <span style="opacity:.6">▾</span>';
      refresh();
    }));
  }

  // All-months summary PDF: one column per month with present (Y) counts + year total.
  function exportAttendanceMonthsPdf(rows) {
    const months = monthsWithData();
    if (!months.length) { toast('No attendance recorded yet', 'error'); return; }
    const monthHeads = months.map(mo => `<th style="border:1px solid #e5e5ea;padding:4px 2px;font-size:8.5px;color:#777">${fmtMonth(mo)}</th>`).join('');
    let grandY = 0;
    const bodyRows = rows.map(({ m, sport, coachId }) => {
      let rowY = 0;
      const cells = months.map(mo => {
        const dd = m.dailyAttendance?.[mo]?.[sport] || {};
        let y = 0; for (const k in dd) if (dd[k] === 'Y') y++;
        rowY += y;
        return `<td style="border:1px solid #eee;text-align:center;font-size:9px;background:${y ? '#d1fae5' : '#fff'};color:${y ? '#065f46' : '#ccc'};font-weight:600">${y || '·'}</td>`;
      }).join('');
      grandY += rowY;
      return `<tr>
        <td style="border:1px solid #e5e5ea;padding:4px 6px;font-size:9px;font-weight:600"><div style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(m.name)}</div><div style="font-size:7.5px;color:#999;font-weight:400">${escapeHtml(sport)}${sport !== SUMMER_CAMP ? ' · ' + escapeHtml(coachName(coachId)) : ''}</div></td>
        ${cells}
        <td style="border:1px solid #e5e5ea;text-align:center;font-size:9px;font-weight:700;color:#059669">${rowY}</td>
      </tr>`;
    }).join('');
    const coachLabel = filter.coach !== 'all' ? coachName(parseInt(filter.coach)) : 'All coaches';
    const sportLabel = filter.sports.length ? filter.sports.join(', ') : 'All sports';
    const distinctMembers = new Set(rows.map(r => r.m.id)).size;
    const win = window.open('', '_blank');
    win.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>attendance_all_months</title>
    <style>
      *{margin:0;padding:0;box-sizing:border-box}
      @page{size:A4 landscape;margin:8mm}
      body{font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#1a1a1a;padding:14px}
      .head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #f26060;padding-bottom:10px;margin-bottom:12px}
      .brand{font-size:18px;font-weight:800}.brand span{color:#f26060}
      .sub{color:#777;font-size:11px;margin-top:2px}
      .meta{font-size:11px;color:#555;margin-bottom:10px}.meta b{color:#1a1a1a}
      table{border-collapse:collapse;width:100%}
      thead th{background:#fafafa;text-align:center}
      .foot{margin-top:14px;font-size:9px;color:#aaa;text-align:center;border-top:1px solid #eee;padding-top:6px}
    </style></head><body>
      <div class="head">
        <div><div class="brand">Black <span>Stars</span> Sports Club</div><div class="sub">Waab, Doha · Attendance Report — all months</div></div>
        <div style="text-align:right;font-size:11px;color:#777">Generated<br><b>${fmtDate(TODAY)}</b></div>
      </div>
      <div class="meta">All months (${months.length}) · ${escapeHtml(coachLabel)} · ${escapeHtml(sportLabel)} · <b>${distinctMembers}</b> student${distinctMembers===1?'':'s'} · <b>${rows.length}</b> row${rows.length===1?'':'s'} · <b>${grandY}</b> present total</div>
      <table>
        <thead><tr><th style="border:1px solid #e5e5ea;padding:4px 6px;font-size:9px;color:#777;text-align:left">Student · Sport</th>${monthHeads}<th style="border:1px solid #e5e5ea;font-size:9px;color:#777">Total Y</th></tr></thead>
        <tbody>${bodyRows}</tbody>
      </table>
      <div class="foot">Black Stars CRM · cell = present (Y) days that month</div>
      <script>window.onload=()=>window.print();<\/script>
    </body></html>`);
    win.document.close();
    toast(`PDF · all months · ${rows.length} rows`);
  }

  $('#att-export-pdf').addEventListener('click', () => {
    const rows = getRows();
    if (!rows.length) { toast('No students to export', 'error'); return; }
    if (filter.month === 'all') { exportAttendanceMonthsPdf(rows); return; }
    const gM = gridMonth();
    const totalDays = daysInMonth(gM);
    const selDays = (filter.days || []).filter(d => d >= 1 && d <= totalDays);
    const baseDays = selDays.length ? selDays.slice().sort((a, b) => a - b) : Array.from({length: totalDays}, (_, i) => i + 1);
    const dayCols = visibleDays(rows, baseDays, gM);   // attended/absent narrowing
    const days = dayCols.length;

    const dayHeads = dayCols.map(d => `<th style="border:1px solid #e5e5ea;padding:3px 1px;font-size:8px;color:#777">${d}</th>`).join('');
    let grandY = 0, grandSlots = 0;
    const bodyRows = rows.map(({ m, sport, coachId }) => {
      const dd = m.dailyAttendance?.[gM]?.[sport] || {};
      let y = 0, n = 0;
      baseDays.forEach(d => { const v = dd[String(d)]; if (v === 'Y') y++; if (v === 'N') n++; });   // totals over full scope
      const cells = dayCols.map(d => {
        const v = dd[String(d)];
        const bg = v==='Y'?'#d1fae5':v==='N'?'#fee2e2':'#fff';
        const col = v==='Y'?'#065f46':v==='N'?'#991b1b':'#ccc';
        return `<td style="border:1px solid #eee;text-align:center;font-size:8px;background:${bg};color:${col};font-weight:600">${v||'·'}</td>`;
      }).join('');
      const tot = y+n; const rate = tot?Math.round(y/tot*100):0;
      grandY += y; grandSlots += tot;
      const rcol = rate>=75?'#059669':rate>=40?'#d97706':rate>0?'#dc2626':'#999';
      return `<tr>
        <td style="border:1px solid #e5e5ea;padding:4px 6px;font-size:9px;font-weight:600;overflow:hidden;text-overflow:ellipsis"><div style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(m.name)}</div><div style="font-size:7.5px;color:#999;font-weight:400;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(sport)}${sport !== SUMMER_CAMP ? ' · ' + escapeHtml(coachName(coachId)) : ''}</div></td>
        ${cells}
        <td style="border:1px solid #e5e5ea;text-align:center;font-size:9px;font-weight:700">${y}/${tot||'—'}</td>
        <td style="border:1px solid #e5e5ea;text-align:center;font-size:9px;font-weight:700;color:${rcol}">${tot?rate+'%':'—'}</td>
      </tr>`;
    }).join('');

    const coachLabel = filter.coach !== 'all' ? coachName(parseInt(filter.coach)) : 'All coaches';
    const sportLabel = filter.sports.length ? filter.sports.join(', ') : 'All sports';
    const attLabel = filter.att === 'attended' ? ' · attended days only' : filter.att === 'notattended' ? ' · absent days only' : '';
    const overallRate = grandSlots ? Math.round(grandY/grandSlots*100) : 0;
    const distinctMembers = new Set(rows.map(r => r.m.id)).size;

    // Build a <colgroup> so the table respects column widths instead of letting
    // the Student column stretch wide. `table-layout: fixed` + colgroup is the
    // canonical way to lock layout for print.
    const dayColWidth = `calc((100% - 200px) / ${days})`;  // 200px = student(140) + Y/Tot(34) + Rate(26)
    const colgroup = `<colgroup>
      <col style="width:140px">
      ${Array.from({length:days},() => `<col style="width:${dayColWidth}">`).join('')}
      <col style="width:34px">
      <col style="width:26px">
    </colgroup>`;

    const win = window.open('', '_blank');
    win.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>attendance_${gM}</title>
    <style>
      *{margin:0;padding:0;box-sizing:border-box}
      @page{size:A4 landscape;margin:8mm}
      body{font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#1a1a1a;padding:14px}
      .head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #f26060;padding-bottom:10px;margin-bottom:12px}
      .brand{font-size:18px;font-weight:800}.brand span{color:#f26060}
      .sub{color:#777;font-size:11px;margin-top:2px}
      .meta{font-size:11px;color:#555;margin-bottom:10px}
      .meta b{color:#1a1a1a}
      table{border-collapse:collapse;width:100%;table-layout:fixed}
      thead th{background:#fafafa;text-align:center}
      td{overflow:hidden}
      .foot{margin-top:14px;font-size:9px;color:#aaa;text-align:center;border-top:1px solid #eee;padding-top:6px}
    </style></head><body>
      <div class="head">
        <div><div class="brand">Black <span>Stars</span> Sports Club</div><div class="sub">Waab, Doha · Attendance Report</div></div>
        <div style="text-align:right;font-size:11px;color:#777">Generated<br><b>${fmtDate(TODAY)}</b></div>
      </div>
      <div class="meta"><b>${fmtMonth(gM)}</b>${attLabel} · ${escapeHtml(coachLabel)} · ${escapeHtml(sportLabel)} · <b>${distinctMembers}</b> student${distinctMembers===1?'':'s'} · <b>${rows.length}</b> row${rows.length===1?'':'s'} · overall <b>${overallRate}%</b></div>
      <table>
        ${colgroup}
        <thead><tr><th style="border:1px solid #e5e5ea;padding:4px 6px;font-size:9px;color:#777;text-align:left">Student · Sport</th>${dayHeads}<th style="border:1px solid #e5e5ea;font-size:9px;color:#777">Y/Tot</th><th style="border:1px solid #e5e5ea;font-size:9px;color:#777">Rate</th></tr></thead>
        <tbody>${bodyRows}</tbody>
      </table>
      <div class="foot">Black Stars CRM · Y = present · N = absent · · = not marked</div>
      <script>window.onload=()=>window.print();<\/script>
    </body></html>`);
    win.document.close();
    toast(`PDF report · ${rows.length} rows`);
  });

  // ─── Attendance sheet → IMAGE (PNG), English or Arabic ─────────────────
  // Builds the same grid as the PDF, but renders it to a PNG via an SVG
  // foreignObject → canvas (no external libraries, works offline). Two buttons
  // pick the language for the labels/heading and the text direction.
  function exportAttendanceImage(lang) {
    const ar = lang === 'ar';
    const L = ar ? {
      brand: '★ نادي بلاك ستارز الرياضي', sub: 'الوعب، الدوحة · تقرير الحضور',
      generated: 'تاريخ الإصدار', student: 'الطالب · الرياضة', yTot: 'حضور/إجمالي',
      rate: 'النسبة', students: 'طالب', rows: 'صف', overall: 'الإجمالي',
      allCoaches: 'كل المدربين', allSports: 'كل الرياضات', present: 'حاضر', absent: 'غائب',
      legend: 'حاضر = Y · غائب = N · لم يُسجّل = ·', noData: 'لا يوجد طلاب للتصدير',
    } : {
      brand: '★ Black Stars Sports Club', sub: 'Waab, Doha · Attendance Report',
      generated: 'Generated', student: 'Student · Sport', yTot: 'Y/Tot',
      rate: 'Rate', students: 'students', rows: 'rows', overall: 'overall',
      allCoaches: 'All coaches', allSports: 'All sports', present: 'P', absent: 'A',
      legend: 'Y = present · N = absent · · = not marked', noData: 'No students to export',
    };
    const rows = getRows();
    if (!rows.length) { toast(L.noData, 'error'); return; }
    if (filter.month === 'all') { toast(ar ? 'اختر شهراً محدداً لتصدير الصورة' : 'Pick a specific month for image export', 'error'); return; }
    const gM = gridMonth();
    const totalDays = daysInMonth(gM);
    const selDays = (filter.days || []).filter(d => d >= 1 && d <= totalDays);
    const baseDays = selDays.length ? selDays.slice().sort((a, b) => a - b) : Array.from({ length: totalDays }, (_, i) => i + 1);
    const dayCols = visibleDays(rows, baseDays, gM);
    const dir = ar ? 'rtl' : 'ltr';
    const align = ar ? 'right' : 'left';

    const dayHeads = dayCols.map(d => `<th style="border:1px solid #e5e5ea;padding:3px 1px;font-size:8px;color:#777">${d}</th>`).join('');
    let grandY = 0, grandSlots = 0;
    const bodyRows = rows.map(({ m, sport, coachId }) => {
      const dd = m.dailyAttendance?.[gM]?.[sport] || {};
      let y = 0, n = 0;
      baseDays.forEach(d => { const v = dd[String(d)]; if (v === 'Y') y++; if (v === 'N') n++; });
      const cells = dayCols.map(d => {
        const v = dd[String(d)];
        const bg = v === 'Y' ? '#d1fae5' : v === 'N' ? '#fee2e2' : '#fff';
        const col = v === 'Y' ? '#065f46' : v === 'N' ? '#991b1b' : '#ccc';
        return `<td style="border:1px solid #eee;text-align:center;font-size:8px;background:${bg};color:${col};font-weight:600">${v || '·'}</td>`;
      }).join('');
      const tot = y + n; const rate = tot ? Math.round(y / tot * 100) : 0;
      grandY += y; grandSlots += tot;
      const rcol = rate >= 75 ? '#059669' : rate >= 40 ? '#d97706' : rate > 0 ? '#dc2626' : '#999';
      const sportCoach = escapeHtml(sport) + (sport !== SUMMER_CAMP ? ' · ' + escapeHtml(coachName(coachId)) : '');
      return `<tr>
        <td style="border:1px solid #e5e5ea;padding:4px 6px;font-size:9px;font-weight:600;text-align:${align}"><div style="white-space:nowrap">${escapeHtml(ar && m.nameArabic ? m.nameArabic : m.name)}</div><div style="font-size:7.5px;color:#999;font-weight:400;white-space:nowrap">${sportCoach}</div></td>
        ${cells}
        <td style="border:1px solid #e5e5ea;text-align:center;font-size:9px;font-weight:700">${y}/${tot || '—'}</td>
        <td style="border:1px solid #e5e5ea;text-align:center;font-size:9px;font-weight:700;color:${rcol}">${tot ? rate + '%' : '—'}</td>
      </tr>`;
    }).join('');

    const coachLabel = filter.coach !== 'all' ? coachName(parseInt(filter.coach)) : L.allCoaches;
    const sportLabel = filter.sports.length ? filter.sports.join(', ') : L.allSports;
    const overallRate = grandSlots ? Math.round(grandY / grandSlots * 100) : 0;
    const distinctMembers = new Set(rows.map(r => r.m.id)).size;
    const monthLabel = ar ? monthNameAR(new Date(gM + '-01')) : fmtMonth(gM);

    // Width scales with the number of day columns so everything stays legible.
    const W = Math.max(900, 220 + dayCols.length * 26 + 90);
    const html = `
      <div xmlns="http://www.w3.org/1999/xhtml" dir="${dir}" style="width:${W}px;background:#fff;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#1a1a1a;padding:18px;box-sizing:border-box">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #f26060;padding-bottom:10px;margin-bottom:12px">
          <div><div style="font-size:18px;font-weight:800">${L.brand}</div><div style="color:#777;font-size:11px;margin-top:2px">${L.sub}</div></div>
          <div style="text-align:${ar ? 'left' : 'right'};font-size:11px;color:#777">${L.generated}<br/><b>${fmtDate(TODAY)}</b></div>
        </div>
        <div style="font-size:11px;color:#555;margin-bottom:10px"><b>${monthLabel}</b> · ${escapeHtml(coachLabel)} · ${escapeHtml(sportLabel)} · <b>${distinctMembers}</b> ${L.students} · <b>${rows.length}</b> ${L.rows} · ${L.overall} <b>${overallRate}%</b></div>
        <table style="border-collapse:collapse;width:100%">
          <thead><tr><th style="border:1px solid #e5e5ea;padding:4px 6px;font-size:9px;color:#777;text-align:${align}">${L.student}</th>${dayHeads}<th style="border:1px solid #e5e5ea;font-size:9px;color:#777">${L.yTot}</th><th style="border:1px solid #e5e5ea;font-size:9px;color:#777">${L.rate}</th></tr></thead>
          <tbody>${bodyRows}</tbody>
        </table>
        <div style="margin-top:14px;font-size:9px;color:#aaa;text-align:center;border-top:1px solid #eee;padding-top:6px">${L.legend}</div>
      </div>`;

    // Measure height by rendering off-screen first.
    const probe = document.createElement('div');
    probe.style.cssText = `position:fixed;left:-99999px;top:0;width:${W}px`;
    probe.innerHTML = html;
    document.body.appendChild(probe);
    const H = Math.ceil(probe.firstElementChild.getBoundingClientRect().height) + 4;
    document.body.removeChild(probe);

    const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}"><foreignObject x="0" y="0" width="${W}" height="${H}">${html}</foreignObject></svg>`;
    const img = new Image();
    const url = 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svg);
    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const scale = 2;   // retina quality
        canvas.width = W * scale; canvas.height = H * scale;
        const ctx = canvas.getContext('2d');
        ctx.fillStyle = '#fff'; ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.scale(scale, scale);
        ctx.drawImage(img, 0, 0);
        canvas.toBlob(blob => {
          if (!blob) { toast('Image export failed — try the PDF instead', 'error'); return; }
          const a = document.createElement('a');
          a.href = URL.createObjectURL(blob);
          a.download = `attendance_${gM}_${ar ? 'ar' : 'en'}.png`;
          a.click();
          setTimeout(() => URL.revokeObjectURL(a.href), 1000);
          toast(ar ? `صورة الحضور · ${rows.length} صف` : `Attendance image · ${rows.length} rows`);
        }, 'image/png');
      } catch (_) { toast('Image export failed — try the PDF instead', 'error'); }
    };
    img.onerror = () => { toast('Image export failed — try the PDF instead', 'error'); };
    img.src = url;
  }
  $('#att-export-img-en')?.addEventListener('click', () => exportAttendanceImage('en'));
  $('#att-export-img-ar')?.addEventListener('click', () => exportAttendanceImage('ar'));

  $('#att-export').addEventListener('click', () => {
    const rows = getRows();
    if (filter.month === 'all') {
      // All-months summary: one column per month (present Y count) + year total.
      const months = monthsWithData();
      const csvRows = [['Student','Sport','Coach',...months.map(fmtMonth),'Total Y']];
      for (const { m, sport, coachId } of rows) {
        let grand = 0;
        const cells = months.map(mo => {
          const dd = m.dailyAttendance?.[mo]?.[sport] || {};
          let y = 0; for (const k in dd) if (dd[k] === 'Y') y++;
          grand += y; return y;
        });
        csvRows.push([m.name, sport, sport === SUMMER_CAMP ? '' : coachName(coachId), ...cells, grand]);
      }
      const csv = csvRows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
      downloadFile('attendance-all-months.csv', csv, 'text/csv');
      toast('Attendance CSV exported · all months');
      return;
    }
    const gM = gridMonth();
    const totalDays = daysInMonth(gM);
    const selDays = (filter.days || []).filter(d => d >= 1 && d <= totalDays);
    const baseDays = selDays.length ? selDays.slice().sort((a, b) => a - b) : Array.from({length: totalDays}, (_, i) => i + 1);
    const dayCols = visibleDays(rows, baseDays, gM);
    const csvRows = [['Student','Sport','Coach',...dayCols.map(String),'Total Y','Total N','Rate']];
    for (const { m, sport, coachId } of rows) {
      const dd = m.dailyAttendance?.[gM]?.[sport] || {};
      let y = 0, n = 0;
      baseDays.forEach(d => { const v = dd[String(d)]; if (v === 'Y') y++; if (v === 'N') n++; });
      const cells = dayCols.map(d => dd[String(d)] || '');
      csvRows.push([m.name, sport, sport === SUMMER_CAMP ? '' : coachName(coachId), ...cells, y, n, y+n ? Math.round(y/(y+n)*100)+'%' : '']);
    }
    const csv = csvRows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
    downloadFile(`attendance-${gM}.csv`, csv, 'text/csv');
    toast('Attendance CSV exported');
  });

  $('#att-today').addEventListener('click', () => {
    const now = new Date();
    const ymonth = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}`;
    const dayNum = now.getDate();
    const monthsAvail = availableMonths();
    const target = monthsAvail.includes(ymonth) ? ymonth : (monthsAvail.length ? monthsAvail[monthsAvail.length-1] : ymonth);
    filter.months = [target];
    syncMonthFromMonths();
    // Reflect the single-month pick in the month multi-select picker.
    const mm = document.getElementById('att-month');
    if (mm) { mm.querySelectorAll('.mm-pop input[type=checkbox]').forEach(b => { b.checked = !b.classList.contains('mm-all-cb') && b.value === target; }); const l = mm.querySelector('.mm-label'); if (l) l.textContent = fmtMonth(target); }
    const dm = daysInMonth(target);
    const useDay = dayNum <= dm ? dayNum : 1;
    filter.days = [useDay];
    buildDayGrid();
    applyDays();
    toast(`Jumped to day ${useDay} · tap names to mark present`);
  });

  $('#att-import').addEventListener('click', () => {
    toast('Import: drop a CSV in the same format as Export', 'success');
  });

  refresh();
};

// ─── Per-student attendance PDF report ──────────────────────────────
window._attPdf = function(memberId, month, sport) {
  const m = state.members.find(x => x.id === memberId);
  if (!m) return;
  const mo = month || (window._attCurrentMonth) || latestDataMonth();
  const days = daysInMonth(mo);
  const sportsMap = m.dailyAttendance?.[mo] || {};
  // If a sport was passed, show just that sport. Otherwise show all sports the
  // member has attendance for, in this month.
  const sportsShown = sport ? [sport] : Object.keys(sportsMap);
  if (!sportsShown.length && sport) sportsShown.push(sport);
  if (!sportsShown.length) sportsShown.push(m.sport || '—');

  let totalY = 0, totalN = 0;
  const sportSections = sportsShown.map(sp => {
    const dd = sportsMap[sp] || {};
    let y = 0, n = 0;
    const marked = [];
    for (let d = 1; d <= days; d++) {
      const v = dd[String(d)];
      if (v === 'Y') { y++; marked.push({ d, v }); }
      else if (v === 'N') { n++; marked.push({ d, v }); }
    }
    totalY += y; totalN += n;
    const sTot = y + n;
    const sRate = sTot ? Math.round(y / sTot * 100) : 0;
    const enr = (m.enrollments || []).find(e => e.sport === sp);
    const cid = enr?.coachId ?? m.coachId;
    // Vertical list of marked days — reads top-to-bottom, ideal on a phone.
    const dayRows = marked.length ? marked.map(c => {
      const dateStr = fmtDate(`${mo}-${String(c.d).padStart(2, '0')}`);
      const present = c.v === 'Y';
      return `<tr>
        <td style="border:1px solid #e5e5ea;padding:7px 10px;font-size:12px">${dateStr}</td>
        <td style="border:1px solid #e5e5ea;padding:7px 10px;text-align:center;font-weight:700;font-size:12px;background:${present ? '#d1fae5' : '#fee2e2'};color:${present ? '#065f46' : '#991b1b'}">${present ? 'Present' : 'Absent'}</td>
      </tr>`;
    }).join('') : `<tr><td colspan="2" style="border:1px solid #e5e5ea;padding:10px;text-align:center;color:#999;font-size:12px">No days marked this month</td></tr>`;
    return `
      <div style="margin-bottom:20px">
        <div style="font-size:14px;font-weight:700;color:#f26060;margin-bottom:8px">${escapeHtml(sp)}${sp === SUMMER_CAMP ? '' : ' · Coach ' + escapeHtml(coachName(cid))} · <span style="color:#666;font-weight:500">${y}/${sTot} · ${sTot ? sRate + '%' : '—'}</span></div>
        <table style="width:100%;border-collapse:collapse"><thead><tr>
          <th style="border:1px solid #e5e5ea;padding:6px 10px;font-size:10px;color:#777;background:#fafafa;text-align:left;text-transform:uppercase;letter-spacing:.5px">Date</th>
          <th style="border:1px solid #e5e5ea;padding:6px 10px;font-size:10px;color:#777;background:#fafafa;text-align:center;text-transform:uppercase;letter-spacing:.5px">Attendance</th>
        </tr></thead>
        <tbody>${dayRows}</tbody></table>
      </div>`;
  }).join('');

  const total = totalY + totalN;
  const rate = total ? Math.round(totalY / total * 100) : 0;
  const fileName = `${m.name.replace(/[^a-z0-9]+/gi, '_')}${sport?`_${sport.replace(/[^a-z0-9]+/gi,'_')}`:''}_attendance_${mo}`;

  const win = window.open('', '_blank');
  win.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${fileName}</title>
  <style>
    *{margin:0;padding:0;box-sizing:border-box}
    @page{size:A4 portrait;margin:12mm}
    body{font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#1a1a1a;padding:24px;max-width:600px;margin:0 auto}
    .head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #f26060;padding-bottom:14px;margin-bottom:18px}
    .brand{font-size:22px;font-weight:800}.brand span{color:#f26060}
    .sub{color:#777;font-size:12px;margin-top:2px}
    h1{font-size:17px;margin-bottom:2px}
    .meta{font-size:12px;color:#555;margin-bottom:16px}
    .meta b{color:#1a1a1a}
    table{border-collapse:collapse;margin-bottom:10px}
    .summary{display:flex;gap:10px;margin-bottom:18px;flex-wrap:wrap}
    .kpi{flex:1;min-width:110px;border:1px solid #e5e5ea;border-radius:8px;padding:10px 14px}
    .kpi .l{font-size:10px;text-transform:uppercase;color:#999;letter-spacing:.5px}
    .kpi .v{font-size:22px;font-weight:700;margin-top:2px}
    .foot{margin-top:24px;font-size:10px;color:#aaa;text-align:center;border-top:1px solid #eee;padding-top:10px}
  </style></head><body>
    <div class="head">
      <div><div class="brand">Black <span>Stars</span> Sports Club</div><div class="sub">Waab, Doha · Attendance Report</div></div>
      <div style="text-align:right;font-size:11px;color:#777">Generated<br><b>${fmtDate(TODAY)}</b></div>
    </div>
    <h1>${escapeHtml(m.name)}${m.nameArabic ? ` <span style="color:#999;font-weight:400">(${escapeHtml(m.nameArabic)})</span>` : ''}</h1>
    <div class="meta">${sport ? '' : `<b>${sportsShown.length} sport${sportsShown.length===1?'':'s'}</b> · `}${fmtMonth(mo)} · Status: <b>${memberStatus(m)}</b></div>
    <div class="summary">
      <div class="kpi"><div class="l">Present (Y)</div><div class="v" style="color:#059669">${totalY}</div></div>
      <div class="kpi"><div class="l">Absent (N)</div><div class="v" style="color:#dc2626">${totalN}</div></div>
      <div class="kpi"><div class="l">Days marked</div><div class="v">${total}</div></div>
      <div class="kpi"><div class="l">Overall rate</div><div class="v" style="color:${rate>=75?'#059669':rate>=40?'#d97706':'#dc2626'}">${total?rate+'%':'—'}</div></div>
    </div>
    ${sportSections}
    <div class="foot">Black Stars CRM · Y = present · N = absent · · = not marked</div>
    <script>window.onload=()=>{window.print();}<\/script>
  </body></html>`);
  win.document.close();
};

// Attendance sheet covering the member's LAST SUBSCRIPTION (start → expiry).
// Spans every calendar month the period touches (so a 30-day cycle that crosses
// a month boundary prints BOTH months). One PDF, one section per month per sport.
window._attPdfSubscription = function(memberId) {
  const m = state.members.find(x => x.id === memberId);
  if (!m) { toast('Member not found', 'error'); return; }

  // Subscription window: last renewal/start → expiry. Fall back gracefully.
  const startISO = m.startDate || m.firstRegistration || null;
  const endISO = m.expiryDate || null;
  // Build the list of YYYY-MM the window touches (cap at a sane 6 to avoid runaway).
  let months = [];
  if (startISO && endISO) {
    let cur = startISO.slice(0, 7);
    const last = endISO.slice(0, 7);
    let guard = 0;
    while (guard++ < 6) {
      months.push(cur);
      if (cur === last) break;
      // advance one month
      let [yy, mm] = cur.split('-').map(Number);
      mm += 1; if (mm > 12) { mm = 1; yy += 1; }
      cur = `${yy}-${String(mm).padStart(2, '0')}`;
    }
  }
  if (!months.length) months = [latestDataMonth() || (window._attCurrentMonth)].filter(Boolean);
  if (!months.length) { toast('No subscription dates to build a sheet from', 'error'); return; }

  // Sports to show: the member's enrolment sports, else any sports with marks.
  const enrolSports = (m.enrollments || []).map(e => e.sport).filter(Boolean);
  const attSports = new Set();
  for (const mo of months) for (const sp of Object.keys(m.dailyAttendance?.[mo] || {})) attSports.add(sp);
  let sportsShown = enrolSports.length ? [...new Set(enrolSports)] : [...attSports];
  if (!sportsShown.length) sportsShown.push(m.sport || '—');

  let grandY = 0, grandN = 0;
  const monthSections = months.map(mo => {
    const days = daysInMonth(mo);
    const sportsMap = m.dailyAttendance?.[mo] || {};
    const perSport = sportsShown.map(sp => {
      const dd = sportsMap[sp] || {};
      let y = 0, n = 0; const marked = [];
      for (let d = 1; d <= days; d++) {
        const v = dd[String(d)];
        if (v === 'Y') { y++; marked.push({ d, v }); }
        else if (v === 'N') { n++; marked.push({ d, v }); }
      }
      grandY += y; grandN += n;
      const sTot = y + n;
      const sRate = sTot ? Math.round(y / sTot * 100) : 0;
      const enr = (m.enrollments || []).find(e => e.sport === sp);
      const cid = enr?.coachId ?? m.coachId;
      if (!marked.length) return '';   // skip months with nothing marked for this sport
      const dayRows = marked.map(c => {
        const dateStr = fmtDate(`${mo}-${String(c.d).padStart(2, '0')}`);
        const present = c.v === 'Y';
        return `<tr>
          <td style="border:1px solid #e5e5ea;padding:7px 10px;font-size:12px">${dateStr}</td>
          <td style="border:1px solid #e5e5ea;padding:7px 10px;text-align:center;font-weight:700;font-size:12px;background:${present ? '#d1fae5' : '#fee2e2'};color:${present ? '#065f46' : '#991b1b'}">${present ? 'Present' : 'Absent'}</td>
        </tr>`;
      }).join('');
      return `
        <div style="margin-bottom:14px">
          <div style="font-size:13px;font-weight:700;color:#f26060;margin-bottom:6px">${escapeHtml(sp)}${sp === SUMMER_CAMP ? '' : ' · Coach ' + escapeHtml(coachName(cid))} · <span style="color:#666;font-weight:500">${y}/${sTot} · ${sTot ? sRate + '%' : '—'}</span></div>
          <table style="width:100%;border-collapse:collapse"><thead><tr>
            <th style="border:1px solid #e5e5ea;padding:6px 10px;font-size:10px;color:#777;background:#fafafa;text-align:left;text-transform:uppercase;letter-spacing:.5px">Date</th>
            <th style="border:1px solid #e5e5ea;padding:6px 10px;font-size:10px;color:#777;background:#fafafa;text-align:center;text-transform:uppercase;letter-spacing:.5px">Attendance</th>
          </tr></thead>
          <tbody>${dayRows}</tbody></table>
        </div>`;
    }).join('');
    if (!perSport.trim()) return '';   // skip a month with no marks at all
    return `<div style="margin-bottom:22px"><div style="font-size:14px;font-weight:800;border-bottom:2px solid #eee;padding-bottom:4px;margin-bottom:10px">${fmtMonth(mo)}</div>${perSport}</div>`;
  }).join('');

  const total = grandY + grandN;
  const rate = total ? Math.round(grandY / total * 100) : 0;
  const periodLabel = (startISO && endISO) ? `${fmtDate(startISO)} → ${fmtDate(endISO)}` : fmtMonth(months[0]);
  const fileName = `${m.name.replace(/[^a-z0-9]+/gi, '_')}_attendance_subscription`;

  const win = window.open('', '_blank');
  if (!win) { toast('Pop-up blocked — allow pop-ups to export', 'error'); return; }
  win.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${fileName}</title>
  <style>
    *{margin:0;padding:0;box-sizing:border-box}
    @page{size:A4 portrait;margin:12mm}
    body{font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#1a1a1a;padding:24px;max-width:600px;margin:0 auto}
    .head{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #f26060;padding-bottom:14px;margin-bottom:18px}
    .brand{font-size:22px;font-weight:800}.brand span{color:#f26060}
    .sub{color:#777;font-size:12px;margin-top:2px}
    h1{font-size:17px;margin-bottom:2px}
    .meta{font-size:12px;color:#555;margin-bottom:16px}
    .meta b{color:#1a1a1a}
    table{border-collapse:collapse;margin-bottom:10px}
    .summary{display:flex;gap:10px;margin-bottom:18px;flex-wrap:wrap}
    .kpi{flex:1;min-width:110px;border:1px solid #e5e5ea;border-radius:8px;padding:10px 14px}
    .kpi .l{font-size:10px;text-transform:uppercase;color:#999;letter-spacing:.5px}
    .kpi .v{font-size:22px;font-weight:700;margin-top:2px}
    .foot{margin-top:24px;font-size:10px;color:#aaa;text-align:center;border-top:1px solid #eee;padding-top:10px}
  </style></head><body>
    <div class="head">
      <div><div class="brand">Black <span>Stars</span> Sports Club</div><div class="sub">Waab, Doha · Attendance Sheet — Last Subscription</div></div>
      <div style="text-align:right;font-size:11px;color:#777">Generated<br><b>${fmtDate(TODAY)}</b></div>
    </div>
    <h1>${escapeHtml(m.name)}${m.nameArabic ? ` <span style="color:#999;font-weight:400">(${escapeHtml(m.nameArabic)})</span>` : ''}</h1>
    <div class="meta">Subscription: <b>${periodLabel}</b> · ${months.length} month${months.length === 1 ? '' : 's'} · Status: <b>${memberStatus(m)}</b></div>
    <div class="summary">
      <div class="kpi"><div class="l">Present (Y)</div><div class="v" style="color:#059669">${grandY}</div></div>
      <div class="kpi"><div class="l">Absent (N)</div><div class="v" style="color:#dc2626">${grandN}</div></div>
      <div class="kpi"><div class="l">Days marked</div><div class="v">${total}</div></div>
      <div class="kpi"><div class="l">Overall rate</div><div class="v" style="color:${rate >= 75 ? '#059669' : rate >= 40 ? '#d97706' : '#dc2626'}">${total ? rate + '%' : '—'}</div></div>
    </div>
    ${monthSections}
    <div class="foot">Black Stars CRM · Y = present · N = absent · · = not marked</div>
    <script>window.onload=()=>{window.print();}<\/script>
  </body></html>`);
  win.document.close();
};


PAGES.history = (main) => {
  let state2 = { selectedId: null, search: '' };

  if (window._historyLastSelected) state2.selectedId = window._historyLastSelected;
  else if (state.members.length) state2.selectedId = state.members[0].id;

  function memberFilter(m) {
    if (!state2.search) return true;
    const q = state2.search.toLowerCase();
    return searchMatchesFields(q, [m.name, m.nameArabic, m.phone, m.phone2, m.qid, m.email], [m.phone, m.phone2]);
  }

  // ─ Build subscription history rows (chronological) ─
  function buildSubs(m) {
    const subs = (m.subscriptions || []).map(s => ({ ...s }));
    // Add legacy standalone renewals (where the renewal entry doesn't have a
    // matching subscription row by _rid). New renewals are pushed to both
    // subscriptions[] and renewals[] at save time — we dedupe here so they
    // don't show twice.
    const subRids = new Set(subs.map(s => s._rid).filter(Boolean));
    for (const r of (m.renewals || [])) {
      if (r._rid && subRids.has(r._rid)) continue;
      subs.push({ ...r, manual: true });
    }
    // Sort by start date desc (most recent first)
    return subs.sort((a, b) => (b.start || '').localeCompare(a.start || ''));
  }

  function renderTimeline() {
    const m = state.members.find(x => x.id === state2.selectedId);
    const right = $('#hist-right');
    if (!m) {
      right.innerHTML = `<div class="empty" style="padding:60px"><div class="empty-icon">📜</div>Select a member to view their history</div>`;
      return;
    }
    window._historyLastSelected = m.id;

    const subs = buildSubs(m);

    // Aggregate stats
    const totalSubs = subs.length;
    const totalPaid = subs.reduce((s, x) => s + (x.amountPaid || 0), 0);
    const activeSubs = subs.filter(s => (s.status || '').toLowerCase() === 'active').length;
    const expiredSubs = subs.filter(s => (s.status || '').toLowerCase() === 'expired').length;

    right.innerHTML = `
      <div class="card">
        <div style="display:flex;gap:16px;align-items:center;margin-bottom:16px">
          <div class="avatar" style="width:64px;height:64px;font-size:22px;background:linear-gradient(135deg,var(--blue),var(--purple))">${initials(m.name)}</div>
          <div style="flex:1">
            <div style="font-size:20px;font-weight:700">${escapeHtml(m.name)}${m.nameArabic ? ` · <span style="color:var(--text-dim);font-weight:500" dir="rtl">${escapeHtml(m.nameArabic)}</span>` : ''}</div>
            <div class="text-dim" style="font-size:13px">${escapeHtml(m.sport)} · ${escapeHtml(coachName(m.coachId))}${m.level ? ' · '+escapeHtml(m.level) : ''}</div>
            <div class="mt-1">
              <span class="badge ${memberStatus(m).toLowerCase()}">${memberStatus(m)}</span>
              ${isRealPhone(m.phone) ? `<span class="text-mute" style="margin-left:8px;font-size:11px">📱 ${phoneCell(m.phone, { stop: false })}</span>` : ''}
              ${m.qid ? `<span class="text-mute" style="margin-left:8px;font-size:11px">🆔 ${escapeHtml(m.qid)}</span>` : ''}
            </div>
          </div>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button class="btn ghost sm" onclick="editMember(${m.id})" title="Edit member">✏️ Edit</button>
            <button class="btn ghost sm" onclick="duplicateMember(${m.id})" title="Create a new member copying this one's contact info (for siblings)">⧉ Duplicate</button>
            ${canManageFreeze() ? `<button class="btn ghost sm" onclick="freezeMember(${m.id})" title="Freeze membership (pause and shift expiry)">❄️ Freeze</button>` : ''}
            <button class="btn ghost sm" onclick="switchSport(${m.id})" title="Switch this member to a different sport/coach">🔄 Switch Sport</button>
            <button class="btn ghost sm" onclick="printIdCard(${m.id})" title="Print membership ID card">🪪 ID Card</button>
            <button class="btn primary sm" onclick="addRenewal(${m.id})" title="Record a new subscription / renewal">+ Add Renewal</button>
          </div>
        </div>
        ${m.updatedAt ? `<div class="text-mute" style="font-size:11px;margin:-6px 0 12px">🕓 ${t('Last updated by', 'آخر تعديل بواسطة')} <b>${escapeHtml(m.updatedByName || m.updatedBy)}</b> · ${fmtDateTime(m.updatedAt)}</div>` : ''}

        ${(() => {
          const isFrozen = m.currentFreezeUntil && TODAY <= m.currentFreezeUntil;
          if (!isFrozen) return '';
          const remaining = Math.max(0, Math.ceil((new Date(m.currentFreezeUntil) - new Date(TODAY)) / 86400000));
          const f = (m.freezes || []).slice(-1)[0];
          return `<div style="background:rgba(96,165,250,.12);border:1px solid rgba(96,165,250,.4);border-radius:8px;padding:10px 14px;margin-bottom:14px;display:flex;align-items:center;gap:12px">
            <div style="font-size:24px">❄️</div>
            <div style="flex:1">
              <div style="font-weight:700;color:var(--blue)">Frozen until ${fmtDate(m.currentFreezeUntil)}</div>
              <div class="text-mute" style="font-size:12px">${remaining} day${remaining === 1 ? '' : 's'} remaining${f && f.reason ? ` · "${escapeHtml(f.reason)}"` : ''}</div>
            </div>
            ${canManageFreeze() ? `<button class="btn ghost sm" onclick="unfreezeMember(${m.id})" title="End the freeze early">⏯ Unfreeze</button>` : ''}
          </div>`;
        })()}

        <div class="kpi-grid" style="grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:20px">
          <div class="kpi" style="padding:10px 12px"><div class="kpi-label" style="font-size:10px">Total Subscriptions</div><div class="kpi-value" style="font-size:18px">${totalSubs}</div></div>
          <div class="kpi green" style="padding:10px 12px"><div class="kpi-label" style="font-size:10px">Active</div><div class="kpi-value" style="font-size:18px">${activeSubs}</div></div>
          <div class="kpi orange" style="padding:10px 12px"><div class="kpi-label" style="font-size:10px">Expired</div><div class="kpi-value" style="font-size:18px">${expiredSubs}</div></div>
          <div class="kpi blue" style="padding:10px 12px"><div class="kpi-label" style="font-size:10px">Total Paid</div><div class="kpi-value" style="font-size:18px">${fmt(totalPaid)}</div></div>
        </div>

        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
          <h3 style="font-size:14px;font-weight:600">Subscription &amp; Renewal History</h3>
          <button class="btn ghost sm" onclick="exportMemberHistoryCSV(${m.id})" style="font-size:11px">📥 Export CSV</button>
        </div>

        <div class="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Activity</th>
                <th>Coach</th>
                <th>Start Date</th>
                <th>End Date</th>
                <th class="text-right">Amount Paid</th>
                <th>Status</th>
                <th class="text-right">Actions</th>
              </tr>
            </thead>
            <tbody>
              ${subs.length ? subs.map((s, i) => {
                const statusBadge = s.status
                  ? `<span class="badge ${(s.status||'').toLowerCase() === 'expired' ? 'expired' : 'active'}">${s.status}</span>`
                  : '<span class="text-mute">—</span>';
                const coachName = s.coach || (s.coachId ? state.coaches.find(c => c.id === s.coachId)?.name : '—');
                return `
                  <tr>
                    <td>${escapeHtml(s.activity || '—')}${s.manual ? ' <span class="badge" style="font-size:9px;padding:1px 5px">Manual</span>' : ''}</td>
                    <td>${escapeHtml(coachName || '—')}</td>
                    <td>${s.start ? fmtDate(s.start) : '—'}</td>
                    <td>${s.end ? fmtDate(s.end) : '—'}</td>
                    <td class="text-right num font-bold">${s.amountPaid ? fmt(s.amountPaid) : '—'}</td>
                    <td>${statusBadge}</td>
                    <td class="text-right">
                      ${s.manual ? `<button class="btn ghost sm" onclick="deleteRenewal(${m.id}, '${s._rid}')" title="Delete">🗑</button>` : '<span class="text-mute" style="font-size:10px">from sheet</span>'}
                    </td>
                  </tr>
                `;
              }).join('') : `<tr><td colspan="7" class="empty">No subscription history yet. Click "+ Add Renewal" to record one.</td></tr>`}
            </tbody>
          </table>
        </div>

        ${(m.freezes && m.freezes.length) ? `
        <div style="display:flex;align-items:center;justify-content:space-between;margin:18px 0 10px">
          <h3 style="font-size:14px;font-weight:600">❄️ Freeze History</h3>
        </div>
        <div class="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Start</th>
                <th>End</th>
                <th class="text-right">Days</th>
                <th>Reason</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              ${m.freezes.slice().reverse().map(f => {
                const active = m.currentFreezeUntil === f.end && TODAY <= f.end;
                return `<tr>
                  <td>${fmtDate(f.start)}</td>
                  <td>${fmtDate(f.end)}</td>
                  <td class="text-right num font-bold">${f.days}</td>
                  <td class="text-mute" style="font-size:12px">${escapeHtml(f.reason || '—')}</td>
                  <td>${active ? '<span class="badge" style="background:rgba(96,165,250,.18);color:var(--blue)">Active</span>' : '<span class="badge" style="background:var(--surface-2);color:var(--text-mute)">Past</span>'}</td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
        ` : ''}

        ${(m.sportSwitches && m.sportSwitches.length) ? `
        <div style="display:flex;align-items:center;justify-content:space-between;margin:18px 0 10px">
          <h3 style="font-size:14px;font-weight:600">🔄 Sport Switch History</h3>
        </div>
        <div class="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Date</th>
                <th>From</th>
                <th>To</th>
                <th>Commission split</th>
                <th>Reason</th>
              </tr>
            </thead>
            <tbody>
              ${m.sportSwitches.slice().reverse().map(sw => {
                const sn = sw.snapshot;
                let splitCell = '<span class="text-mute" style="font-size:11px">—</span>';
                if (sn) {
                  if (sn.attendedByOld === 0) {
                    splitCell = `<span class="badge" style="background:rgba(245,158,11,.15);color:var(--accent-2);font-size:10px">No attendance · no commission</span>`;
                  } else {
                    splitCell = `
                      <div style="font-size:11px">
                        <span style="color:var(--blue)">${fmt(sn.aShare)}</span>
                        <span class="text-mute"> / </span>
                        <span style="color:var(--green)">${fmt(sn.bShare)}</span>
                      </div>
                      <div class="text-mute" style="font-size:10px">${sn.attendedByOld}/${sn.totalClasses} classes attended</div>
                    `;
                  }
                }
                return `
                <tr>
                  <td>${fmtDate(sw.date)}</td>
                  <td><span class="badge">${escapeHtml(sw.fromSport)}</span> <span class="text-mute" style="font-size:11px">· ${escapeHtml(sw.fromCoach || coachName(sw.fromCoachId))}</span></td>
                  <td><span class="badge blue">${escapeHtml(sw.toSport)}</span> <span class="text-mute" style="font-size:11px">· ${escapeHtml(sw.toCoach || coachName(sw.toCoachId))}</span></td>
                  <td>${splitCell}</td>
                  <td class="text-mute" style="font-size:12px">${escapeHtml(sw.reason || '—')}</td>
                </tr>
              `;}).join('')}
            </tbody>
          </table>
        </div>
        ` : ''}

        ${(m.withdrawals && m.withdrawals.length) ? `
        <div style="display:flex;align-items:center;justify-content:space-between;margin:18px 0 10px">
          <h3 style="font-size:14px;font-weight:600">↩ Withdrawal History</h3>
          <span class="text-mute" style="font-size:11px">${m.withdrawals.length} withdrawal${m.withdrawals.length === 1 ? '' : 's'} · ${fmt(m.withdrawals.reduce((s,w) => s + (w.refundAmount || 0), 0))} QAR refunded</span>
        </div>
        <div class="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Date</th>
                <th>Sport</th>
                <th>Coach</th>
                <th class="text-right">Paid</th>
                <th class="text-right">Attended</th>
                <th class="text-right">Used</th>
                <th class="text-right">Refunded</th>
                <th>Reason</th>
              </tr>
            </thead>
            <tbody>
              ${m.withdrawals.slice().reverse().map(w => `
                <tr>
                  <td>${fmtDate(w.date)}</td>
                  <td><span class="badge">${escapeHtml(w.sport)}</span></td>
                  <td class="text-mute" style="font-size:12px">${w.sport === SUMMER_CAMP ? '<span style="font-style:italic">no coach</span>' : escapeHtml(w.coachName || coachName(w.coachId) || '—')}</td>
                  <td class="text-right num">${fmt(w.originalPrice)}</td>
                  <td class="text-right num">${w.attendedClasses}/${w.totalClasses}</td>
                  <td class="text-right num" style="color:var(--green)">${fmt(w.usedAmount)}</td>
                  <td class="text-right num" style="color:var(--accent-2);font-weight:700">${fmt(w.refundAmount)}</td>
                  <td class="text-mute" style="font-size:12px">${escapeHtml(w.reason || '—')}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>
        </div>
        ` : ''}

        ${(() => {
          // Other transactions: rentals (matched by phone/QID) + product sales (matched by customerId)
          const memberSales = (state.sales || []).filter(s => s.customerId === m.id);
          // Rentals don't carry customerId (walk-in shape), but phone/QID may match
          const memberRentals = (state.rentals || []).filter(r => {
            if (m.phone && r.customerPhone === m.phone) return true;
            if (m.qid && r.customerQid && r.customerQid === m.qid) return true;
            return false;
          });
          if (!memberSales.length && !memberRentals.length) return '';
          const salesTotal = memberSales.reduce((a, s) => a + (s.total || 0), 0);
          const rentTotal = memberRentals.reduce((a, r) => a + (r.amount || 0), 0);
          return `
          <div style="display:flex;align-items:center;justify-content:space-between;margin:18px 0 10px">
            <h3 style="font-size:14px;font-weight:600">🧾 Other transactions</h3>
            <span class="text-mute" style="font-size:11px">${memberSales.length} sale${memberSales.length===1?'':'s'} · ${memberRentals.length} rental${memberRentals.length===1?'':'s'} · ${fmt(salesTotal + rentTotal)} QAR</span>
          </div>
          <div class="table-wrap">
            <table>
              <thead>
                <tr><th>Date</th><th>Type</th><th>Details</th><th class="text-right">Amount</th><th>Method</th><th></th></tr>
              </thead>
              <tbody>
                ${[...memberSales.map(s => ({ kind: 'sale', date: s.date, items: s.items, amount: s.total, method: s.method, invId: s.invoiceId })),
                   ...memberRentals.map(r => ({ kind: 'rental', date: r.date, facility: r.facility, hours: r.hours, amount: r.amount, method: r.method, invId: r.invoiceId }))]
                  .sort((a,b) => (b.date||'').localeCompare(a.date||''))
                  .map(t => {
                    if (t.kind === 'sale') {
                      const desc = (t.items || []).map(it => `${it.qty}× ${escapeHtml(it.name)}`).join(', ');
                      return `<tr>
                        <td class="text-dim" style="white-space:nowrap;font-size:11px">${fmtDate(t.date)}</td>
                        <td><span class="badge purple">🛒 Sale</span></td>
                        <td class="text-mute" style="font-size:12px;max-width:240px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${desc}</td>
                        <td class="text-right num font-bold">${fmt(t.amount || 0)}</td>
                        <td><span class="badge ${t.method === 'card' ? 'blue' : ''}">${t.method || 'cash'}</span></td>
                        <td class="text-right">${t.invId ? `<button class="btn ghost sm" onclick="closeModal();printInvoicePDF(${t.invId})">📄</button>` : ''}</td>
                      </tr>`;
                    }
                    const icon = t.facility === 'Football Court' ? '⚽' : t.facility === 'Boxing Room' ? '🥊' : '🏊';
                    return `<tr>
                      <td class="text-dim" style="white-space:nowrap;font-size:11px">${fmtDate(t.date)}</td>
                      <td><span class="badge pending">🏟 Rental</span></td>
                      <td style="font-size:12px">${icon} ${escapeHtml(t.facility)} · ${t.hours}h</td>
                      <td class="text-right num font-bold">${fmt(t.amount || 0)}</td>
                      <td><span class="badge ${t.method === 'card' ? 'blue' : ''}">${t.method || 'cash'}</span></td>
                      <td class="text-right">${t.invId ? `<button class="btn ghost sm" onclick="closeModal();printInvoicePDF(${t.invId})">📄</button>` : ''}</td>
                    </tr>`;
                  }).join('')}
              </tbody>
            </table>
          </div>
          `;
        })()}
      </div>
    `;
  }

  function renderMembers() {
    const filtered = state.members.filter(memberFilter);
    $('#hist-list').innerHTML = filtered.length ? filtered.map(m => {
      const subCount = (m.subscriptions || []).length + (m.renewals || []).length;
      const isSel = m.id === state2.selectedId;
      return `
        <div class="hist-mem-row" data-id="${m.id}" style="display:flex;align-items:center;gap:10px;padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--border);${isSel ? 'background:rgba(242,96,96,.12);border-left:3px solid var(--accent);padding-left:9px' : ''}">
          <div class="avatar" style="width:30px;height:30px;font-size:10px;background:linear-gradient(135deg,var(--blue),var(--purple));flex-shrink:0">${initials(m.name)}</div>
          <div style="flex:1;min-width:0">
            <div style="font-weight:600;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escapeHtml(m.name)}</div>
            <div class="text-mute" style="font-size:10px">${escapeHtml(m.sport)} · ${escapeHtml(coachName(m.coachId))}</div>
          </div>
          <div style="display:flex;flex-direction:column;align-items:flex-end;gap:3px">
            <span class="badge ${memberStatus(m).toLowerCase()}" style="font-size:9px;padding:2px 5px">${memberStatus(m)}</span>
            ${subCount ? `<span class="text-mute" style="font-size:10px">${subCount} sub${subCount===1?'':'s'}</span>` : ''}
          </div>
        </div>
      `;
    }).join('') : `<div class="empty" style="padding:20px">No members match</div>`;

    $('#hist-mem-count').textContent = `${filtered.length} of ${state.members.length}`;

    $$('.hist-mem-row[data-id]').forEach(row => {
      row.addEventListener('click', () => {
        state2.selectedId = parseInt(row.dataset.id);
        renderMembers();
        renderTimeline();
      });
    });
  }

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>Member History</h1>
        <div class="subtitle">Subscription &amp; renewal records · activity · amount paid · start / end · coach</div>
      </div>
    </div>

    <div class="card" style="display:grid;grid-template-columns:300px 1fr;gap:0;padding:0;overflow:hidden">
      <div style="border-right:1px solid var(--border);display:flex;flex-direction:column;max-height:80vh">
        <div style="padding:12px;border-bottom:1px solid var(--border);background:var(--surface-2)">
          <div class="search" style="margin-bottom:6px"><input id="hist-search" type="text" placeholder="${t('Search name, phone, QID...', 'ابحث بالاسم أو الهاتف أو الهوية...')}" /></div>
          <div class="text-mute" style="font-size:11px"><span id="hist-mem-count"></span></div>
        </div>
        <div id="hist-list" style="flex:1;overflow-y:auto;min-height:0"></div>
      </div>
      <div id="hist-right" style="padding:16px;overflow-y:auto;max-height:80vh"></div>
    </div>
  `;

  $('#hist-search').addEventListener('input', e => { state2.search = e.target.value; renderMembers(); });
  attachRecentSearch('hist-search', 'history');

  renderMembers();
  renderTimeline();
};

// ─── Switch a member's sport mid-cycle ────────────────────────────
// THE RULE (locked in v95):
//   1. Read the OLD enrollment's CURRENT attended count (Y marks for old sport,
//      across all months, on or before switch date).
//   2. attended / totalClasses × price = OLD coach's locked share (A_share)
//   3. price − A_share = NEW coach's share (B_share)
//   4. If attended == 0 → A_share = 0 AND B_share = 0 (nobody earns)
//   5. The original invoice line gets REPLACED:
//        - The old line is rewritten with price = A_share
//        - A new line is appended to the SWITCH MONTH's invoice (or a new
//          adjustment invoice) with price = B_share, coach = B, sport = NEW
//      That way Coach A's commission shows on the original invoice month,
//      and Coach B's commission shows on the switch month going forward.
//   6. A switchSwitches[] record stores the snapshot so admin can audit later.
//
// History preservation: the OLD sport attendance and subscription rows STAY
// in place. The enrollment row is updated to the new sport+coach. Future
// commission ONLY comes from the new enrollment.
// ─── Withdraw / Refund flow ─────────────────────────────────────────
// When a paying member wants to leave a sport mid-cycle, we calculate the
// refund based on classes attended vs total purchased, then create a
// "withdraw-credit" invoice that:
//   1. Reduces revenue by the refund amount (negative invoice amount)
//   2. Reduces coach commission base by the unused portion (negative line item)
//   3. Removes the enrollment from the member
//
// The original payment invoice stays UNTOUCHED — audit trail. The withdraw
// invoice nets the difference, and shows up in the withdraw month's payroll.
//
// Math (matches Switch Sport reconciliation, simplified to one-side):
//   attendedRatio = attendedClasses / totalClasses
//   usedAmount    = price × attendedRatio    (member's value received)
//   refundAmount  = price − usedAmount       (what we return)
//   commissionAdj = −refundAmount            (coach loses commission on unused portion)
window.withdrawSport = function(memberId, sport) {
  const m = state.members.find(x => x.id === memberId);
  if (!m) { toast('Member not found', 'error'); return; }

  // Find the enrollment row
  const enrollment = (m.enrollments || []).find(e => e.sport === sport);
  if (!enrollment) { toast(`No enrollment for ${sport}`, 'error'); return; }

  const totalClasses = parseInt(enrollment.classes) || 0;
  const price = parseFloat(enrollment.price) || 0;
  if (price <= 0) {
    toast('Cannot withdraw a free enrollment — just delete the row instead', 'error');
    return;
  }

  // Count attended classes for this sport (Y marks in dailyAttendance)
  let attended = 0;
  const ymKeys = Object.keys(m.dailyAttendance || {});
  for (const ym of ymKeys) {
    const sportData = m.dailyAttendance[ym]?.[sport] || {};
    for (const mark of Object.values(sportData)) {
      if (mark === 'Y') attended++;
    }
  }

  const isCamp = sport === SUMMER_CAMP;
  // This sport's start date (from its latest subscription, else member start).
  let sportStart = null;
  for (const s of (m.subscriptions || [])) if (s.activity === sport && s.start) sportStart = s.start;
  sportStart = sportStart || enrollment.start || m.startDate || null;

  const graceDefault = (state.settings && state.settings.refundGraceDays != null) ? state.settings.refundGraceDays : 7;
  const feeDefault = (state.settings && state.settings.refundFeePct != null) ? state.settings.refundFeePct : 20;
  const calc = computeWithdrawRefund({ price, totalClasses, attended, startDate: sportStart, refundDate: TODAY, graceDays: graceDefault, feePct: feeDefault });
  const usedAmount = calc.used;
  const refundAmount = calc.refund;
  const graceLine = (d, withinGrace) => d == null
    ? '<span class="text-mute">start date unknown — treated as within grace</span>'
    : `${d} day${d === 1 ? '' : 's'} since start · ${withinGrace ? '<b style="color:var(--green)">within grace</b>' : '<b style="color:var(--accent-2)">after grace</b>'}`;

  // Live recompute when grace days / fee % / refund date change.
  window._recalcWithdraw = function() {
    const g = document.getElementById('wd-grace');
    const f = document.getElementById('wd-fee');
    const dt = document.getElementById('wd-date');
    const c = computeWithdrawRefund({ price, totalClasses, attended, startDate: sportStart, refundDate: (dt && dt.value) || TODAY, graceDays: g ? g.value : graceDefault, feePct: f ? f.value : feeDefault });
    const set = (id, html) => { const el = document.getElementById(id); if (el) el.innerHTML = html; };
    set('wd-since', graceLine(c.daysSinceStart, c.withinGrace));
    set('wd-used', `${fmt(c.used)} QAR`);
    set('wd-unused', `${fmt(c.unused)} QAR`);
    set('wd-fee-line', c.withinGrace ? 'No admin fee (within grace period)' : `Admin fee (${c.feePct}% of unused): −${fmt(c.fee)} QAR`);
    const rf = document.getElementById('wd-refund');
    if (rf && !rf.dataset.touched) rf.value = c.refund;
  };

  // Show the withdrawal confirmation modal
  showModal({
    title: `↩ Withdraw ${m.name} from ${sport}`,
    body: `
      <div style="background:rgba(245,158,11,.08);border:1px solid rgba(245,158,11,.25);border-radius:8px;padding:12px;margin-bottom:14px;font-size:12px">
        <div style="font-weight:700;margin-bottom:6px;color:var(--accent-2)">⚠ This will:</div>
        <ul style="margin:0;padding-left:18px;line-height:1.7">
          <li>Issue the refund below to the member</li>
          <li>Remove ${sport} from their enrollments${(m.enrollments || []).length <= 1 ? ' and mark the member <b>Withdrawn</b>' : ''}</li>
          ${!isCamp && enrollment.coachId
            ? `<li>Deduct the refunded amount from <b>${escapeHtml(coachName(enrollment.coachId))}</b>'s commission base in ${fmtMonth(currentMonth())}</li>`
            : isCamp
              ? `<li>No coach commission impact (Summer Camp revenue belongs to club)</li>`
              : `<li>No coach assigned — no commission impact</li>`}
          <li>The original payment invoice stays untouched (audit trail)</li>
        </ul>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
        <div class="field" style="margin:0">
          <label>Original payment</label>
          <div style="padding:10px;background:var(--surface-2);border-radius:8px;font-weight:700">${fmt(price)} QAR</div>
        </div>
        <div class="field" style="margin:0">
          <label>Classes attended</label>
          <div style="padding:10px;background:var(--surface-2);border-radius:8px">
            <b>${attended} / ${totalClasses}</b>
            <span class="text-mute" style="font-size:11px"> · ${calc.total > 0 ? Math.round(calc.attended / calc.total * 100) : 0}% used</span>
          </div>
        </div>
      </div>

      <div style="background:var(--surface-2);border-radius:8px;padding:12px;margin-bottom:14px;font-size:12px;line-height:1.8">
        <div>📅 <span id="wd-since">${graceLine(calc.daysSinceStart, calc.withinGrace)}</span></div>
        <div>Used (kept by club): <b id="wd-used">${fmt(calc.used)} QAR</b></div>
        <div>Unused (refundable): <b id="wd-unused">${fmt(calc.unused)} QAR</b></div>
        <div id="wd-fee-line" style="color:var(--text-mute)">${calc.withinGrace ? 'No admin fee (within grace period)' : `Admin fee (${calc.feePct}% of unused): −${fmt(calc.fee)} QAR`}</div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
        <div class="field" style="margin:0">
          <label>Grace period (days)</label>
          <input id="wd-grace" type="number" min="0" step="1" value="${graceDefault}" oninput="window._recalcWithdraw()" />
        </div>
        <div class="field" style="margin:0">
          <label>Admin fee after grace (%)</label>
          <input id="wd-fee" type="number" min="0" max="100" step="1" value="${feeDefault}" oninput="window._recalcWithdraw()" />
        </div>
      </div>

      <div class="field">
        <label>Refund to member <span style="color:var(--accent)">*</span></label>
        <input id="wd-refund" type="number" min="0" max="${price}" step="0.01" value="${refundAmount}" oninput="this.dataset.touched=1" style="font-size:18px;font-weight:700;color:var(--accent-2)" />
        <div class="text-mute" style="font-size:10px;margin-top:3px">Auto-calculated from grace + attendance; adjust if needed</div>
      </div>

      <div class="field">
        <label>Refund date</label>
        <input id="wd-date" type="date" value="${TODAY}" oninput="window._recalcWithdraw()" />
      </div>

      <div class="field">
        <label>Refund method</label>
        <select id="wd-method">
          <option value="cash">Cash</option>
          <option value="card">Card</option><option value="fawran">Fawran</option>
          <option value="transfer">Bank transfer</option>
        </select>
      </div>

      <div class="field">
        <label>Reason (recorded in audit trail)</label>
        <input id="wd-reason" placeholder="e.g. moved to another club, schedule conflict" />
      </div>
    `,
    actions: [
      { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
      { label: '↩ Confirm Withdrawal', class: 'btn danger', onclick: () => {
        const refund = Math.max(0, parseFloat(document.getElementById('wd-refund').value) || 0);
        const refundDate = document.getElementById('wd-date').value || TODAY;
        const method = document.getElementById('wd-method').value || 'cash';
        const reason = document.getElementById('wd-reason').value.trim() || null;

        if (refund > price) { toast(`Refund cannot exceed paid amount (${fmt(price)} QAR)`, 'error'); return; }

        const refundMonth = refundDate.slice(0, 7);
        const withdrawRef = `WD-${Date.now().toString().slice(-6)}`;

        // Create the withdraw-credit invoice. NEGATIVE amount + negative line
        // item so coach commission base goes down by `refund` in this month.
        // Summer Camp has no commission anyway (Summer Camp filter handles it).
        const lineItems = [{
          sport,
          coach: enrollment.coachId ? coachName(enrollment.coachId) : null,
          coachId: enrollment.coachId || null,
          classes: -(totalClasses - attended),  // negative visual cue
          price: -refund,                       // negative price → negative commission base
        }];
        state.invoices.push({
          id: nextId(state.invoices),
          date: refundDate,
          description: `${m.name} — withdrawal refund: ${sport}` + (reason ? ` (${reason})` : ''),
          amount: -refund,           // negative → reduces revenue
          method,
          month: refundMonth,
          ref: withdrawRef,
          sport,
          coach: enrollment.coachId ? coachName(enrollment.coachId) : null,
          coachId: enrollment.coachId || null,
          customerId: m.id,
          customerName: m.name,
          category: 'Membership',
          activityType: 'withdraw-credit',
          withdrawCredit: true,
          reason,
          lineItems,
        });

        // Record on member: withdrawal audit + remove enrollment
        if (!Array.isArray(m.withdrawals)) m.withdrawals = [];
        m.withdrawals.push({
          id: 'wd_' + Date.now(),
          date: refundDate,
          sport,
          coachId: enrollment.coachId || null,
          coachName: enrollment.coachId ? coachName(enrollment.coachId) : null,
          originalPrice: price,
          totalClasses,
          attendedClasses: attended,
          usedAmount,
          refundAmount: refund,
          method,
          reason,
          invoiceRef: withdrawRef,
          createdAt: new Date().toISOString(),
        });
        // Remove from enrollments
        m.enrollments = (m.enrollments || []).filter(e => e.sport !== sport);
        // Recalculate expiry: latest end across remaining enrollments via subs
        const remainingEnds = (m.subscriptions || [])
          .filter(s => s.activity !== sport && s.end)
          .map(s => s.end);
        m.expiryDate = remainingEnds.length ? remainingEnds.sort().pop() : null;
        // No sports left → member has fully withdrawn: mark Withdrawn + clear expiry.
        if (!(m.enrollments || []).length) { m.status = 'Withdrawn'; m.expiryDate = null; }
        // If this was the legacy primary sport, switch to any remaining one
        if (m.sport === sport) {
          const nextEnr = (m.enrollments || [])[0];
          if (nextEnr) {
            m.sport = nextEnr.sport;
            m.coachId = nextEnr.coachId;
          } else {
            // Last sport withdrawn — clear the legacy primary fields so the
            // member no longer appears on the Enrolled report via the m.sport
            // fallback (this was the "ghost enrollment" bug).
            m.sport = null;
            m.coachId = null;
          }
        }

        save();
        closeModal();
        audit('sport.withdraw', `member:${m.id}`,
          `Withdrew ${m.name} from ${sport} — refunded ${fmt(refund)} QAR`,
          { memberId: m.id, sport, originalPrice: price, usedAmount, refundAmount: refund, attended, totalClasses, invoiceRef: withdrawRef });
        render();
        toast(`✓ Refund issued: ${fmt(refund)} QAR · ${sport} removed from ${m.name}`);
        setTimeout(() => viewMember(m.id), 200);
      }},
    ],
  });
};

window.switchSport = function(memberId) {
  const m = state.members.find(x => x.id === memberId);
  if (!m) return;

  // One switch per membership cycle. Count switches made on/after the current
  // cycle start (renewing resets the allowance). If they've already switched,
  // block it — a member can't keep hopping sports on a single paid membership.
  const cycleStart = m.startDate || m.firstRegistration || '0000-00-00';
  const switchesThisCycle = (m.sportSwitches || []).filter(sw => (sw.date || '') >= cycleStart);
  if (switchesThisCycle.length >= 1) {
    const last = switchesThisCycle[switchesThisCycle.length - 1];
    const what = last.distributed
      ? `${last.fromSport} → ${(last.targets || []).map(t => t.sport).join(', ')}`
      : `${last.fromSport || '—'} → ${last.toSport || '—'}`;
    showModal({
      title: `Already switched: ${escapeHtml(m.name)}`,
      body: `<div style="text-align:center;padding:20px"><div style="font-size:40px;margin-bottom:10px">🔒</div>
        <p>${escapeHtml(m.name)} has already used their <b>one sport switch</b> for this membership${last.date ? ` (on ${fmtDate(last.date)}: ${escapeHtml(what)})` : ''}.</p>
        <p class="text-mute" style="font-size:12px">Only one switch is allowed per paid membership. The allowance resets when they renew. For a different correction, use Withdraw or Edit pricing.</p></div>`,
      actions: [{ label: 'Close', primary: true, onclick: closeModal }],
    });
    return;
  }

  // Build the list of CURRENT enrollments (the ones eligible to be switched).
  // Fall back to subscriptions if enrollments[] isn't populated.
  const enrolled = (m.enrollments && m.enrollments.length) ? m.enrollments
    : (m.subscriptions || []).reduce((acc, s) => {
        if (!s.activity) return acc;
        if (!acc.find(x => x.sport === s.activity)) {
          acc.push({ sport: s.activity, coachId: s.coachId, classes: s.totalClasses || 0, price: s.amountPaid || 0 });
        }
        return acc;
      }, []);
  if (!enrolled.length) {
    toast('No active enrollments to switch from', 'error');
    return;
  }

  const sportsList = SPORTS.slice();
  const selCoaches = activeCoaches();
  const coachOpts = (cid) => selCoaches.map(co => `<option value="${co.id}" ${co.id === cid ? 'selected' : ''}>${escapeHtml(co.name)}</option>`).join('');

  // Default to the first enrollment as the "from"
  const defaultFrom = enrolled[0];
  const enrolledSports = new Set(enrolled.map(e => e.sport));
  const defaultToSport = sportsList.find(s => s !== defaultFrom.sport && !enrolledSports.has(s)) ||
                         sportsList.find(s => s !== defaultFrom.sport) || sportsList[0];

  // Helper: count attended Y marks for a sport up to (inclusive) a given date.
  // Reads m.dailyAttendance[YYYY-MM][sportName] = {day: 'Y'|'N'} structure.
  function countAttendedUpTo(sport, untilDateStr) {
    if (!m.dailyAttendance) return 0;
    let total = 0;
    for (const monthKey of Object.keys(m.dailyAttendance)) {
      const mo = m.dailyAttendance[monthKey];
      const sportMap = mo && typeof mo === 'object' ? mo[sport] : null;
      if (!sportMap) continue;
      for (const day of Object.keys(sportMap)) {
        if (sportMap[day] !== 'Y') continue;
        const dateStr = `${monthKey}-${String(day).padStart(2, '0')}`;
        if (dateStr <= untilDateStr) total++;
      }
    }
    return total;
  }

  // Switch targets — one by default; admin can distribute into several sports.
  let targets = [{ sport: defaultToSport, coachId: defaultFrom.coachId, classes: null }];

  showModal({
    title: `🔄 Switch Sport · ${m.name}`,
    body: `
      <div style="background:rgba(91,141,239,.06);border:1px solid rgba(91,141,239,.2);border-radius:8px;padding:10px;margin-bottom:14px;display:flex;gap:10px;align-items:flex-start">
        <div style="font-size:18px">💡</div>
        <div style="font-size:12px;color:var(--text-dim);line-height:1.5">
          The enrollment row is updated to the new sport/coach. Past attendance under the old sport stays as history. <b>Commission is split based on attended classes:</b> old coach gets <code>(attended / planned) × price</code>, new coach gets the remainder. If no classes were attended, nobody earns commission from this enrollment.
        </div>
      </div>

      <div class="form-row">
        <div class="field"><label>Switch FROM</label>
          <select id="sw-from">
            ${enrolled.map((e, i) => `<option value="${i}">${escapeHtml(e.sport)} · with ${escapeHtml(coachName(e.coachId))} · ${e.classes || 0} planned · ${fmt(e.price || 0)} QAR</option>`).join('')}
          </select>
        </div>
        <div class="field"><label>Switch date</label><input id="sw-date" type="date" value="${TODAY}" /></div>
      </div>

      <div style="margin:14px 0 6px;display:flex;justify-content:space-between;align-items:center">
        <span style="font-size:11px;color:var(--blue);text-transform:uppercase;letter-spacing:.6px;font-weight:600">Switch TO</span>
        <button type="button" id="sw-add-target" class="btn ghost sm" style="padding:4px 10px;font-size:11px;text-transform:none">＋ Distribute into another sport</button>
      </div>
      <div id="sw-remaining" class="text-mute" style="font-size:11px;margin-bottom:8px;display:none"></div>
      <div id="sw-targets"></div>

      <div class="field"><label>Reason (optional)</label><input id="sw-reason" placeholder="e.g. Wants to focus on Boxing" /></div>

      <div id="sw-preview" style="margin-top:10px;padding:12px;background:var(--surface-2);border-radius:6px;font-size:12px;line-height:1.6"></div>
    `,
    actions: [
      { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
      { label: '🔄 Confirm Switch', class: 'btn primary', onclick: () => {
        const fromIdx = parseInt($('#sw-from').value);
        const from = enrolled[fromIdx];
        const switchDate = $('#sw-date').value || TODAY;
        const reason = $('#sw-reason').value.trim() || null;
        if (!from) { toast('Pick the sport to switch from', 'error'); return; }

        // Read the target row(s) from the dynamic list.
        const tgs = targets.map((t, i) => ({
          sport: ($('#sw-sport-' + i) || {}).value || t.sport,
          coachId: parseInt(($('#sw-coach-' + i) || {}).value) || null,
          classes: targets.length > 1 ? (parseInt(($('#sw-classes-' + i) || {}).value) || 0) : null,
        }));

        // ════ MULTI-TARGET DISTRIBUTION (split remaining classes across sports) ════
        if (tgs.length > 1) {
          const attendedA = countAttendedUpTo(from.sport, switchDate);
          const planned = parseInt(from.classes) || 0;
          const remaining = Math.max(0, planned - attendedA);
          const creditedBase = coachBaseForSport(m, from.sport, from.coachId);
          const priceBase = creditedBase > 0 ? creditedBase : (parseFloat(from.price) || 0);
          const switchMonth = switchDate.slice(0, 7);
          for (const tg of tgs) {
            if (!tg.sport) { toast('Pick a sport for each new row', 'error'); return; }
            if (tg.sport === SUMMER_CAMP) { toast('Summer Camp can\'t be a distribution target — remove it.', 'error'); return; }
            if (!tg.coachId) { toast('Pick a coach for each new row', 'error'); return; }
          }
          if (new Set(tgs.map(t => t.sport)).size !== tgs.length) { toast('Each new sport must be different', 'error'); return; }
          if (from.sport === SUMMER_CAMP) { toast('Distribution isn\'t available when switching FROM Summer Camp.', 'error'); return; }
          const sumClasses = tgs.reduce((s, t) => s + (t.classes || 0), 0);
          if (sumClasses <= 0) { toast('Allocate the remaining classes across the new sports', 'error'); return; }
          if (sumClasses !== remaining) { toast('Allocated ' + sumClasses + ' but ' + remaining + ' classes remain — they must match.', 'error'); return; }

          const split = computeSwitchSplit(priceBase, attendedA, planned);
          const aShare = split.aShare, bShare = split.bShare;
          const resolved = tgs.map(t => ({ ...t, value: remaining > 0 ? bShare * (t.classes / remaining) : 0 }));

          // Net-zero reconciliation invoice: A's deduction + one positive per target.
          if (bShare > 0 && remaining > 0) {
            const lineItems = [{ sport: from.sport, coach: coachName(from.coachId), coachId: from.coachId, classes: -remaining, price: -bShare }];
            for (const tr of resolved) lineItems.push({ sport: tr.sport, coach: coachName(tr.coachId), coachId: tr.coachId, classes: tr.classes, price: tr.value });
            state.invoices.push({
              id: nextId(state.invoices), date: switchDate,
              description: m.name + ' — sport switch (distributed): ' + from.sport + ' → ' + tgs.map(t => t.sport).join(', '),
              amount: 0, method: 'transfer', month: switchMonth, ref: 'SW-' + Date.now().toString().slice(-6),
              sport: from.sport + ' → ' + tgs.map(t => t.sport).join('/'), coach: coachName(from.coachId) + ' → multiple', coachId: null,
              customerId: m.id, customerName: m.name, category: 'Membership', activityType: 'switch-credit', switchCredit: true, lineItems,
            });
          }
          if (!Array.isArray(m.sportSwitches)) m.sportSwitches = [];
          m.sportSwitches.push({
            id: 'sw_' + Date.now(), date: switchDate, fromSport: from.sport, fromCoachId: from.coachId, fromCoach: coachName(from.coachId),
            distributed: true, targets: resolved.map(t => ({ sport: t.sport, coachId: t.coachId, coach: coachName(t.coachId), classes: t.classes, value: t.value })),
            reason, snapshot: { attendedByOld: attendedA, totalClasses: planned, originalPrice: priceBase, aShare, bShare, switchMonth }, createdAt: new Date().toISOString(),
          });
          if (!Array.isArray(m.enrollments)) m.enrollments = [];
          if (m.enrollments.length === 0 && enrolled.length) m.enrollments = enrolled.map(e => ({ ...e }));
          const srcIdx = m.enrollments.findIndex(e => e.sport === from.sport && e.coachId === from.coachId);
          const srcEnroll = srcIdx >= 0 ? m.enrollments[srcIdx] : from;
          if (srcIdx >= 0) m.enrollments.splice(srcIdx, 1);
          for (const tr of resolved) m.enrollments.push({ sport: tr.sport, coachId: tr.coachId, classes: tr.classes, price: tr.value, start: srcEnroll.start || switchDate, validity: srcEnroll.validity || DEFAULT_VALIDITY });
          if (m.sport === from.sport && m.coachId === from.coachId) { m.sport = resolved[0].sport; m.coachId = resolved[0].coachId; }
          audit('sport.switch', 'member:' + m.id, 'Distributed ' + from.sport + ' → ' + tgs.map(t => t.sport).join(', ') + ' for ' + (m.name || m.nameArabic), { memberId: m.id });
          save(); closeModal(); render();
          toast('Switched · ' + from.sport + ' distributed into ' + tgs.length + ' sports · ' + coachName(from.coachId) + ' keeps ' + fmt(aShare));
          return;
        }

        // ════ SINGLE TARGET (unchanged behavior) ════
        const toSport = tgs[0].sport;
        const toCoachId = tgs[0].coachId;
        if (!toSport) { toast('Pick the new sport', 'error'); return; }
        if (toSport !== SUMMER_CAMP && !toCoachId) { toast('Pick the new coach', 'error'); return; }
        if (from.sport === toSport && from.coachId === toCoachId) {
          toast('No change — same sport and coach', 'error');
          return;
        }

        // ─── COMPUTE THE SPLIT ─────────────────────────────────────
        // Summer Camp has no coach commission — if EITHER side is Summer Camp,
        // skip the reconciliation entirely. Just update the enrollment record.
        const fromIsCamp = from.sport === SUMMER_CAMP;
        const toIsCamp = toSport === SUMMER_CAMP;
        const skipReconciliation = fromIsCamp || toIsCamp;

        const attendedA = countAttendedUpTo(from.sport, switchDate);
        const totalClasses = parseInt(from.classes) || 0;
        // Base the reconciliation on what coach A was ACTUALLY credited for this
        // sport (the amount shown in the revenue report), NOT the nominal
        // enrollment price — so a switch never claws back more than was paid.
        const creditedBase = coachBaseForSport(m, from.sport, from.coachId);
        const price = creditedBase > 0 ? creditedBase : (parseFloat(from.price) || 0);
        let aShare = 0, bShare = 0;
        if (skipReconciliation) {
          // No commission to split when Summer Camp is on either side
          aShare = 0; bShare = 0;
        } else {
          const split = computeSwitchSplit(price, attendedA, totalClasses);
          aShare = split.aShare; bShare = split.bShare;
        }
        const switchMonth = switchDate.slice(0, 7);

        // ─── CREATE SWITCH-CREDIT INVOICE IN THE SWITCH MONTH ──────
        // The original invoice is LEFT ALONE — Coach A keeps the historical
        // record of what was paid to him for that month. Instead, we create
        // an internal reconciliation invoice in the switch month with TWO
        // lineItems that net to zero:
        //   1. A's negative adjustment: -(price - aShare)
        //      This deducts A's overpayment from his switch-month commission
        //   2. B's positive earning: +bShare
        //      This credits B for the new coach's share
        // Net amount = 0 (it's pure accounting, not revenue).
        // SKIP entirely for Summer Camp (no commission to split).
        const deductionA = skipReconciliation ? 0 : -(price - aShare);
        if (!skipReconciliation && (bShare > 0 || deductionA < 0)) {
          const switchRef = `SW-${Date.now().toString().slice(-6)}`;
          const lineItems = [];
          if (deductionA < 0) {
            lineItems.push({
              sport: from.sport,
              coach: coachName(from.coachId),
              coachId: from.coachId,
              classes: -(totalClasses - attendedA),  // negative class count for visual cue
              price: deductionA,                     // NEGATIVE — deducts from A
            });
          }
          if (bShare > 0) {
            lineItems.push({
              sport: toSport,
              coach: coachName(toCoachId),
              coachId: toCoachId,
              classes: Math.max(0, totalClasses - attendedA),
              price: bShare,
            });
          }
          state.invoices.push({
            id: nextId(state.invoices),
            date: switchDate,
            description: `${m.name} — sport switch reconciliation: ${from.sport} → ${toSport}`,
            amount: 0,           // lineItems net to zero — no revenue impact
            method: 'transfer',  // internal accounting only
            month: switchMonth,
            ref: switchRef,
            sport: `${from.sport} → ${toSport}`,
            coach: `${coachName(from.coachId)} → ${coachName(toCoachId)}`,
            coachId: null,       // mixed coaches — read from lineItems
            customerId: m.id,
            customerName: m.name,
            category: 'Membership',
            activityType: 'switch-credit',
            switchCredit: true,  // flag for revenue report filtering
            lineItems,
          });
        }

        // ─── RECORD THE SWITCH ─────────────────────────────────────
        if (!Array.isArray(m.sportSwitches)) m.sportSwitches = [];
        m.sportSwitches.push({
          id: 'sw_' + Date.now(),
          date: switchDate,
          fromSport: from.sport,
          fromCoachId: from.coachId,
          fromCoach: coachName(from.coachId),
          toSport,
          toCoachId,
          toCoach: coachName(toCoachId),
          reason,
          // Locked snapshot — never recalculates
          snapshot: {
            attendedByOld: attendedA,
            totalClasses,
            originalPrice: price,
            aShare,
            bShare,
            switchMonth,
          },
          createdAt: new Date().toISOString(),
        });

        // ─── UPDATE THE ENROLLMENT ROW IN PLACE ────────────────────
        if (!Array.isArray(m.enrollments)) m.enrollments = [];
        if (m.enrollments.length === 0 && enrolled.length) {
          m.enrollments = enrolled.map(e => ({ ...e }));
        }
        // Summer Camp has no coach — force null when switching TO camp
        const finalToCoachId = toIsCamp ? null : toCoachId;
        const targetIdx = m.enrollments.findIndex(e => e.sport === from.sport && e.coachId === from.coachId);
        if (targetIdx >= 0) {
          m.enrollments[targetIdx].sport = toSport;
          m.enrollments[targetIdx].coachId = finalToCoachId;
          // Don't touch classes/price on the enrollment row — those reflect
          // the original deal; commission credits live in the invoice lineItems.
        } else {
          m.enrollments.push({ sport: toSport, coachId: finalToCoachId, classes: from.classes || 0, price: from.price || 0 });
        }

        // If the old sport was the member's PRIMARY sport (legacy fields), update those too
        if (m.sport === from.sport && m.coachId === from.coachId) {
          m.sport = toSport;
          m.coachId = finalToCoachId;
        }

        audit('sport.switch', `member:${m.id}`,
          `Switched ${from.sport} → ${toSport} for ${m.name || m.nameArabic}`,
          { memberId: m.id, name: m.name, fromSport: from.sport, toSport, fromCoachId: from.coachId, toCoachId });

        save();
        closeModal();
        render();
        let msg;
        if (skipReconciliation) {
          msg = `Switched · ${from.sport} → ${toSport} · no commission (Summer Camp involved)`;
        } else if (attendedA === 0) {
          msg = `Switched · no commission earned (no attendance under ${from.sport})`;
        } else {
          msg = `Switched · ${coachName(from.coachId)} keeps ${fmt(aShare)} · ${coachName(toCoachId)} gets ${fmt(bShare)}`;
        }
        toast(msg);
      }},
    ],
  });

  // ─── Target rows: render, add/remove, coach dropdowns, remaining tally ───
  function remainingClasses() {
    const from = enrolled[parseInt($('#sw-from')?.value || 0)] || defaultFrom;
    const attended = countAttendedUpTo(from.sport, $('#sw-date')?.value || TODAY);
    return Math.max(0, (parseInt(from.classes) || 0) - attended);
  }
  function rebuildRowCoaches(i) {
    const sportSel = $('#sw-sport-' + i), coachSel = $('#sw-coach-' + i);
    if (!sportSel || !coachSel) return;
    const sport = sportSel.value;
    if (sport === SUMMER_CAMP) { coachSel.innerHTML = '<option value="">— none (camp) —</option>'; targets[i].coachId = null; return; }
    const prev = targets[i].coachId || null;
    const list = coachesForSport(sport, prev);
    coachSel.innerHTML = list.length
      ? list.map(co => `<option value="${co.id}" ${co.id === prev ? 'selected' : ''}>${coachOptionLabel(co, sport)}</option>`).join('')
      : '<option value="">— no active coach teaches this sport —</option>';
    targets[i].coachId = parseInt(coachSel.value) || null;
  }
  function updateRemaining() {
    const el = $('#sw-remaining'); if (!el) return;
    if (targets.length <= 1) { el.style.display = 'none'; return; }
    const rem = remainingClasses();
    const sum = targets.reduce((s, t) => s + (parseInt(t.classes) || 0), 0);
    const ok = sum === rem;
    el.style.display = 'block';
    el.innerHTML = `Allocate <b>${rem}</b> remaining class${rem === 1 ? '' : 'es'} across the sports below · allocated <b style="color:${ok ? 'var(--green)' : 'var(--accent)'}">${sum}</b>${ok ? ' ✓' : ' — must equal ' + rem}`;
  }
  function renderTargets() {
    const wrap = $('#sw-targets'); if (!wrap) return;
    const multi = targets.length > 1;
    wrap.innerHTML = targets.map((t, i) => {
      const opts = sportsList.map(s => `<option ${s === t.sport ? 'selected' : ''}>${s}</option>`).join('');
      const classCol = multi ? `<div class="field" style="max-width:92px"><label>Classes</label><input type="number" min="0" id="sw-classes-${i}" value="${t.classes == null ? '' : t.classes}" /></div>` : '';
      const rmBtn = multi ? `<button type="button" class="btn ghost sm sw-rm" data-i="${i}" title="Remove" style="align-self:flex-end;margin-bottom:2px;padding:6px 9px">✕</button>` : '';
      return `<div class="form-row" style="align-items:flex-end;gap:8px;margin-bottom:6px">
        <div class="field"><label>${multi ? 'Sport ' + (i + 1) : 'New sport'}</label><select id="sw-sport-${i}">${opts}</select></div>
        <div class="field"><label>New coach</label><select id="sw-coach-${i}"></select></div>
        ${classCol}${rmBtn}
      </div>`;
    }).join('');
    targets.forEach((t, i) => {
      rebuildRowCoaches(i);
      const sp = $('#sw-sport-' + i);
      if (sp) sp.addEventListener('change', () => { targets[i].sport = sp.value; rebuildRowCoaches(i); updatePreview(); });
      const co = $('#sw-coach-' + i);
      if (co) co.addEventListener('change', () => { targets[i].coachId = parseInt(co.value) || null; updatePreview(); });
      const cl = $('#sw-classes-' + i);
      if (cl) cl.addEventListener('input', () => { targets[i].classes = parseInt(cl.value) || 0; updateRemaining(); updatePreview(); });
    });
    $$('.sw-rm').forEach(b => b.addEventListener('click', () => {
      targets.splice(parseInt(b.dataset.i), 1);
      if (targets.length === 1) targets[0].classes = null;
      renderTargets();
    }));
    updateRemaining(); updatePreview();
  }
  function addTarget() {
    const rem = remainingClasses();
    const from = enrolled[parseInt($('#sw-from')?.value || 0)] || defaultFrom;
    if (from.sport === SUMMER_CAMP) { toast('Distribution isn\'t available from Summer Camp', 'error'); return; }
    // Seed class counts: first row gets all remaining the first time we go multi.
    if (targets.length === 1 && targets[0].classes == null) targets[0].classes = rem;
    const taken = new Set(targets.map(t => t.sport));
    const newSport = sportsList.find(s => s !== SUMMER_CAMP && s !== from.sport && !taken.has(s)) || sportsList.find(s => !taken.has(s)) || sportsList[0];
    targets.push({ sport: newSport, coachId: null, classes: 0 });
    renderTargets();
  }

  // Live commission preview — single-target keeps the detailed view; multi shows the split.
  function updatePreview() {
    const from = enrolled[parseInt($('#sw-from')?.value || 0)];
    if (!from) return;
    const switchDate = $('#sw-date')?.value || TODAY;
    const attended = countAttendedUpTo(from.sport, switchDate);
    const totalClasses = parseInt(from.classes) || 0;
    const remaining = Math.max(0, totalClasses - attended);
    const creditedBase = coachBaseForSport(m, from.sport, from.coachId);
    const price = creditedBase > 0 ? creditedBase : (parseFloat(from.price) || 0);
    const switchMonth = switchDate.slice(0, 7);
    const monthLabel = fmtMonth(switchMonth);
    const elPrev = $('#sw-preview'); if (!elPrev) return;

    if (targets.length > 1) {
      const split = computeSwitchSplit(price, attended, totalClasses);
      const oldRate = parseFloat(state.coaches.find(c => c.id === from.coachId)?.rate) || 0;
      const aDeduct = (price - split.aShare) * oldRate / 100;
      const rows = targets.map((t, i) => {
        const cls = parseInt($('#sw-classes-' + i)?.value) || 0;
        const val = remaining > 0 ? split.bShare * (cls / remaining) : 0;
        const coachId = parseInt($('#sw-coach-' + i)?.value) || null;
        const rate = parseFloat(state.coaches.find(c => c.id === coachId)?.rate) || 0;
        return `<div style="display:flex;justify-content:space-between;padding:3px 0;border-top:1px solid var(--border)"><span>${escapeHtml(($('#sw-sport-' + i)?.value) || t.sport)} · ${escapeHtml(coachName(coachId))} · ${cls} cls</span><span style="color:var(--green);font-weight:600">+${fmt(val * rate / 100)} <span style="color:var(--text-mute);font-weight:400">@${rate}%</span></span></div>`;
      }).join('');
      elPrev.innerHTML = `<div style="font-weight:700;margin-bottom:6px">📊 Distributed reconciliation (${escapeHtml(monthLabel)})</div>
        <div style="font-size:11px;color:var(--text-dim);margin-bottom:6px">${escapeHtml(coachName(from.coachId))} attended ${attended}/${totalClasses} — keeps ${fmt(split.aShare)} base. The remaining ${fmt(split.bShare)} is split across the sports by class count:</div>
        <div style="display:flex;justify-content:space-between;padding:6px 8px;background:rgba(242,96,96,.06);border-radius:6px;margin-bottom:4px"><span style="color:var(--red)">${escapeHtml(coachName(from.coachId))} deduction</span><span style="color:var(--red);font-weight:700">−${fmt(aDeduct)}</span></div>
        ${rows}`;
      return;
    }

    const newCoachId = parseInt($('#sw-coach-0')?.value || from.coachId);
    const oldCoachName = coachName(from.coachId);
    const newCoachName = coachName(newCoachId);
    let aShare = 0, bShare = 0;
    if (attended === 0) { aShare = 0; bShare = 0; }
    else if (totalClasses > 0) { aShare = (attended / totalClasses) * price; bShare = price - aShare; }
    let body;
    const toSport = $('#sw-sport-0')?.value || '';
    const fromIsCamp = from.sport === SUMMER_CAMP;
    const toIsCamp = toSport === SUMMER_CAMP;
    if (fromIsCamp || toIsCamp) {
      body = `<div style="font-weight:700;color:var(--accent-2);margin-bottom:6px">🌞 Summer Camp · no commission reconciliation</div>
        <div style="color:var(--text-dim)">${fromIsCamp ? 'Switching FROM Summer Camp — no commission was earned to split.' : 'Switching TO Summer Camp — new sport generates no commission.'}</div>`;
    } else if (attended === 0) {
      body = `<div style="font-weight:700;color:var(--accent);margin-bottom:6px">⚠️ No commission earned</div>
        <div>${escapeHtml(oldCoachName)} has 0 attended classes for ${from.sport} as of ${fmtDate(switchDate)}.</div>
        <div style="margin-top:4px;color:var(--text-mute)">Neither coach earns commission from this enrollment.</div>`;
    } else {
      const rate = parseFloat(state.coaches.find(c => c.id === from.coachId)?.rate) || 0;
      const newRate = parseFloat(state.coaches.find(c => c.id === newCoachId)?.rate) || 0;
      const aDeduction = (price * rate / 100) - (aShare * rate / 100);
      const bCommission = bShare * newRate / 100;
      body = `<div style="font-weight:700;margin-bottom:6px">📊 Commission reconciliation (${escapeHtml(monthLabel)})</div>
        <div style="font-size:11px;color:var(--text-dim);margin-bottom:8px">${escapeHtml(oldCoachName)} attended ${attended} of ${totalClasses} classes (${totalClasses ? Math.round(attended / totalClasses * 100) : 0}%) — he keeps ${fmt(aShare)} QAR base, ${escapeHtml(newCoachName)} gets ${fmt(bShare)} QAR.</div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
          <div style="padding:8px;background:rgba(242,96,96,.06);border:1px solid rgba(242,96,96,.2);border-radius:6px">
            <div style="font-size:10px;color:var(--red);text-transform:uppercase;font-weight:600">${escapeHtml(oldCoachName)} · deduction</div>
            <div style="font-size:16px;font-weight:700;margin-top:2px;color:var(--red)">−${fmt(aDeduction)} QAR</div>
            <div style="font-size:10px;color:var(--text-mute);margin-top:2px">in ${escapeHtml(monthLabel)}'s payroll</div>
          </div>
          <div style="padding:8px;background:rgba(16,185,129,.08);border:1px solid rgba(16,185,129,.2);border-radius:6px">
            <div style="font-size:10px;color:var(--green);text-transform:uppercase;font-weight:600">${escapeHtml(newCoachName)} · earning</div>
            <div style="font-size:16px;font-weight:700;margin-top:2px;color:var(--green)">+${fmt(bCommission)} QAR</div>
            <div style="font-size:10px;color:var(--text-mute);margin-top:2px">commission on ${fmt(bShare)} @ ${newRate}%</div>
          </div>
        </div>`;
    }
    elPrev.innerHTML = body;
  }

  setTimeout(() => {
    const addBtn = $('#sw-add-target');
    if (addBtn) addBtn.addEventListener('click', addTarget);
    ['#sw-from', '#sw-date'].forEach(id => { const elx = $(id); if (elx) elx.addEventListener('change', () => { renderTargets(); }); });
    renderTargets();
  }, 50);
};

// ─── Add a renewal / new subscription record ──────────────────────
// For multi-sport members, the member's enrolled sports are offered as quick
// picks so a specific sport can be renewed — even if its classes aren't finished.
window.addRenewal = function(memberId) {
  const m = state.members.find(x => x.id === memberId);
  if (!m) return;
  const sports = ['MMA','Boxing','Kick Boxing','Karate','Taekwondo','Gymnastic','Football','Swimming','Zumba'];

  // Active coaches (registration rule), keeping current coach selectable if inactive
  const selCoaches = activeCoaches();
  if (m.coachId && !selCoaches.some(c => c.id === m.coachId)) {
    const cur = state.coaches.find(c => c.id === m.coachId); if (cur) selCoaches.push(cur);
  }
  const coachOpts = c => selCoaches.map(co => `<option value="${co.id}" ${co.id===c?'selected':''}>${escapeHtml(co.name)}${isCoachActive(co)?'':' (inactive)'}</option>`).join('');

  // The member's current enrolled sports (each with coach + class progress)
  const enrolled = (m.enrollments && m.enrollments.length) ? m.enrollments
    : (m.subscriptions || []).map(s => ({ sport: s.activity, coachId: s.coachId, classes: s.totalClasses || 0, price: s.amountPaid || 0 }));
  // De-dupe by sport+coach
  const seen = new Set();
  const enrolledUnique = enrolled.filter(e => { const k = e.sport + '|' + e.coachId; if (seen.has(k)) return false; seen.add(k); return true; });

  // Build a quick-pick list showing class progress so you can renew before finishing
  function progressFor(sport, coachId) {
    const subs = (m.subscriptions || []).filter(s => s.activity === sport && (coachId == null || s.coachId === coachId));
    let att = 0, tot = 0;
    subs.forEach(s => { att += s.attendedClasses || 0; tot += s.totalClasses || 0; });
    return tot ? `${att}/${tot} classes${att < tot ? ' · not finished' : ' · finished'}` : '';
  }

  const multiSport = enrolledUnique.length > 1;
  const quickPicks = enrolledUnique.map((e, i) => {
    const prog = progressFor(e.sport, e.coachId);
    return `
      <label style="display:flex;align-items:center;gap:8px;padding:8px 10px;border:1px solid var(--border);border-radius:8px;margin-bottom:6px;cursor:pointer" data-renew-pick="${i}">
        <input type="radio" name="renew-sport" value="${i}" ${i===0?'checked':''} />
        <div style="flex:1">
          <div style="font-weight:600;font-size:13px">${escapeHtml(e.sport)} <span class="text-mute" style="font-weight:400">· ${escapeHtml(coachName(e.coachId))}</span></div>
          ${prog ? `<div class="text-dim" style="font-size:11px">${prog}</div>` : ''}
        </div>
        <div class="text-dim" style="font-size:11px">${e.classes ? e.classes + ' cls' : ''}${e.price ? ' · ' + fmt(e.price) + ' QAR' : ''}</div>
      </label>`;
  }).join('');

  showModal({
    title: `Renew Subscription — ${escapeHtml(m.name)}`,
    body: `
      ${multiSport ? `
      <div style="margin-bottom:12px">
        <div style="font-size:11px;color:var(--blue);text-transform:uppercase;letter-spacing:.6px;font-weight:600;margin-bottom:8px">Which sport to renew?</div>
        ${quickPicks}
        <div class="text-mute" style="font-size:10px">This member is enrolled in ${enrolledUnique.length} sports. Pick one to renew — you can renew it even if the classes aren't finished yet.</div>
      </div>` : ''}
      <div class="form-row">
        <div class="field"><label>Activity</label><select id="rn-act">${[...new Set([...enrolledUnique.map(e => e.sport), m.sport, ...sports].filter(Boolean))].map(s => `<option ${s===(enrolledUnique[0]?.sport||m.sport)?'selected':''}>${escapeHtml(s)}</option>`).join('')}</select></div>
        <div class="field" id="rn-coach-field" style="${(enrolledUnique[0]?.sport || m.sport) === SUMMER_CAMP ? 'display:none' : ''}"><label>Coach</label><select id="rn-coach">${coachOpts(enrolledUnique[0]?.coachId || m.coachId)}</select></div>
      </div>
      <div class="form-row">
        <div class="field"><label>Classes</label><input id="rn-classes" type="number" min="0" step="1" value="${enrolledUnique[0]?.classes || ''}" /></div>
        <div class="field"><label>Validity</label><select id="rn-validity">${VALIDITY_OPTIONS.map(v => `<option value="${v}" ${v===DEFAULT_VALIDITY?'selected':''}>${v} days</option>`).join('')}</select></div>
        <div class="field"><label>Amount paid (QAR)</label><input id="rn-amount" type="number" step="0.01" min="0" value="${enrolledUnique[0]?.price || ''}" /></div>
      </div>
      <div class="form-row">
        <div class="field"><label>Start / renewal date</label><input id="rn-start" type="date" value="${TODAY}" /></div>
        <div class="field"><label>Expiry date <span class="text-mute" style="font-size:10px;font-weight:400">(auto · override allowed)</span></label><input id="rn-end" type="date" /><div id="rn-end-hint" class="text-mute" style="font-size:10px;margin-top:3px"></div></div>
      </div>
      <div id="rn-deduct-banner" style="display:none"></div>
      <div id="rn-carry-banner" style="display:none"></div>
      <div class="field"><label>Status</label><select id="rn-status"><option value="active">Active</option><option value="expired">Expired</option></select></div>
    `,
    actions: [
      { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
      { label: 'Save Renewal', class: 'btn primary', onclick: () => {
        const start = $('#rn-start').value;
        const end = $('#rn-end').value;
        const amount = parseFloat($('#rn-amount').value) || 0;
        const classesRaw = parseInt($('#rn-classes').value) || 0;
        const validity = parseInt($('#rn-validity').value) || DEFAULT_VALIDITY;
        const renewedSport = $('#rn-act').value;
        // Camp has no coach; for camp renewals a missing/NaN coach is fine (null).
        const coachId = renewedSport === SUMMER_CAMP ? null : (parseInt($('#rn-coach').value) || null);
        if (!start) { toast('Start date required', 'error'); return; }
        // Guard against creating a DUPLICATE identical period (same sport / coach /
        // start) — the usual cause of two identical rows (renewing twice or a double
        // submit). Admin can still confirm if it's genuinely intended.
        const _dupExisting = (m.subscriptions || []).find(s => (s.activity || '') === renewedSport && (s.start || '') === start && (s.coachId || null) === (coachId || null) && s.status !== 'Withdrawn');
        if (_dupExisting && !confirm(`⚠ ${m.name} already has an identical ${renewedSport} period starting ${fmtDate(start)}.\n\nThis is what creates duplicate rows. Add ANOTHER identical period anyway?`)) return;
        if (!m.renewals) m.renewals = [];
        const _rid = 'r' + Date.now();

        // ── Post-expiry attendance deduction ──
        // If admin confirmed the deduction (checkbox), reduce totalClasses by
        // the count of Y marks attended after the previous expiry.
        let classes = classesRaw;
        let deductedCount = 0;
        const applyDeduction = document.getElementById('rn-apply-deduction')?.checked;
        const pending = window._rnPendingDeduction || 0;
        if (applyDeduction && pending > 0 && classesRaw > 0) {
          deductedCount = Math.min(pending, classesRaw);
          classes = classesRaw - deductedCount;
        }

        // ── Carry-forward credit ──
        // If the member had unused (paid-but-unattended) classes on their previous
        // finished period for this sport, ADD up to 2 of them onto this renewal.
        let carried = 0;
        const applyCarry = document.getElementById('rn-apply-carry')?.checked;
        if (applyCarry && classes > 0) {
          carried = carryForwardCredit(m, renewedSport);
          if (carried > 0) classes = classes + carried;
        }

        // 1) Record in renewals[] (audit trail of manual entries)
        m.renewals.push({
          _rid,
          activity: renewedSport,
          coach: coachName(coachId),
          coachId,
          start, end: end || null,
          validity,
          totalClasses: classes || null,
          amountPaid: amount,
          status: $('#rn-status').value,
          manual: true,
          createdAt: new Date().toISOString(),
        });

        // 2) Also push to subscriptions[] so it shows up in Subscription History,
        //    counts toward classes, and links to the invoice.
        const ref = nextInvoiceRef();
        if (!m.subscriptions) m.subscriptions = [];
        m.subscriptions.push({
          _sid: 's' + Date.now(),
          _rid,                                    // back-ref to the renewal entry
          month: ymToShort(start.slice(0,7)) || start.slice(0,7),
          activity: renewedSport,
          coach: coachName(coachId),
          coachId,
          firstRegistration: m.firstRegistration || null,
          start, end: end || null,
          validity,
          status: $('#rn-status').value,
          totalClasses: classes || null,
          attendedClasses: 0,
          priceCompleted: null,
          amountPaid: amount,
          invoiceNumber: ref,
          manual: true,                            // distinguishes from initial registration
        });

        // 3) Create the corresponding invoice so it appears in revenue
        if (amount > 0) {
          // Build a duration-aware label so the receipt reads e.g.
          // "Summer Camp · 1 month renewal" instead of plain "Summer Camp renewal".
          const dl = (renewedSport === SUMMER_CAMP && classes)
            ? (campLabelForClasses(classes) || '')
            : '';
          const sportLabel = dl ? `${renewedSport} · ${dl}` : renewedSport;
          state.invoices.push({
            id: nextId(state.invoices),
            date: start,
            description: `${sportLabel} renewal — ${m.name}${classes && renewedSport !== SUMMER_CAMP ? ` · ${classes} classes` : ''}`,
            amount,
            method: 'cash',
            month: start.slice(0, 7),
            ref,
            sport: sportLabel,
            coach: coachName(coachId),
            coachId,
            customerId: m.id,
            customerName: m.name,
            category: 'Membership',
            activityType: 'subscription',
            lineItems: [{
              sport: renewedSport,
              coach: coachName(coachId),
              coachId,
              classes,
              price: amount,
              durationLabel: dl || null,
              billMonth: start.slice(0, 7),   // renewal revenue lands in the RENEWAL month, unambiguously
            }],
          });
        }

        // 4) Bump counters + member-level state
        m.renewalCount = (m.renewalCount || 0) + 1;
        if (!m.renewalsBySport) m.renewalsBySport = {};
        m.renewalsBySport[renewedSport] = (m.renewalsBySport[renewedSport] || 0) + 1;
        m.startDate = start;
        if (end && (!m.expiryDate || end > m.expiryDate)) m.expiryDate = end;
        if ($('#rn-status').value === 'active') m.status = 'Active';
        // Renewing re-activates a withdrawn member (Withdrawn is terminal otherwise).
        if (m.status === 'Withdrawn') m.status = ($('#rn-status').value === 'active' ? 'Active' : 'Expired');

        audit('subscription.renew', `member:${m.id}`,
          `Renewed ${renewedSport} for ${m.name || m.nameArabic}`,
          { memberId: m.id, name: m.name, sport: renewedSport, amount, start, end, invoiceRef: ref });

        save();
        closeModal();
        // Clear modal-scoped state so a later renewal doesn't carry over
        window._rnPendingDeduction = 0;
        render();
        toast(`Renewal recorded — ${renewedSport} (#${m.renewalsBySport[renewedSport]} for this sport) · invoice ${ref}${amount > 0 ? ' · ' + fmt(amount) + ' QAR' : ''}${deductedCount > 0 ? ' · −' + deductedCount + ' post-expiry class' + (deductedCount === 1 ? '' : 'es') : ''}${carried > 0 ? ' · +' + carried + ' carried class' + (carried === 1 ? '' : 'es') : ''}`);
      }},
    ],
  });

  // Wire quick-pick radios to fill the form fields
  if (multiSport) {
    document.querySelectorAll('[name="renew-sport"]').forEach(radio => {
      radio.addEventListener('change', e => {
        const e2 = enrolledUnique[parseInt(e.target.value)];
        if (!e2) return;
        const actSel = document.getElementById('rn-act');
        const coachSel = document.getElementById('rn-coach');
        if (actSel) actSel.value = e2.sport;
        if (coachSel) coachSel.value = e2.coachId;
        const coachField2 = document.getElementById('rn-coach-field');
        if (coachField2) coachField2.style.display = (e2.sport === SUMMER_CAMP) ? 'none' : '';
        const cl = document.getElementById('rn-classes'); if (cl) cl.value = e2.classes || '';
        const am = document.getElementById('rn-amount'); if (am) am.value = e2.price || '';
        if (e2.validity) {
          const vSel = document.getElementById('rn-validity');
          if (vSel) vSel.value = e2.validity;
        }
        recalcRnExpiry();
      });
    });
  }

  // Auto-calc renewal expiry: start + validity. User may override.
  let _rnAutoSet = true;
  function recalcRnExpiry() {
    const startEl = document.getElementById('rn-start');
    const vEl = document.getElementById('rn-validity');
    const endEl = document.getElementById('rn-end');
    const hintEl = document.getElementById('rn-end-hint');
    const actEl3 = document.getElementById('rn-act');
    if (!startEl || !vEl || !endEl) return;
    const isCampRenew = actEl3 && actEl3.value === SUMMER_CAMP;
    const v = parseInt(vEl.value) || DEFAULT_VALIDITY;
    // Camp expiry follows business days (a week = 5 Sun–Thu days), driven by the
    // class count; regular sports use calendar days.
    let auto;
    if (isCampRenew) {
      const cls = parseInt((document.getElementById('rn-classes') || {}).value) || 0;
      // Recover the sold duration's day-count from the class count, then end-date it.
      const priceRow = (DEFAULT_SUMMER_CAMP_PRICES || []).find(p => campClassCount(p.days) === cls);
      auto = priceRow ? campEndDate(startEl.value, priceRow.days) : addDays(startEl.value, v);
    } else {
      auto = addDays(startEl.value, v);
    }
    if (!endEl.value || _rnAutoSet) {
      endEl.value = auto;
      _rnAutoSet = true;
    }
    if (hintEl) {
      const same = endEl.value === auto;
      hintEl.textContent = same
        ? (isCampRenew ? `Auto: camp business days (Sun–Thu)` : `Auto: ${fmtDate(startEl.value)} + ${v} days`)
        : `Manual override · auto would be ${fmtDate(auto)}`;
    }
  }
  document.getElementById('rn-start')?.addEventListener('change', recalcRnExpiry);
  document.getElementById('rn-validity')?.addEventListener('change', recalcRnExpiry);
  document.getElementById('rn-classes')?.addEventListener('input', recalcRnExpiry);
  document.getElementById('rn-act')?.addEventListener('change', recalcRnExpiry);
  document.getElementById('rn-end')?.addEventListener('input', () => { _rnAutoSet = false; recalcRnExpiry(); });
  recalcRnExpiry();

  // Post-expiry attendance deduction:
  // If the member is expired (or this sport's previous subscription ended in
  // the past) AND has Y attendance marks AFTER that expiry, the new package's
  // Classes should be reduced by that count. The banner shows the count and
  // a checkbox to confirm the deduction.
  function getLastSportExpiry(sport) {
    // Find the most recent end-date among this member's subscriptions for this sport
    const subs = (m.subscriptions || []).filter(s => s.activity === sport && s.end);
    if (!subs.length) return null;
    return subs.map(s => s.end).sort().pop();
  }
  function countAttendedAfter(sport, afterDateStr) {
    // Count Y marks for this sport that are dated strictly AFTER afterDateStr.
    if (!m.dailyAttendance || !afterDateStr) return 0;
    let total = 0;
    for (const monthKey of Object.keys(m.dailyAttendance)) {
      const mo = m.dailyAttendance[monthKey];
      const sportMap = mo && typeof mo === 'object' ? mo[sport] : null;
      if (!sportMap) continue;
      for (const day of Object.keys(sportMap)) {
        if (sportMap[day] !== 'Y') continue;
        const dateStr = `${monthKey}-${String(day).padStart(2, '0')}`;
        if (dateStr > afterDateStr) total++;
      }
    }
    return total;
  }
  function recalcRnDeduction() {
    // Reset stale state first — runs every time on every modal open.
    // Avoids cross-modal leakage if the DOM lookup below fails.
    window._rnPendingDeduction = 0;
    const actEl = document.getElementById('rn-act');
    const banner = document.getElementById('rn-deduct-banner');
    if (!actEl || !banner) return;
    const sport = actEl.value;
    const lastEnd = getLastSportExpiry(sport);
    const count = lastEnd ? countAttendedAfter(sport, lastEnd) : 0;
    if (!lastEnd || count === 0) {
      banner.style.display = 'none';
      banner.innerHTML = '';
      return;
    }
    window._rnPendingDeduction = count;
    banner.style.display = 'block';
    banner.innerHTML = `
      <div style="margin:4px 0 10px;padding:10px;background:rgba(245,158,11,.08);border:1px solid rgba(245,158,11,.3);border-radius:8px">
        <div style="display:flex;align-items:flex-start;gap:8px">
          <div style="font-size:18px">⚠️</div>
          <div style="flex:1;font-size:12px;line-height:1.5">
            <b>Post-expiry attendance detected.</b><br>
            Member attended <b style="color:var(--accent-2)">${count} class${count===1?'':'es'}</b> of ${escapeHtml(sport)} after the last expiry (${fmtDate(lastEnd)}).
            <label style="display:flex;align-items:center;gap:6px;margin-top:6px;cursor:pointer">
              <input type="checkbox" id="rn-apply-deduction" checked />
              <span>Deduct ${count} class${count===1?'':'es'} from the new package</span>
            </label>
          </div>
        </div>
      </div>
    `;
  }
  // Carry-forward credit banner — runs independently so it shows whether or not
  // there's post-expiry attendance to deduct.
  function recalcRnCarry() {
    const actEl = document.getElementById('rn-act');
    const carryBanner = document.getElementById('rn-carry-banner');
    if (!actEl || !carryBanner) return;
    const sport = actEl.value;
    const credit = carryForwardCredit(m, sport);
    if (credit > 0) {
      carryBanner.style.display = 'block';
      carryBanner.innerHTML = `
        <div style="margin:4px 0 10px;padding:10px;background:rgba(16,185,129,.08);border:1px solid rgba(16,185,129,.3);border-radius:8px">
          <div style="display:flex;align-items:flex-start;gap:8px">
            <div style="font-size:18px">🎁</div>
            <div style="flex:1;font-size:12px;line-height:1.5">
              <b>Carry-forward credit available.</b><br>
              Member has <b style="color:#10b981">${credit} unused class${credit === 1 ? '' : 'es'}</b> from their expired ${escapeHtml(sport)} period (max ${CARRY_FORWARD_MAX} carried).
              <label style="display:flex;align-items:center;gap:6px;margin-top:6px;cursor:pointer">
                <input type="checkbox" id="rn-apply-carry" checked />
                <span>Add ${credit} class${credit === 1 ? '' : 'es'} to this renewal</span>
              </label>
            </div>
          </div>
        </div>
      `;
    } else {
      carryBanner.style.display = 'none';
      carryBanner.innerHTML = '';
    }
  }
  const syncRnCoachVisibility = () => {
    const actEl2 = document.getElementById('rn-act');
    const coachField = document.getElementById('rn-coach-field');
    if (actEl2 && coachField) coachField.style.display = (actEl2.value === SUMMER_CAMP) ? 'none' : '';
  };
  document.getElementById('rn-act')?.addEventListener('change', () => { syncRnCoachVisibility(); recalcRnDeduction(); recalcRnCarry(); });
  syncRnCoachVisibility();
  recalcRnDeduction();
  recalcRnCarry();
};

// Delete ONE specific subscription period (by _sid) — for fixing a duplicate or a
// not-yet-started entry without touching the member's other subscriptions of the
// same sport. Only allowed when that subscription has ZERO attendance (nothing was
// consumed). Also removes its linked invoice (or that sport's line) so PAID drops.
window.deleteSubscription = function(memberId, sid) {
  if (currentRole() !== 'admin') { toast('Only admins can delete a subscription', 'error'); return; }
  const m = state.members.find(x => x.id === memberId);
  if (!m || !Array.isArray(m.subscriptions)) return;
  const sub = m.subscriptions.find(s => (s._sid || s._rid) === sid);
  if (!sub) { toast('Subscription not found', 'error'); return; }
  // A DUPLICATE (identical sport/coach/window twin) can always be deleted: attendance
  // lives in dailyAttendance (keyed by sport+day), so it stays on the surviving twin —
  // deleting the extra period never loses attendance, it just removes the double record.
  const hasTwin = m.subscriptions.some(o => (o._sid || o._rid) !== sid && (o.activity || '') === (sub.activity || '') && (o.start || '') === (sub.start || '') && (o.end || '') === (sub.end || '') && (o.coachId || null) === (sub.coachId || null));
  // Guard: never delete a NON-duplicate subscription that has real attendance.
  const liveAtt = (typeof liveAttendanceCount === 'function')
    ? liveAttendanceCount(m, sub.activity, sub.start || null, sub.end || null).y : 0;
  const attended = Math.max(parseInt(sub.attendedClasses) || 0, liveAtt);
  if (attended > 0 && !hasTwin) {
    toast(`Can't delete — ${attended} class${attended === 1 ? '' : 'es'} already attended on this period. Use Withdraw / Switch Sport instead.`, 'error');
    return;
  }
  const label = `${sub.activity || 'sport'} (${sub.start ? fmtDate(sub.start) : '?'} → ${sub.end ? fmtDate(sub.end) : '?'})`;
  const dupNote = hasTwin ? '\n\n⚠ This is a DUPLICATE of an identical period — the attendance stays on the remaining one.' : '';
  if (!confirm(`Delete this subscription period?\n\n${label}\nPaid: ${fmt(sub.amountPaid || 0)} QAR${dupNote}\n\nThis removes just this one period and its linked invoice (no refund record). The member's other subscriptions are untouched.`)) return;

  // Remove the linked invoice line / invoice for this sub, so PAID drops.
  const ref = sub.invoiceNumber || null;
  if (ref) {
    for (const inv of (state.invoices || [])) {
      if (inv.deleted) continue;
      if (inv.customerId !== m.id) continue;
      if ((inv.ref || '') !== ref && inv.invoiceNumber !== ref) continue;
      const items = (inv.lineItems && inv.lineItems.length) ? inv.lineItems : null;
      if (items && items.length > 1) {
        // Shrink: drop just this sport's line.
        const keep = items.filter(li => li.sport !== sub.activity);
        const removed = items.filter(li => li.sport === sub.activity).reduce((s, li) => s + (Number(li.price) || 0), 0);
        inv.lineItems = keep;
        inv.amount = Math.max(0, (inv.amount || 0) - removed);
      } else {
        inv.deleted = true;   // whole invoice was for this sub
      }
    }
  }
  // Remove the subscription + any matching renewal entry.
  m.subscriptions = m.subscriptions.filter(s => (s._sid || s._rid) !== sid);
  if (sub._rid && Array.isArray(m.renewals)) m.renewals = m.renewals.filter(r => r._rid !== sub._rid);
  // Recompute the member's expiry from whatever subscriptions remain (latest end).
  const ends = (m.subscriptions || []).map(s => s.end).filter(Boolean).sort();
  if (ends.length) m.expiryDate = ends[ends.length - 1];
  else m.expiryDate = m.expiryDate;   // leave as-is if nothing left to derive from
  if (typeof audit === 'function') audit('member.subscription.delete', 'member:' + memberId, `Deleted subscription ${label} (0 attended)`);
  save();
  render();
  toast(`Deleted subscription: ${label}`);
};

// Remove every attendance mark for `sport` whose date falls inside [start,end] from a
// member's dailyAttendance (keyed YYYY-MM → sport → day). Returns the number of
// ATTENDED ('Y') classes removed. Prunes empty sport / month maps.
function _clearSportAttendanceWindow(m, sport, start, end) {
  if (!m || !m.dailyAttendance || !sport) return 0;
  const from = start || '0000-00-00', to = end || '9999-99-99';
  let removed = 0;
  for (const ym of Object.keys(m.dailyAttendance)) {
    const monthMap = m.dailyAttendance[ym];
    const sportMap = monthMap && monthMap[sport];
    if (!sportMap) continue;
    for (const day of Object.keys(sportMap)) {
      const full = ym + '-' + String(day).padStart(2, '0');
      if (full >= from && full <= to) {
        if (String(sportMap[day]).toUpperCase() === 'Y') removed++;
        delete sportMap[day];
      }
    }
    if (!Object.keys(sportMap).length) delete monthMap[sport];
    if (monthMap && !Object.keys(monthMap).length) delete m.dailyAttendance[ym];
  }
  return removed;
}

// ADMIN full delete of a sport/subscription from a member — including the ATTENDANCE
// recorded during that period and the linked invoice line. Used for a COMPLETED (or
// otherwise attended) sport that the quick delete refuses. Always confirms first.
window.deleteSportFull = function(memberId, sid) {
  if (currentRole() !== 'admin') { toast('Only admins can delete a sport', 'error'); return; }
  const m = state.members.find(x => x.id === memberId);
  if (!m || !Array.isArray(m.subscriptions)) return;
  const sub = m.subscriptions.find(s => (s._sid || s._rid) === sid);
  if (!sub) { toast('Subscription not found', 'error'); return; }
  const sport = sub.activity || '';
  const liveAtt = (typeof liveAttendanceCount === 'function')
    ? liveAttendanceCount(m, sport, sub.start || null, sub.end || null).y : 0;
  const attended = Math.max(parseInt(sub.attendedClasses) || 0, liveAtt || 0);
  const label = `${sport || 'sport'} (${sub.start ? fmtDate(sub.start) : '?'} → ${sub.end ? fmtDate(sub.end) : '?'})`;
  if (!confirm(`⚠ DELETE this sport from the member — PERMANENT.\n\n${label}\nPaid: ${fmt(sub.amountPaid || 0)} QAR\nAttendance to be removed: ${attended} class${attended === 1 ? '' : 'es'}\n\nThis removes the subscription period, its enrollment (if no other period of this sport remains), the ${attended} attendance mark${attended === 1 ? '' : 's'} in this window, and the linked invoice line. This cannot be undone.\n\nContinue?`)) return;

  // 1) Remove the attendance recorded during this period for this sport.
  const removedAtt = _clearSportAttendanceWindow(m, sport, sub.start || null, sub.end || null);

  // 2) Remove / shrink the linked invoice for this sub (so PAID drops), same as the
  //    quick delete.
  const ref = sub.invoiceNumber || null;
  if (ref) {
    for (const inv of (state.invoices || [])) {
      if (inv.deleted || inv.customerId !== m.id) continue;
      if ((inv.ref || '') !== ref && inv.invoiceNumber !== ref) continue;
      const items = (inv.lineItems && inv.lineItems.length) ? inv.lineItems : null;
      if (items && items.length > 1) {
        const removed = items.filter(li => li.sport === sport).reduce((s, li) => s + (Number(li.price) || 0), 0);
        inv.lineItems = items.filter(li => li.sport !== sport);
        inv.amount = Math.max(0, (inv.amount || 0) - removed);
      } else {
        inv.deleted = true;
      }
    }
  }

  // 3) Remove the subscription + any matching renewal entry.
  m.subscriptions = m.subscriptions.filter(s => (s._sid || s._rid) !== sid);
  if (sub._rid && Array.isArray(m.renewals)) m.renewals = m.renewals.filter(r => r._rid !== sub._rid);

  // 4) Remove the ENROLLMENT for this sport ONLY if no other subscription of the same
  //    sport remains (don't break a still-active period of the same sport).
  const stillHasSport = (m.subscriptions || []).some(s => (s.activity || '') === sport);
  if (!stillHasSport && Array.isArray(m.enrollments)) {
    m.enrollments = m.enrollments.filter(e => (e.sport || '') !== sport);
  }

  // 5) Recompute expiry from whatever remains.
  const ends = (m.subscriptions || []).map(s => s.end).filter(Boolean).sort();
  if (ends.length) m.expiryDate = ends[ends.length - 1];

  if (typeof stampUpdate === 'function') stampUpdate(m);
  if (typeof audit === 'function') audit('member.sport.delete', 'member:' + memberId,
    `Deleted sport ${label} from ${m.name} — removed ${removedAtt} attendance mark(s)${!stillHasSport ? ' + enrollment' : ''}`,
    { memberId, sport, removedAttendance: removedAtt });
  save();
  render();
  if (typeof viewMember === 'function') viewMember(memberId);   // re-open the card
  toast(`Deleted ${sport} · ${removedAtt} attendance removed`);
};

window.deleteRenewal = function(memberId, rid) {
  const m = state.members.find(x => x.id === memberId);
  if (!m || !m.renewals) return;
  if (!confirm('Delete this renewal record?')) return;
  m.renewals = m.renewals.filter(r => r._rid !== rid);
  save();
  render();
  toast('Renewal deleted');
};

// Add eligible carry-forward credit (unused classes from the previous finished period,
// capped at CARRY_FORWARD_MAX) onto the member's CURRENT active membership for each sport
// that qualifies. Used to fix a renewal where the carry-forward box was missed — e.g. a
// new 8-class period becomes 10 when 2 classes were unused. Updates the subscription total
// and the linked invoice line item, and marks the period so it can't be applied twice.
window.applyCarryForwardToActive = function(memberId) {
  const m = state.members.find(x => x.id === memberId);
  if (!m) { toast('Member not found', 'error'); return; }
  const sports = [...new Set([m.sport, ...((m.enrollments || []).map(e => e.sport)), ...((m.subscriptions || []).map(s => s.activity))].filter(Boolean))];
  const plan = [];
  for (const sp of sports) {
    const credit = (typeof carryForwardCredit === 'function') ? carryForwardCredit(m, sp) : 0;
    if (credit <= 0) continue;
    const active = (m.subscriptions || []).find(s => (s.activity || '') === sp && (!s.end || s.end >= TODAY) && (s.status || '').toLowerCase() !== 'withdrawn' && !s._carryApplied);
    if (active) plan.push({ sp, credit, active });
  }
  if (!plan.length) { toast('No carry-forward credit to apply', 'info'); return; }
  const summary = plan.map(p => `${p.sp}: +${p.credit} (→ ${(parseInt(p.active.totalClasses) || 0) + p.credit})`).join('\n');
  if (!confirm(`Apply carry-forward credit?\n\n${summary}\n\nThis adds the unused classes from the previous period onto the current membership and updates the linked invoice.`)) return;
  let applied = 0;
  for (const p of plan) {
    const before = parseInt(p.active.totalClasses) || 0;
    p.active.totalClasses = before + p.credit;
    p.active._carryApplied = true;
    p.active._carriedClasses = (p.active._carriedClasses || 0) + p.credit;
    applied += p.credit;
    // Update the linked invoice's line item class count + description, if present.
    const inv = (state.invoices || []).find(i => !i.deleted && i.customerId === m.id &&
      ((p.active.invoiceNumber && (i.ref === p.active.invoiceNumber || i.invoiceNumber === p.active.invoiceNumber))));
    if (inv && Array.isArray(inv.lineItems)) {
      const li = inv.lineItems.find(l => (l.sport || '') === p.sp);
      if (li) li.classes = (parseInt(li.classes) || before) + p.credit;
    }
    // Mirror onto the matching enrollment classes too (so edit dialogs agree).
    const enr = (m.enrollments || []).find(e => e.sport === p.sp);
    if (enr && p.sp !== SUMMER_CAMP) enr.classes = (parseInt(enr.classes) || before) + p.credit;
  }
  if (typeof audit === 'function') audit('member.carry.apply', `member:${m.id}`, `Applied ${applied} carry-forward class(es) to ${m.name}`);
  save();
  toast(`✅ Added ${applied} carried class${applied === 1 ? '' : 'es'} to ${m.name}`);
  closeModal();
  viewMember(memberId);
};

window.openMemberHistory = function(memberId) {
  window._historyLastSelected = memberId;
  navigate('history');
};

// ─── Export this member's history as CSV ──────────────────────────
window.exportMemberHistoryCSV = function(memberId) {
  const m = state.members.find(x => x.id === memberId);
  if (!m) return;
  const rows = [['Activity','Coach','Start Date','End Date','Amount Paid','Status','Source']];
  // Dedupe: skip renewals[] entries that already have a matching subscription
  // (those would otherwise show twice).
  const subRids = new Set((m.subscriptions || []).map(s => s._rid).filter(Boolean));
  const all = [
    ...(m.subscriptions || []).map(s => ({ ...s, _source: s.manual ? 'Renewal' : 'Initial enrollment' })),
    ...(m.renewals || [])
      .filter(r => !r._rid || !subRids.has(r._rid))
      .map(s => ({ ...s, _source: 'Manual entry (legacy)' })),
  ].sort((a, b) => (b.start || '').localeCompare(a.start || ''));
  for (const s of all) {
    rows.push([
      s.activity || '',
      s.coach || (s.coachId ? (state.coaches.find(c => c.id === s.coachId)?.name || '') : ''),
      s.start || '',
      s.end || '',
      s.amountPaid || 0,
      s.status || '',
      s._source,
    ]);
  }
  const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
  downloadFile(`${m.name.replace(/[^a-zA-Z0-9]/g,'_')}_history.csv`, csv, 'text/csv');
  toast('History exported');
};

// ═══════════════════════════════════════════════════════════════════
// EXPIRING SOON — members whose membership ends within N days
// ═══════════════════════════════════════════════════════════════════

PAGES.expiring = (main) => {
  const threshold = state.settings?.expiringSoonDays || 3;
  let filter = { sport: 'all', coach: 'all', search: '', bucket: 'all', sort: 'expiry', reminded: 'all' };
  // Which sections are collapsed (default: all open)
  const collapsed = { soon: false, expired: false, upcoming: false };
  // Bulk-selected member IDs (across all sections)
  const selectedIds = new Set();

  // Bucket members (compute once — only filter the visible lists)
  const expired = [];
  const expiringSoon = [];
  const upcoming = [];

  for (const m of state.members) {
    if (m.deleted) continue;  // archived members don't appear in expiring
    if (!m.expiryDate) continue;
    // Skip frozen members — their expiry was shifted, they aren't really expiring
    if (memberStatus(m) === 'Frozen') continue;
    if (memberStatus(m) === 'Withdrawn') continue;  // withdrawn members aren't renewing
    const d = daysUntil(m.expiryDate);
    if (d == null) continue;
    // A camp member who has used up all their classes is DONE (Completed) and needs
    // renewal — surface them in the expired bucket even if their validity window
    // hasn't ended yet.
    if (memberStatus(m) === 'Completed' && (typeof campLimitReached === 'function' && campLimitReached(m))) {
      expired.push({ m, days: Math.min(d, 0), completed: true });
      continue;
    }
    if (d < 0) expired.push({ m, days: d });
    else if (d <= threshold) expiringSoon.push({ m, days: d });
    else if (d <= 30) upcoming.push({ m, days: d });
  }

  expired.sort((a, b) => b.days - a.days);
  expiringSoon.sort((a, b) => a.days - b.days);
  upcoming.sort((a, b) => a.days - b.days);

  // "Recently expired" = expired within the last N days (win-back window), N configurable.
  const recentDays = state.settings?.recentlyExpiredDays || 15;
  const recentCount = expired.filter(x => x.days >= -recentDays).length;

  // Sports + coaches present in the expiring lists, for the dropdowns
  const allEntries = [...expired, ...expiringSoon, ...upcoming];
  const sportsInList = [...new Set(allEntries.flatMap(({m}) =>
    [m.sport, ...((m.enrollments||[]).map(e=>e.sport)), ...((m.subscriptions||[]).map(s=>s.activity))].filter(Boolean)
  ))].sort();
  const coachesInList = [...new Set(allEntries.map(({m}) => m.coachId).filter(Boolean))];

  function matchFilter({ m, days }) {
    // "Recently expired" bucket: only expired within the last N days.
    if (filter.bucket === 'recent' && !(days < 0 && days >= -recentDays)) return false;
    if (filter.sport !== 'all') {
      const ms = new Set([m.sport, ...((m.enrollments||[]).map(e=>e.sport)), ...((m.subscriptions||[]).map(s=>s.activity))].filter(Boolean));
      if (!ms.has(filter.sport)) return false;
    }
    if (filter.coach !== 'all' && m.coachId !== parseInt(filter.coach)) return false;
    // Reminded filter: show only reminded, only not-yet-reminded, or all.
    if (filter.reminded && filter.reminded !== 'all') {
      const rc = (typeof reminderInfo === 'function') ? reminderInfo(m).count : 0;
      if (filter.reminded === 'reminded' && rc < 1) return false;
      if (filter.reminded === 'notreminded' && rc >= 1) return false;
    }
    if (filter.search) {
      const q = filter.search.toLowerCase();
      const hay = [m.name, m.nameArabic, m.phone, m.phone2, m.qid].filter(Boolean).join(' ').toLowerCase();
      if (!searchMatchesFields(q, [m.name, m.nameArabic, m.phone, m.phone2, m.qid], [m.phone, m.phone2])) return false;
    }
    return true;
  }

  // Attended Y-marks per enrolled sport within the member's current cycle window.
  function attendedBySport(m) {
    const enrolls = (m.enrollments && m.enrollments.length) ? m.enrollments : (m.sport ? [{ sport: m.sport, classes: 0 }] : []);
    const out = [];
    for (const e of enrolls) {
      if (!e.sport) continue;
      // Count ALL present marks for this sport (live, unwindowed) so it matches the
      // Attendance grid and the class-limit logic — not just marks inside the
      // member's date window (which under-counted, e.g. showing 6 when 9 attended).
      const attended = (typeof liveAttendanceCount === 'function')
        ? (liveAttendanceCount(m, e.sport, null, null).y || 0) : 0;
      // Planned = the enrolled class/day limit. Prefer the subscription's
      // totalClasses (the real cap) over the enrollment's classes.
      const sub = (m.subscriptions || []).filter(s => (s.activity || '') === e.sport).slice(-1)[0];
      const planned = (sub && parseInt(sub.totalClasses)) || parseInt(e.classes) || 0;
      out.push({ sport: e.sport, attended, planned });
    }
    return out;
  }
  function attendedCell(m) {
    const list = attendedBySport(m);
    if (!list.length) return '<span class="text-mute">—</span>';
    if (list.length === 1) {
      const a = list[0];
      const col = a.planned ? (a.attended / a.planned >= 0.75 ? 'var(--green)' : a.attended / a.planned >= 0.4 ? 'var(--accent-2)' : 'var(--red)') : 'var(--text)';
      return `<span style="font-weight:700;color:${col}" title="${escapeHtml(a.sport)}">${a.attended}${a.planned ? '/' + a.planned : ''}</span>`;
    }
    const total = list.reduce((s, a) => s + a.attended, 0);
    const tip = list.map(a => `${a.sport}: ${a.attended}${a.planned ? '/' + a.planned : ''}`).join('\n');
    return `<span style="font-weight:700;cursor:help;border-bottom:1px dotted var(--text-mute)" title="${escapeHtml(tip)}">🏅 ${total} <span class="text-mute" style="font-weight:400;font-size:11px">(${list.length} ${t('sports', 'رياضات')}) ⓘ</span></span>`;
  }

  function rowHtml({ m, days, completed }, bucket) {
    const color = bucket === 'expired' ? 'var(--red)' : bucket === 'soon' ? 'var(--accent-2)' : 'var(--text-dim)';
    const label = bucket === 'expired' ? `${Math.abs(days)}d ago` : bucket === 'soon' ? `in ${days}d` : `in ${days}d`;
    const phone = m.phone && !m.phone.startsWith('+9747000') ? m.phone : null;
    const lastR = lastRenewalDate(m);
    const isChecked = selectedIds.has(m.id);
    // Pre-build the WhatsApp reminder link (bilingual template, EN + AR)
    let reminderHref = '';
    if (phone) {
      const kind = completed ? 'completed' : (bucket === 'expired' ? 'expired' : 'expiring');
      const msg = buildReminderMessage(m, kind, days);
      const cleanPhone = String(phone).replace(/[^\d]/g, '');
      reminderHref = `https://wa.me/${cleanPhone}?text=${encodeURIComponent(msg)}`;
    }
    return `
      <tr style="cursor:pointer" data-id="${m.id}">
        <td style="width:32px;text-align:center" onclick="event.stopPropagation()">
          <input type="checkbox" class="exp-row-cb" data-id="${m.id}" ${isChecked ? 'checked' : ''} ${phone ? '' : 'disabled title="No phone — cannot include in WhatsApp/SMS"'} style="cursor:${phone ? 'pointer' : 'not-allowed'}" />
        </td>
        <td>
          <div style="display:flex;align-items:center;gap:10px">
            <div class="avatar" style="width:32px;height:32px;font-size:11px;background:linear-gradient(135deg,var(--blue),var(--purple))">${initials(m.name)}</div>
            <div>
              <div style="font-weight:600">${escapeHtml(m.name)}${m.nameArabic ? ` · <span class="text-dim" style="font-weight:normal" dir="rtl">${escapeHtml(m.nameArabic)}</span>` : ''}</div>
              <div class="text-mute" style="font-size:11px">${escapeHtml(m.sport)} · ${escapeHtml(coachName(m.coachId))}</div>
            </div>
          </div>
        </td>
        <td>${phoneCell(phone)}</td>
        <td>${lastR ? fmtDate(lastR) : '<span class="text-mute">—</span>'}</td>
        <td><span style="color:${color};font-weight:600">${fmtDate(m.expiryDate)}</span></td>
        <td><span style="color:${color};font-weight:700">${label}</span></td>
        <td class="text-right">${attendedCell(m)}</td>
        <td class="text-right">${(() => {
          const due = memberOutstanding(m.id);
          const editable = currentRole() === 'admin' || currentRole() === 'receptionist';
          if (due > 0.001) return `<button class="btn ghost sm" ${editable ? `onclick="event.stopPropagation();editMemberPricing(${m.id})"` : 'onclick="event.stopPropagation()"'} title="${editable ? 'Click to record a payment / edit pricing' : 'Outstanding balance'}" style="background:rgba(242,163,60,.15);border:1px solid var(--accent-2);color:var(--accent-2);font-weight:700;padding:4px 10px">⚠ ${fmt(due)}</button>`;
          return '<span style="color:var(--green);font-weight:600">✓</span>';
        })()}</td>
        <td class="text-right" style="white-space:nowrap">
          ${phone
            ? (() => {
                const wasReminded = reminderInfo(m).count > 0;
                // Already reminded → green button (but still clickable to remind again).
                const btnStyle = wasReminded
                  ? 'background:var(--green);border-color:var(--green);color:#fff'
                  : '';
                const btnLabel = wasReminded ? `✓ ${t('Remind again', 'تذكير مجدداً')}` : `💬 Remind`;
                return `<a class="btn primary sm" style="${btnStyle}" href="${reminderHref}" target="_blank" onclick="event.stopPropagation();markReminded(${m.id})" title="${wasReminded ? 'Already reminded — click to send another reminder' : 'Send bilingual reminder via WhatsApp'}">${btnLabel}</a>`;
              })()
            : `<span class="text-mute" style="font-size:11px">No phone</span>`}
          <button class="btn ghost sm" onclick="event.stopPropagation();addRenewal(${m.id})" title="Record renewal">🔄 Renew</button>
          <button class="btn ghost sm" onclick="event.stopPropagation();window._attPdfSubscription(${m.id})" title="Attendance sheet for the last subscription (covers up to two months)">📄 Sheet</button>
          <div id="rem-label-${m.id}" class="text-mute" style="font-size:10px;margin-top:4px;${m.lastRemindedAt ? '' : 'display:none'}">${m.lastRemindedAt ? '✓ ' + t('Reminded', 'تذكير') + ' ' + (reminderInfo(m).count > 1 ? reminderInfo(m).count + '× · ' : '') + t('last', 'آخر') + ' ' + escapeHtml(fmtDateTime(m.lastRemindedAt)) : ''}</div>
        </td>
      </tr>
    `;
  }

  function section(title, color, icon, list, bucket) {
    const isCollapsed = collapsed[bucket];
    // How many in this section are currently selected?
    const sectionIds = list.map(x => x.m.id);
    const selectedInSection = sectionIds.filter(id => selectedIds.has(id)).length;
    const phoneIds = list.filter(x => x.m.phone && !x.m.phone.startsWith('+9747000')).map(x => x.m.id);
    const allPhonesSelected = phoneIds.length > 0 && phoneIds.every(id => selectedIds.has(id));
    return `
      <div class="card" data-bucket="${bucket}">
        <div class="card-header exp-section-header" data-bucket="${bucket}" style="cursor:pointer;user-select:none">
          <div style="display:flex;align-items:center;gap:10px;flex:1">
            <span class="exp-chevron" style="display:inline-block;transition:transform .15s;transform:rotate(${isCollapsed ? '-90' : '0'}deg);color:${color};font-size:13px">▾</span>
            <div>
              <div class="card-title" style="color:${color}">${icon} ${title}</div>
              <div class="card-subtitle">${list.length} member${list.length === 1 ? '' : 's'}${selectedInSection ? ` · <b style="color:var(--blue)">${selectedInSection} selected</b>` : ''}${isCollapsed ? ' · collapsed (click to expand)' : ''}</div>
            </div>
          </div>
        </div>
        <div class="exp-section-body" style="display:${isCollapsed ? 'none' : 'block'}">
          ${list.length ? `
            <div class="table-wrap">
              <table>
                <thead><tr>
                  <th style="width:32px;text-align:center" onclick="event.stopPropagation()">
                    <input type="checkbox" class="exp-select-all" data-bucket="${bucket}" ${allPhonesSelected ? 'checked' : ''} ${phoneIds.length === 0 ? 'disabled' : ''} title="Select all in this section (with phone)" />
                  </th>
                  <th>Member</th><th>Mobile</th><th>Last Renewal</th><th>Expiry</th><th>When</th><th class="text-right">Attended</th><th class="text-right">💰 Due</th><th class="text-right">Actions</th>
                </tr></thead>
                <tbody>${list.map(x => rowHtml(x, bucket)).join('')}</tbody>
              </table>
            </div>
          ` : `<div class="empty" style="padding:24px;font-size:13px">No members in this group 🎉</div>`}
        </div>
      </div>
    `;
  }

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>Expiring Soon</h1>
        <div class="subtitle">Members needing renewal · alert window: ${threshold} days <a href="#" onclick="event.preventDefault();navigate('settings')" style="color:var(--blue)">(change)</a></div>
      </div>
      <div class="topbar-actions">
        <button class="btn ghost" title="Show members who expired within the last ${recentDays} days (set in Settings)" onclick="document.getElementById('exp-bucket').value='recent';document.getElementById('exp-bucket').dispatchEvent(new Event('change'))">🔴 Recently expired (≤${recentDays}d) · ${recentCount}</button>
        ${isViewerRole() ? '' : '<button class="btn ghost" id="export-expiring">📥 Export CSV</button>'}
      </div>
    </div>

    <div class="kpi-grid mb-3">
      <div class="kpi red" style="cursor:pointer" onclick="document.getElementById('exp-bucket').value='expired';document.getElementById('exp-bucket').dispatchEvent(new Event('change'))">
        <div class="kpi-icon">⛔</div>
        <div class="kpi-label">Already Expired</div>
        <div class="kpi-value num">${expired.length}</div>
        <div class="kpi-delta flat">Lost members · click to filter</div>
      </div>
      <div class="kpi orange" style="cursor:pointer" onclick="document.getElementById('exp-bucket').value='soon';document.getElementById('exp-bucket').dispatchEvent(new Event('change'))">
        <div class="kpi-icon">⏰</div>
        <div class="kpi-label">Expiring in ≤ ${threshold} days</div>
        <div class="kpi-value num">${expiringSoon.length}</div>
        <div class="kpi-delta flat">Call them now · click to filter</div>
      </div>
      <div class="kpi blue" style="cursor:pointer" onclick="document.getElementById('exp-bucket').value='upcoming';document.getElementById('exp-bucket').dispatchEvent(new Event('change'))">
        <div class="kpi-icon">📅</div>
        <div class="kpi-label">Expiring in ≤ 30 days</div>
        <div class="kpi-value num">${upcoming.length}</div>
        <div class="kpi-delta flat">On the horizon · click to filter</div>
      </div>
      ${(() => {
        const inList = [...expired, ...expiringSoon, ...upcoming];
        const dueRows = inList.filter(({ m }) => memberOutstanding(m.id) > 0.001);
        if (!dueRows.length) return '';
        const total = dueRows.reduce((s, { m }) => s + memberOutstanding(m.id), 0);
        return `<div class="kpi" style="background:rgba(242,163,60,.10);border:1px solid var(--accent-2)">
          <div class="kpi-icon">💰</div>
          <div class="kpi-label" style="color:var(--accent-2)">Money due (from these members)</div>
          <div class="kpi-value num" style="color:var(--accent-2)">${fmt(total)} <span style="font-size:12px;color:var(--text-dim)">QAR</span></div>
          <div class="kpi-delta flat">${dueRows.length} member${dueRows.length === 1 ? '' : 's'} owe payment · click 💰 in the table to collect</div>
        </div>`;
      })()}
      ${isViewerRole() ? '' : `<div class="kpi green">
        <div class="kpi-icon">💰</div>
        <div class="kpi-label">Potential Revenue</div>
        <div class="kpi-value num">${fmt((expired.length + expiringSoon.length) * 350)} <span style="font-size:12px;color:var(--text-dim)">QAR</span></div>
        <div class="kpi-delta flat">@ 350 QAR avg/renewal</div>
      </div>`}
    </div>

    <div class="card" style="padding:14px 16px;margin-bottom:14px">
      <div class="filter-bar" style="flex-wrap:wrap">
        <select id="exp-bucket" class="btn ghost">
          <option value="all">All statuses</option>
          <option value="soon">⏰ Expiring in ≤ ${threshold} days</option>
          <option value="recent">🔴 Recently expired (≤ ${recentDays} days)</option>
          <option value="expired">⛔ Already expired</option>
          <option value="upcoming">📅 Expiring in ≤ 30 days</option>
        </select>
        <select id="exp-sport" class="btn ghost">
          <option value="all">All sports</option>
          ${sportsInList.map(s => `<option value="${escapeHtml(s)}">${escapeHtml(s)}</option>`).join('')}
        </select>
        <select id="exp-coach" class="btn ghost">
          <option value="all">All coaches</option>
          ${coachesInList.map(cid => `<option value="${cid}">${escapeHtml(coachName(cid))}</option>`).join('')}
        </select>
        <select id="exp-reminded" class="btn ghost" title="${t('Filter by reminder status', 'تصفية حسب حالة التذكير')}">
          <option value="all">🔔 ${t('All (reminded or not)', 'الكل (مذكّر أو لا)')}</option>
          <option value="reminded">✓ ${t('Reminded', 'تم تذكيره')}</option>
          <option value="notreminded">○ ${t('Not reminded yet', 'لم يُذكّر بعد')}</option>
        </select>
        <select id="exp-sort" class="btn ghost" title="Sort each section">
          <option value="expiry">↕ Sort: Expiry (default)</option>
          <option value="renewal_desc">↓ Last renewal: newest first</option>
          <option value="renewal_asc">↑ Last renewal: oldest first</option>
        </select>
        <div class="search" style="flex:1;min-width:220px"><input id="exp-search" type="text" placeholder="Search by name, mobile, QID..." /></div>
        <button class="btn ghost sm" id="exp-collapse-all" title="Collapse all sections">⊟ Collapse all</button>
        <button class="btn ghost sm" id="exp-expand-all" title="Expand all sections">⊞ Expand all</button>
      </div>
    </div>

    <div id="exp-sections"></div>

    <!-- Floating bulk action bar (only visible when 1+ members are selected) -->
    <div id="exp-bulk-bar" style="display:none;position:fixed;bottom:24px;left:50%;transform:translateX(-50%);z-index:1000;background:var(--surface-2);border:1px solid var(--border);border-radius:12px;padding:12px 18px;box-shadow:0 10px 40px rgba(0,0,0,.4);align-items:center;gap:12px;font-size:13px">
      <div style="display:flex;align-items:center;gap:8px">
        <span style="background:var(--blue);color:white;border-radius:999px;padding:2px 10px;font-weight:700;font-size:11px"><span id="exp-bulk-count">0</span> selected</span>
      </div>
      <button class="btn ghost sm" id="exp-bulk-copy" title="Copy phone numbers (comma-separated) to clipboard">📋 Copy phones</button>
      <button class="btn ghost sm" id="exp-bulk-message" title="Copy a renewal reminder message">📝 Copy message</button>
      <button class="btn primary sm" id="exp-bulk-whatsapp" title="Open WhatsApp for each selected member with a bilingual reminder pre-filled">💬 Send Reminders</button>
      <button class="btn ghost sm" id="exp-bulk-clear" style="color:var(--text-mute)" title="Clear selection">✕</button>
    </div>
  `;

  function renderSections() {
    // Sort within each section. Default keeps the expiry-proximity order computed
    // above; the other options re-order by last-renewal date (asc/desc).
    const applySort = (arr) => {
      if (filter.sort === 'renewal_desc' || filter.sort === 'renewal_asc') {
        const dir = filter.sort === 'renewal_asc' ? 1 : -1;
        return arr.slice().sort((a, b) => {
          const ra = lastRenewalDate(a.m) || '', rb = lastRenewalDate(b.m) || '';
          if (ra === rb) return 0;
          if (!ra) return 1;       // members with no renewal date go last
          if (!rb) return -1;
          return ra < rb ? -dir : dir;
        });
      }
      return arr;   // 'expiry' default — already sorted by days
    };
    const sFiltered = applySort(expiringSoon.filter(matchFilter));
    const eFiltered = applySort(expired.filter(matchFilter));
    const uFiltered = applySort(upcoming.filter(matchFilter));
    const parts = [];
    if (filter.bucket === 'recent') {
      parts.push(section(`Recently expired — within ${recentDays} days`, 'var(--red)', '🔴', eFiltered, 'expired'));
    }
    if (filter.bucket === 'all' || filter.bucket === 'soon')
      parts.push(section('Expiring within ' + threshold + ' days — call ASAP', 'var(--accent-2)', '⏰', sFiltered, 'soon'));
    if (filter.bucket === 'all' || filter.bucket === 'expired')
      parts.push(section('Already expired', 'var(--red)', '⛔', eFiltered, 'expired'));
    if (filter.bucket === 'all' || filter.bucket === 'upcoming')
      parts.push(section('Expiring within 30 days', 'var(--blue)', '📅', uFiltered, 'upcoming'));
    $('#exp-sections').innerHTML = parts.join('');
    // Wire row clicks (open member detail)
    $$('tbody tr[data-id]').forEach(tr => {
      tr.addEventListener('click', () => viewMember(parseInt(tr.dataset.id)));
    });
    // Wire collapse/expand on each section header
    $$('.exp-section-header').forEach(h => {
      h.addEventListener('click', () => {
        const b = h.dataset.bucket;
        collapsed[b] = !collapsed[b];
        renderSections();
      });
    });
    // Wire per-row checkbox toggles
    $$('.exp-row-cb').forEach(cb => {
      cb.addEventListener('click', e => e.stopPropagation());
      cb.addEventListener('change', e => {
        const id = parseInt(e.target.dataset.id);
        if (e.target.checked) selectedIds.add(id);
        else selectedIds.delete(id);
        updateBulkBar();
        // Update section subtitle counts
        renderSectionHeadersOnly();
      });
    });
    // Wire select-all-in-section checkbox
    $$('.exp-select-all').forEach(cb => {
      cb.addEventListener('click', e => e.stopPropagation());
      cb.addEventListener('change', e => {
        const bucket = e.target.dataset.bucket;
        const list = bucket === 'soon' ? expiringSoon.filter(matchFilter)
                   : bucket === 'expired' ? expired.filter(matchFilter)
                   : upcoming.filter(matchFilter);
        const phoneIds = list.filter(x => x.m.phone && !x.m.phone.startsWith('+9747000')).map(x => x.m.id);
        if (e.target.checked) phoneIds.forEach(id => selectedIds.add(id));
        else phoneIds.forEach(id => selectedIds.delete(id));
        renderSections();  // re-render to update all row checkboxes
        updateBulkBar();
      });
    });
    updateBulkBar();
  }

  // Lightweight update for section subtitles only — avoids full re-render
  // when toggling a single row (so DOM focus / scroll position isn't lost).
  function renderSectionHeadersOnly() {
    $$('.exp-section-header').forEach(h => {
      const b = h.dataset.bucket;
      const list = b === 'soon' ? expiringSoon.filter(matchFilter)
                  : b === 'expired' ? expired.filter(matchFilter)
                  : upcoming.filter(matchFilter);
      const sel = list.filter(x => selectedIds.has(x.m.id)).length;
      const sub = h.querySelector('.card-subtitle');
      if (sub) {
        sub.innerHTML = `${list.length} member${list.length === 1 ? '' : 's'}${sel ? ` · <b style="color:var(--blue)">${sel} selected</b>` : ''}${collapsed[b] ? ' · collapsed (click to expand)' : ''}`;
      }
    });
  }

  // Show/hide the floating bulk action bar based on selection count
  function updateBulkBar() {
    const bar = $('#exp-bulk-bar');
    const countEl = $('#exp-bulk-count');
    if (!bar || !countEl) return;
    const count = selectedIds.size;
    countEl.textContent = count;
    bar.style.display = count > 0 ? 'flex' : 'none';
  }

  // Pull phone numbers + names for current selection (de-duped)
  function selectedMembersWithPhone() {
    return [...selectedIds]
      .map(id => state.members.find(m => m.id === id))
      .filter(m => m && m.phone && !m.phone.startsWith('+9747000'));
  }

  renderSections();

  $('#exp-bucket').addEventListener('change', e => { filter.bucket = e.target.value; renderSections(); });
  $('#exp-sport').addEventListener('change', e => { filter.sport = e.target.value; renderSections(); });
  $('#exp-coach').addEventListener('change', e => { filter.coach = e.target.value; renderSections(); });
  $('#exp-reminded')?.addEventListener('change', e => { filter.reminded = e.target.value; renderSections(); });
  $('#exp-sort').addEventListener('change', e => { filter.sort = e.target.value; renderSections(); });
  $('#exp-search').addEventListener('input', e => { filter.search = e.target.value; renderSections(); });
  attachRecentSearch('exp-search', 'campmembers');
  $('#exp-collapse-all').addEventListener('click', () => {
    collapsed.soon = collapsed.expired = collapsed.upcoming = true;
    renderSections();
  });
  $('#exp-expand-all').addEventListener('click', () => {
    collapsed.soon = collapsed.expired = collapsed.upcoming = false;
    renderSections();
  });

  // ─── Bulk action bar wiring ──────────────────────────────────────
  $('#exp-bulk-clear').addEventListener('click', () => {
    selectedIds.clear();
    renderSections();
  });
  $('#exp-bulk-copy').addEventListener('click', async () => {
    const members = selectedMembersWithPhone();
    if (!members.length) { toast('No selected members have phone numbers', 'error'); return; }
    // Strip non-digits from each phone for cleanest copy. Comma-separated.
    const phones = members.map(m => m.phone.replace(/[^\d+]/g, '')).join(', ');
    try {
      await navigator.clipboard.writeText(phones);
      toast(`📋 Copied ${members.length} phone number${members.length === 1 ? '' : 's'} to clipboard`);
    } catch {
      // Fallback: show in a modal so admin can manually copy
      showModal({
        title: 'Copy phone numbers',
        body: `<p>Clipboard access blocked — copy manually below:</p>
          <textarea readonly style="width:100%;height:120px;padding:10px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:monospace">${phones}</textarea>`,
        actions: [{ label: 'Close', class: 'btn primary', onclick: closeModal }],
      });
    }
  });
  $('#exp-bulk-message').addEventListener('click', async () => {
    const members = selectedMembersWithPhone();
    if (!members.length) { toast('No selected members have phone numbers', 'error'); return; }
    // Generic reminder template — admin can adjust before sending
    const tpl = `Dear member,

This is a reminder from Black Stars Sports Club: your membership is expiring soon. Please contact us to renew and continue training.

Black Stars Sports Club
Waab, Doha`;
    try {
      await navigator.clipboard.writeText(tpl);
      toast('📝 Reminder template copied · paste into WhatsApp');
    } catch {
      showModal({
        title: 'Reminder message',
        body: `<p>Copy this message and paste into WhatsApp:</p>
          <textarea readonly style="width:100%;height:160px;padding:10px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text);font-family:monospace">${tpl}</textarea>`,
        actions: [{ label: 'Close', class: 'btn primary', onclick: closeModal }],
      });
    }
  });
  $('#exp-bulk-whatsapp').addEventListener('click', () => {
    const members = selectedMembersWithPhone();
    if (!members.length) { toast('No selected members have phone numbers', 'error'); return; }
    // Browsers block opening >1 popup without user gesture — warn for 5+ tabs
    if (members.length > 5 && !confirm(`This will open ${members.length} WhatsApp tabs, each with a personalized bilingual reminder.\n\nMany browsers block multiple tabs without explicit permission. Continue?`)) return;
    // Build a lookup of memberId → bucket + days. We already computed these
    // when rendering the page, so reuse them rather than recomputing.
    const bucketOf = new Map();
    expired.forEach(x => bucketOf.set(x.m.id, { kind: 'expired',  days: x.days }));
    expiringSoon.forEach(x => bucketOf.set(x.m.id, { kind: 'expiring', days: x.days }));
    upcoming.forEach(x => bucketOf.set(x.m.id, { kind: 'expiring', days: x.days }));

    let opened = 0, blocked = 0;
    const nowIso = new Date().toISOString();
    for (const m of members) {
      const info = bucketOf.get(m.id) || { kind: 'expiring', days: 0 };
      const msg = buildReminderMessage(m, info.kind, info.days);
      const ph = m.phone.replace(/[^\d]/g, '');
      const url = `https://wa.me/${ph}?text=${encodeURIComponent(msg)}`;
      const w = window.open(url, '_blank');
      if (w) { opened++; m.lastRemindedAt = nowIso; } else blocked++;
    }
    if (opened) save();
    if (blocked) {
      toast(`Opened ${opened} · ${blocked} blocked by browser. Allow popups to open the rest.`, 'error');
    } else {
      toast(`💬 Opened ${opened} reminder${opened === 1 ? '' : 's'} (bilingual)`);
    }
  });

  $('#export-expiring')?.addEventListener('click', () => {   // hidden for viewer/reception role
    const all = [...expiringSoon.filter(matchFilter).map(x => ({ ...x, bucket: 'Expiring soon' })),
                 ...expired.filter(matchFilter).map(x => ({ ...x, bucket: 'Expired' })),
                 ...upcoming.filter(matchFilter).map(x => ({ ...x, bucket: 'Upcoming' }))];
    const rows = [['Name','Name Arabic','Mobile','QID','Sport','Coach','Last Renewal','Expiry','Days','Bucket']];
    for (const { m, days, bucket } of all) {
      rows.push([m.name, m.nameArabic || '', m.phone || '', m.qid || '', m.sport, coachName(m.coachId),
                 lastRenewalDate(m) || '', m.expiryDate || '', days, bucket]);
    }
    const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
    downloadFile('expiring-members.csv', csv, 'text/csv');
    toast(`Exported ${all.length} member${all.length===1?'':'s'}`);
  });
};

// ═══════════════════════════════════════════════════════════════════
// TRIALS — people who came for a free trial, follow-up reminders
// ═══════════════════════════════════════════════════════════════════

PAGES.trials = (main) => {
  let filter = { status: 'all', search: '', sport: 'all' };
  const pg = makePager(10);

  function applyFilter() {
    return (state.trials || []).filter(t => {
      if (filter.status !== 'all' && t.status !== filter.status) return false;
      if (filter.sport !== 'all' && t.sport !== filter.sport && t.sport2 !== filter.sport) return false;
      if (filter.search) {
        const q = filter.search.toLowerCase();
        const hay = [t.name, t.nameArabic, t.phone, t.email, t.notes].filter(Boolean).join(' ').toLowerCase();
        if (!searchMatchesFields(q, [t.name, t.nameArabic, t.phone, t.email, t.notes], [t.phone])) return false;
      }
      return true;
    });
  }

  function refresh() {
    const allTrials = applyFilter().sort((a, b) => (b.trialDate || '').localeCompare(a.trialDate || ''));
    const trials = paginate(allTrials, pg);

    $('#trial-tbody').innerHTML = trials.length ? trials.map(t => {
      const phone = t.phone || '';
      const daysSince = t.trialDate ? Math.abs(daysUntil(t.trialDate) || 0) : null;
      const statusColor = t.status === 'converted' ? 'var(--green)' : t.status === 'declined' ? 'var(--red)' : t.status === 'follow-up' ? 'var(--accent-2)' : 'var(--blue)';
      return `
        <tr data-id="${t.id}">
          <td>
            <div style="display:flex;align-items:center;gap:10px">
              <div class="avatar" style="width:32px;height:32px;font-size:11px;background:linear-gradient(135deg,var(--accent),var(--accent-2))">${initials(t.name)}</div>
              <div>
                <div style="font-weight:600">${escapeHtml(t.name)}${t.nameArabic ? ` · <span class="text-dim" style="font-weight:normal" dir="rtl">${escapeHtml(t.nameArabic)}</span>` : ''}</div>
                <div class="text-mute" style="font-size:11px">${escapeHtml(t.email || phone || '')}</div>
              </div>
            </div>
          </td>
          <td>${phoneCell(phone)}</td>
          <td>${escapeHtml(t.sport || '—')}${t.sport2 ? `<div class="text-mute" style="font-size:10px">+ ${escapeHtml(t.sport2)}</div>` : ''}</td>
          <td>${t.coachId ? escapeHtml(coachName(t.coachId)) : '<span class="text-mute">—</span>'}${t.sport2 && t.coachId2 ? `<div class="text-mute" style="font-size:10px">+ ${escapeHtml(coachName(t.coachId2))}</div>` : ''}</td>
          <td>${t.trialDate ? fmtDate(t.trialDate) : '<span class="text-mute">—</span>'}${daysSince != null ? `<div class="text-mute" style="font-size:10px">${daysSince}d ago</div>` : ''}</td>
          <td>${t.followUpDate ? fmtDate(t.followUpDate) : '<span class="text-mute">—</span>'}</td>
          <td><span style="color:${statusColor};font-weight:600;text-transform:capitalize">${t.status || 'new'}</span></td>
          <td class="text-right" style="white-space:nowrap">
            ${phone ? `<a class="btn ghost sm" href="https://wa.me/${phone.replace(/[^\d]/g, '')}?text=${encodeURIComponent(buildTrialFollowupMessage(t))}" target="_blank" title="${t.status === 'converted' ? 'WhatsApp' : 'Send an encouraging follow-up to join'}" onclick="event.stopPropagation();_logTrialFollowup(${t.id})">💬</a>` : ''}
            <button class="btn ghost sm" onclick="editTrial(${t.id})" title="Edit">✏️</button>
            <button class="btn primary sm" onclick="convertTrialToMember(${t.id})" title="Convert to member">→ Convert</button>
            <button class="btn ghost sm" onclick="deleteTrial(${t.id})" title="Delete">🗑</button>
          </td>
        </tr>
      `;
    }).join('') : `<tr><td colspan="8" class="empty"><div class="empty-icon">🎁</div>No trial entries yet. Click + Add Trial to record someone.</td></tr>`;

    $('#trial-count').textContent = `${allTrials.length} of ${(state.trials || []).length}`;
    $('#trial-pagination').innerHTML = paginationBar(pg, allTrials.length, 'trial');
    bindPagination('trial', pg, allTrials.length, refresh);
  }

  // Compute KPIs
  const all = state.trials || [];
  const newCount = all.filter(t => !t.status || t.status === 'new').length;
  const followCount = all.filter(t => t.status === 'follow-up').length;
  const convertedCount = all.filter(t => t.status === 'converted').length;
  const conversionRate = all.length ? Math.round(convertedCount / all.length * 100) : 0;

  // Unique sports for filter dropdown
  const uniqSports = [...new Set(all.flatMap(t => [t.sport, t.sport2]).filter(Boolean))].sort();

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>Trials</h1>
        <div class="subtitle">Prospective members who came for a free class — log them and follow up</div>
      </div>
      <div class="topbar-actions">
        ${isViewerRole() ? '' : '<button class="btn ghost" id="export-trials">📥 Export CSV</button>'}
        <button class="btn primary" id="add-trial">+ Add Trial</button>
      </div>
    </div>

    <div class="kpi-grid mb-3">
      <div class="kpi">
        <div class="kpi-icon">🎁</div>
        <div class="kpi-label">Total Trials</div>
        <div class="kpi-value num">${all.length}</div>
      </div>
      <div class="kpi blue">
        <div class="kpi-icon">🆕</div>
        <div class="kpi-label">New (no follow-up yet)</div>
        <div class="kpi-value num">${newCount}</div>
      </div>
      <div class="kpi orange">
        <div class="kpi-icon">📞</div>
        <div class="kpi-label">In Follow-up</div>
        <div class="kpi-value num">${followCount}</div>
      </div>
      <div class="kpi green">
        <div class="kpi-icon">✓</div>
        <div class="kpi-label">Conversion Rate</div>
        <div class="kpi-value num">${conversionRate}<span style="font-size:14px">%</span></div>
        <div class="kpi-delta flat">${convertedCount} converted</div>
      </div>
    </div>

    <div class="card">
      <div class="card-header">
        <div>
          <div class="card-title">${t('Trial Log', 'سجل التجارب')}</div>
          <div class="card-subtitle"><span id="trial-count">0 of 0</span></div>
        </div>
      </div>
      <div class="filter-bar">
        <div class="search"><input id="trial-search" type="text" placeholder="Search name, phone, notes..." /></div>
        <select id="trial-status" class="btn ghost">
          <option value="all">All statuses</option>
          <option value="new">New</option>
          <option value="follow-up">In follow-up</option>
          <option value="converted">Converted</option>
          <option value="declined">Declined</option>
        </select>
        <select id="trial-sport" class="btn ghost">
          <option value="all">All sports</option>
          ${SPORTS.map(s => `<option>${s}</option>`).join('')}
        </select>
      </div>
      <div class="table-wrap">
        <table>
          <thead>
            <tr>
              <th>Name</th>
              <th>Mobile</th>
              <th>Sport</th>
              <th>Coach</th>
              <th>Trial Date</th>
              <th>Follow-up</th>
              <th>Status</th>
              <th class="text-right">Actions</th>
            </tr>
          </thead>
          <tbody id="trial-tbody"></tbody>
        </table>
      </div>
      <div id="trial-pagination"></div>
    </div>
  `;

  $('#trial-search').addEventListener('input', e => { filter.search = e.target.value; pg.page = 1; refresh(); });
  attachRecentSearch('trial-search', 'trials');
  $('#trial-status').addEventListener('change', e => { filter.status = e.target.value; pg.page = 1; refresh(); });
  $('#trial-sport').addEventListener('change', e => { filter.sport = e.target.value; pg.page = 1; refresh(); });
  $('#add-trial').addEventListener('click', () => addTrial());
  $('#export-trials')?.addEventListener('click', () => {   // hidden for viewer/reception role
    const rows = [['Name','Name Arabic','Mobile','Email','Sport','Coach','2nd Sport','2nd Coach','Trial Date','Follow-up Date','Status','Source','Notes']];
    for (const t of (state.trials || [])) {
      rows.push([t.name, t.nameArabic || '', t.phone || '', t.email || '', t.sport || '',
                 t.coachId ? coachName(t.coachId) : '', t.sport2 || '', t.coachId2 ? coachName(t.coachId2) : '',
                 t.trialDate || '', t.followUpDate || '',
                 t.status || 'new', t.source || '', t.notes || '']);
    }
    const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
    downloadFile('trials.csv', csv, 'text/csv');
    toast('Trials exported');
  });

  refresh();
};

// ─── Trial CRUD ───────────────────────────────────────────────────
function addTrial() {
  showTrialForm({
    id: nextId(state.trials || []),
    name: '', phone: '', email: '',
    sport: 'MMA', coachId: 1,
    trialDate: TODAY, followUpDate: '',
    status: 'new', source: '', notes: '',
  });
}

// When the encouraging WhatsApp message is sent to a NEW trial, move it into the
// "in follow-up" stage and stamp today's date. Already-progressed trials (follow-up,
// converted, declined) are left as-is. Runs as the WhatsApp link opens.
window._logTrialFollowup = function(id) {
  const t = (state.trials || []).find(x => x.id === id);
  if (!t) return;
  if (t.status === 'new' || !t.status) {
    t.status = 'follow-up';
    if (!t.followUpDate) t.followUpDate = TODAY;
    if (typeof audit === 'function') audit('trial.followup', 'trial:' + id, `Sent WhatsApp follow-up to ${t.name}`);
    save();
    // Soft refresh so the KPI counts + status update without disturbing the click.
    setTimeout(() => { try { render(); } catch (_) {} }, 50);
  }
};

window.editTrial = function(id) {
  const t = (state.trials || []).find(x => x.id === id);
  if (!t) return;
  showTrialForm(t);
};

function showTrialForm(t) {
  const isNew = !(state.trials || []).find(x => x.id === t.id);
  showModal({
    title: isNew ? 'Add Trial' : 'Edit Trial',
    body: `
      <div class="form-row">
        <div class="field"><label>Name (English) <span style="color:var(--accent)">*</span></label><input id="t-name" value="${escapeHtml(t.name || '')}" placeholder="First and last name" /></div>
        <div class="field"><label>Name (Arabic)</label><input id="t-name-ar" dir="rtl" value="${escapeHtml(t.nameArabic || '')}" /></div>
      </div>
      <div class="form-row">
        ${phoneInputHtml('t-phone', t.phone, { label: 'Mobile *' })}
        <div class="field"><label>Email (optional)</label><input id="t-email" type="email" value="${escapeHtml(t.email || '')}" /></div>
      </div>
      <div class="form-row">
        <div class="field"><label>Sport tried <span style="color:var(--accent)">*</span></label><select id="t-sport"><option value="" ${!t.sport ? 'selected' : ''}>— pick a sport —</option>${SPORTS.map(s => `<option ${s===t.sport?'selected':''}>${s}</option>`).join('')}</select></div>
        <div class="field"><label>With Coach <span style="color:var(--accent)">*</span></label><select id="t-coach"><option value="" ${!t.coachId ? 'selected' : ''}>— pick a coach —</option>${activeCoaches().map(c => `<option value="${c.id}" ${c.id===t.coachId?'selected':''}>${escapeHtml(c.name)}</option>`).join('')}</select></div>
      </div>
      <div class="form-row">
        <div class="field"><label>2nd sport tried <span class="text-mute" style="font-size:10px">(optional)</span></label><select id="t-sport2"><option value="" ${!t.sport2 ? 'selected' : ''}>— none —</option>${SPORTS.map(s => `<option ${s===t.sport2?'selected':''}>${s}</option>`).join('')}</select></div>
        <div class="field"><label>With Coach</label><select id="t-coach2"><option value="" ${!t.coachId2 ? 'selected' : ''}>— pick a coach —</option>${activeCoaches().map(c => `<option value="${c.id}" ${c.id===t.coachId2?'selected':''}>${escapeHtml(c.name)}</option>`).join('')}</select></div>
      </div>
      <div class="form-row">
        <div class="field"><label>Trial date</label><input id="t-date" type="date" value="${t.trialDate || TODAY}" /></div>
        <div class="field"><label>Follow-up date</label><input id="t-fu" type="date" value="${t.followUpDate || ''}" /></div>
      </div>
      <div class="form-row">
        <div class="field"><label>Status</label><select id="t-status">
          <option value="new" ${t.status==='new'?'selected':''}>New (no follow-up yet)</option>
          <option value="follow-up" ${t.status==='follow-up'?'selected':''}>In follow-up</option>
          <option value="converted" ${t.status==='converted'?'selected':''}>Converted (became member)</option>
          <option value="declined" ${t.status==='declined'?'selected':''}>Declined</option>
        </select></div>
        <div class="field"><label>Source</label><select id="t-source">
          <option value="" ${!t.source?'selected':''}>— select —</option>
          <option ${t.source==='Walk-in'?'selected':''}>Walk-in</option>
          <option ${t.source==='Instagram'?'selected':''}>Instagram</option>
          <option ${t.source==='Friend referral'?'selected':''}>Friend referral</option>
          <option ${t.source==='Google'?'selected':''}>Google</option>
          <option ${t.source==='Flyer'?'selected':''}>Flyer</option>
          <option ${t.source==='Other'?'selected':''}>Other</option>
        </select></div>
      </div>
      <div class="field"><label>Notes</label><textarea id="t-notes" rows="3" placeholder="What did they say? Any feedback?">${escapeHtml(t.notes || '')}</textarea></div>
    `,
    actions: [
      { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
      { label: isNew ? 'Add' : 'Save', class: 'btn primary', onclick: () => {
        // ── Validation: name, mobile (8+ digits), sport, coach ──
        const name = $('#t-name').value.trim();
        const nameAr = $('#t-name-ar').value.trim();
        if (!name && !nameAr) {
          toast('Name required (English or Arabic)', 'error');
          $('#t-name')?.focus();
          return;
        }
        if (!hasFirstAndLast(name) && !hasFirstAndLast(nameAr)) {
          toast('Please enter at least a first and last name', 'error');
          $('#t-name')?.focus();
          return;
        }
        const phoneInput = readPhoneInput('t-phone');
        if (!phoneInput.valid) {
          toast(phoneInput.error || 'Mobile number is invalid', 'error');
          document.getElementById('t-phone-digits')?.focus();
          return;
        }
        const sport = $('#t-sport').value;
        const coachId = parseInt($('#t-coach').value);
        if (!sport) { toast('Sport is required', 'error'); $('#t-sport')?.focus(); return; }
        if (!coachId) { toast('Coach is required (so admin knows who delivered the trial)', 'error'); $('#t-coach')?.focus(); return; }
        const sport2 = $('#t-sport2').value;
        const coachId2 = parseInt($('#t-coach2').value) || null;
        if (sport2 && sport2 === sport) { toast('Pick a different second sport', 'error'); $('#t-sport2')?.focus(); return; }
        if (sport2 && !coachId2) { toast('Pick a coach for the second sport', 'error'); $('#t-coach2')?.focus(); return; }
        const email = $('#t-email').value.trim();
        if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email)) {
          toast('Email format is invalid', 'error');
          $('#t-email')?.focus();
          return;
        }

        const data = {
          id: t.id,
          name: name || nameAr,
          nameArabic: nameAr || null,
          phone: phoneInput.phone,
          email: email || null,
          sport,
          coachId,
          sport2: sport2 || null,
          coachId2: sport2 ? coachId2 : null,
          trialDate: $('#t-date').value || TODAY,
          followUpDate: $('#t-fu').value || null,
          status: $('#t-status').value,
          source: $('#t-source').value || null,
          notes: $('#t-notes').value.trim() || null,
          createdAt: t.createdAt || new Date().toISOString(),
        };
        if (!state.trials) state.trials = [];
        if (isNew) state.trials.push(data);
        else {
          const idx = state.trials.findIndex(x => x.id === t.id);
          state.trials[idx] = data;
        }
        save();
        closeModal();
        render();
        toast(isNew ? 'Trial added' : 'Trial updated');
      }},
    ],
  });
}

window.deleteTrial = function(id) {
  if (!confirm('Delete this trial record?')) return;
  state.trials = (state.trials || []).filter(t => t.id !== id);
  save();
  render();
  toast('Trial deleted');
};

// Switch the role-preview. Pure view layer (no security) until online sign-in exists.
// ─── My Membership (member self-service, read-only, own data only) ──
// Student self-service freeze: pick days within the per-cycle allowance.
window.studentFreeze = function(memberId) {
  // Members may NOT freeze their own membership — only Admin/Reception can.
  // (Kept as a hard guard even though the self-service UI has been removed.)
  if (!canManageFreeze()) { toast(t('Please contact reception to freeze your membership.', 'يرجى التواصل مع الاستقبال لتجميد عضويتك.'), 'error'); return; }
  const m = state.members.find(x => x.id === memberId);
  if (!m) return;
  if (m.currentFreezeUntil && TODAY <= m.currentFreezeUntil) {
    toast(t('Your membership is already frozen.', 'عضويتك مجمّدة بالفعل.'), 'error');
    return;
  }
  if (memberStatus(m) !== 'Active') {
    toast(t('Only an active membership can be frozen.', 'يمكن تجميد العضوية النشطة فقط.'), 'error');
    return;
  }
  const fz = freezeAllowance(m);
  const maxReq = Math.min(fz.remainingDays, fz.perRequestCap);
  if (maxReq < 1) {
    toast(t('You have used your freeze allowance for this membership.', 'لقد استخدمت كامل رصيد التجميد لهذه العضوية.'), 'error');
    return;
  }
  const presets = [1, 3, 5, 7].filter(d => d <= maxReq);
  showModal({
    title: '❄️ ' + t('Freeze my membership', 'تجميد عضويتي'),
    body: `
      <div style="display:flex;flex-direction:column;gap:14px">
        <div class="text-mute" style="font-size:13px">${t('Freezing pauses your membership and pushes your expiry date forward by the same number of days, so you don\u2019t lose any paid days.', 'التجميد يوقف عضويتك مؤقتاً ويؤجّل تاريخ الانتهاء بنفس عدد الأيام، فلا تخسر أي يوم مدفوع.')}</div>
        <div style="background:var(--surface-2);border-radius:8px;padding:10px 12px;font-size:12px">
          <div style="display:flex;justify-content:space-between"><span class="text-mute">${t('Your allowance', 'رصيدك')}</span><span class="font-bold">${fz.allowanceDays} ${t('days', 'يوم')}</span></div>
          <div style="display:flex;justify-content:space-between"><span class="text-mute">${t('Already used', 'المستخدم')}</span><span class="font-bold">${fz.usedDays} ${t('days', 'يوم')}</span></div>
          <div style="display:flex;justify-content:space-between;border-top:1px solid var(--border);margin-top:5px;padding-top:5px"><span class="text-mute">${t('Remaining', 'المتبقي')}</span><span class="font-bold" style="color:var(--blue)">${fz.remainingDays} ${t('days', 'يوم')}</span></div>
        </div>
        <div>
          <label style="font-size:12px;font-weight:600;display:block;margin-bottom:8px">${t('How many days?', 'كم عدد الأيام؟')} <span class="text-mute" style="font-weight:400">(${t('max', 'حد أقصى')} ${maxReq})</span></label>
          <div id="sfz-presets" style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px">
            ${presets.map(d => `<button type="button" class="btn ghost sm sfz-preset" data-days="${d}" style="padding:6px 14px;font-size:12px">${d} ${t('day' + (d === 1 ? '' : 's'), 'يوم')}</button>`).join('')}
          </div>
          <input type="number" id="sfz-days" min="1" max="${maxReq}" value="${maxReq}" style="width:100%;padding:10px 14px;background:var(--surface-2);border:1px solid var(--border);border-radius:8px;color:var(--text)" />
        </div>
        <div id="sfz-preview" style="background:var(--surface-2);border-radius:8px;padding:12px;font-size:12px">
          <div style="display:flex;justify-content:space-between;margin-bottom:4px"><span class="text-mute">${t('Resume on', 'يُستأنف في')}</span><span class="font-bold" id="sfz-resume">${fmtDate(addDays(TODAY, maxReq))}</span></div>
          <div style="display:flex;justify-content:space-between"><span class="text-mute">${t('New expiry', 'الانتهاء الجديد')}</span><span class="font-bold" style="color:var(--blue)" id="sfz-newexp">${m.expiryDate ? fmtDate(addDays(m.expiryDate, maxReq)) : '—'}</span></div>
        </div>
        <div class="text-mute" style="font-size:11px">${t('Note: up to one week per request. Your allowance resets when you renew.', 'ملاحظة: حتى أسبوع واحد لكل طلب. يتجدد رصيدك عند التجديد.')}</div>
      </div>`,
    actions: [
      { label: t('Cancel', 'إلغاء'), onclick: closeModal },
      { label: '❄️ ' + t('Freeze', 'تجميد'), primary: true, onclick: () => {
        let days = parseInt(document.getElementById('sfz-days').value) || 0;
        days = Math.max(1, Math.min(days, maxReq));
        applyFreeze(m, days, 'Self-service freeze');
        if (typeof audit === 'function') audit('member.freeze', 'member:' + m.id, `student froze ${days}d`);
        save(); closeModal(); render();
        toast(t(`Membership frozen for ${days} day${days === 1 ? '' : 's'}`, `تم تجميد العضوية لمدة ${days} يوم`));
      }},
    ],
  });
  const sync = (val) => {
    const d = Math.max(1, Math.min(parseInt(val) || 1, maxReq));
    const r = document.getElementById('sfz-resume'); if (r) r.textContent = fmtDate(addDays(TODAY, d));
    const ne = document.getElementById('sfz-newexp'); if (ne && m.expiryDate) ne.textContent = fmtDate(addDays(m.expiryDate, d));
  };
  document.querySelectorAll('.sfz-preset').forEach(b => b.addEventListener('click', () => {
    const d = b.dataset.days; const inp = document.getElementById('sfz-days'); if (inp) inp.value = d; sync(d);
  }));
  const di = document.getElementById('sfz-days');
  if (di) di.addEventListener('input', () => sync(di.value));
};

PAGES.mymembership = (main) => {
  const meId = (typeof effectiveMemberId === 'function') ? effectiveMemberId() : (state.user && state.user.memberId);
  const m = (state.members || []).find(x => x.id === meId);
  if (!m) {
    main.innerHTML = `<div class="topbar"><div><h1>My Membership</h1></div></div>
      <div class="card"><p style="font-size:14px">We couldn't find a membership linked to this login. Please contact the club so they can link your account.</p></div>`;
    return;
  }
  const status = memberStatus(m);
  const statusColor = status === 'Active' ? 'var(--green)' : status === 'Frozen' ? 'var(--blue)' : status === 'Withdrawn' ? 'var(--text-mute)' : 'var(--red)';
  const dLeft = m.expiryDate ? daysUntil(m.expiryDate) : null;
  const enrolled = (m.enrollments && m.enrollments.length) ? m.enrollments
    : (m.subscriptions || []).map(s => ({ sport: s.activity, coachId: s.coachId, classes: s.totalClasses || 0, price: s.amountPaid || 0 }));
  const outstanding = (typeof memberOutstanding === 'function') ? memberOutstanding(m.id) : 0;
  const mo = TODAY.slice(0, 7);
  const SPORT_META = {
    'MMA': { e: '🥋', c: '#f59e0b' }, 'Boxing': { e: '🥊', c: '#ef4444' }, 'Kick Boxing': { e: '🥊', c: '#dc2626' },
    'Karate': { e: '🥋', c: '#84cc16' }, 'Taekwondo': { e: '🦵', c: '#6366f1' }, 'Gymnastic': { e: '🤸', c: '#10b981' },
    'Football': { e: '⚽', c: '#22c55e' }, 'Swimming': { e: '🏊', c: '#06b6d4' }, 'Zumba': { e: '💃', c: '#ec4899' },
    'Summer Camp': { e: '☀️', c: '#f59e0b' },
  };
  const sportMeta = sp => { const b = SPORT_META[baseSportName(sp)] || SPORT_META[sp] || { e: '🏅', c: '#5b8def' }; return { c: b.c, e: isPrivateSport(sp) ? b.e + '🔒' : b.e, priv: isPrivateSport(sp) }; };
  const sportsHtml = enrolled.length ? enrolled.map(e => {
    const dd = m.dailyAttendance?.[mo]?.[e.sport] || {};
    let y = 0; for (const k in dd) if (dd[k] === 'Y') y++;
    const planned = e.classes || 0;
    const pct = planned ? Math.min(100, Math.round(y / planned * 100)) : 0;
    const meta = sportMeta(e.sport);
    // Classes remaining across the whole subscription (lifetime), so the student
    // sees how many sessions they still have left — not just this month.
    const sub = (m.subscriptions || []).find(s => (s.activity || '') === e.sport && s.status !== 'Withdrawn');
    const remaining = sub ? Math.max(0, (parseInt(sub.totalClasses) || 0) - (parseInt(sub.attendedClasses) || 0)) : null;
    const remLow = remaining != null && remaining > 0 && remaining <= 2;
    return `<div style="border:1px solid var(--border);border-radius:16px;padding:18px;background:linear-gradient(135deg,${meta.c}14,transparent 70%)">
      <div style="display:flex;gap:16px;align-items:center;flex-wrap:wrap">
        <div style="width:60px;height:60px;border-radius:16px;background:${meta.c}26;display:flex;align-items:center;justify-content:center;font-size:32px;flex-shrink:0">${meta.e}</div>
        <div style="flex:1;min-width:140px">
          <div style="font-size:22px;font-weight:800;line-height:1.1">${escapeHtml(e.sport)}${meta.priv ? ` <span class="badge" style="background:#6b728022;color:#6b7280;font-size:10px;vertical-align:middle">🔒 ${t('Private', 'خاص')}</span>` : ''}</div>
          <div style="font-size:14px;color:var(--text-mute);margin-top:3px">👤 ${e.sport === SUMMER_CAMP ? t('No coach (camp)', 'بدون مدرب (معسكر)') : t('Coach', 'المدرب') + ': ' + escapeHtml(coachName(e.coachId))}</div>
        </div>
        <div style="display:flex;gap:22px;text-align:center">
          <div><div style="font-size:30px;font-weight:800;color:var(--blue);line-height:1">${planned}</div><div style="font-size:11px;color:var(--text-mute);text-transform:uppercase;letter-spacing:.5px;margin-top:2px">${t('Planned', 'المخطط')}</div></div>
          <div><div style="font-size:30px;font-weight:800;color:var(--green);line-height:1">${y}</div><div style="font-size:11px;color:var(--text-mute);text-transform:uppercase;letter-spacing:.5px;margin-top:2px">${t('Attended', 'الحضور')}</div></div>
          ${remaining != null ? `<div><div style="font-size:30px;font-weight:800;color:${remLow ? 'var(--red)' : 'var(--accent-2)'};line-height:1">${remaining}</div><div style="font-size:11px;color:var(--text-mute);text-transform:uppercase;letter-spacing:.5px;margin-top:2px">${t('Left', 'المتبقي')}</div></div>` : ''}
        </div>
      </div>
      ${remLow ? `<div style="margin-top:10px;font-size:12px;color:var(--red);font-weight:600">⚠ ${t('Only', 'فقط')} ${remaining} ${t('classes left — please renew soon to keep your spot.', 'حصص متبقية — جدّد قريباً للحفاظ على مكانك.')}</div>` : ''}
      <div style="margin-top:14px">
        <div style="display:flex;justify-content:space-between;font-size:12px;color:var(--text-mute);margin-bottom:5px"><span>${t('This month', 'هذا الشهر')}</span><span><b style="color:var(--text)">${y}</b> ${t('of', 'من')} ${planned} ${t('classes', 'حصة')} · ${pct}%</span></div>
        <div style="height:10px;background:var(--surface);border-radius:99px;overflow:hidden"><div style="height:100%;width:${pct}%;background:${meta.c};border-radius:99px;transition:width .4s"></div></div>
      </div>
    </div>`;
  }).join('') : `<div class="text-mute" style="font-size:14px;padding:14px;text-align:center">${t('No active sports on record.', 'لا توجد رياضات مسجّلة.')}</div>`;

  const isGirl = m.gender === 'Female';
  const nameColor = isGirl ? '#ec4899' : 'inherit';
  const ageTxt = (typeof memberAge === 'function' && m.birthdate && memberAge(m.birthdate) != null) ? `${memberAge(m.birthdate)} yrs · ` : '';

  // Attendance log with actual dates (newest first), across all months/sports.
  const attRows = [];
  const da = m.dailyAttendance || {};
  for (const mk of Object.keys(da)) {
    const moObj = da[mk]; if (!moObj) continue;
    const sample = Object.values(moObj)[0];
    if (sample && typeof sample === 'object') {
      for (const sp of Object.keys(moObj)) {
        const days = moObj[sp] || {};
        for (const d of Object.keys(days)) {
          const v = days[d];
          if (v === 'Y' || v === 'N') attRows.push({ date: `${mk}-${String(d).padStart(2, '0')}`, sport: sp, present: v === 'Y' });
        }
      }
    } else {
      for (const d of Object.keys(moObj)) {
        const v = moObj[d];
        if (v === 'Y' || v === 'N') attRows.push({ date: `${mk}-${String(d).padStart(2, '0')}`, sport: m.sport || '—', present: v === 'Y' });
      }
    }
  }
  attRows.sort((a, b) => b.date.localeCompare(a.date));
  const attendedTotal = attRows.filter(r => r.present).length;
  const attHtml = attRows.length
    ? attRows.map(r => `<tr style="border-top:1px solid var(--border)">
        <td style="padding:7px 8px">${fmtDate(r.date)}</td>
        <td style="padding:7px 8px">${escapeHtml(r.sport)}</td>
        <td style="padding:7px 8px;text-align:center">${r.present
          ? `<span class="badge active">${t('Present', 'حاضر')}</span>`
          : `<span class="badge expired">${t('Absent', 'غائب')}</span>`}</td>
      </tr>`).join('')
    : `<tr><td colspan="3" style="padding:10px" class="text-mute">${t('No attendance recorded yet.', 'لا يوجد حضور مسجّل بعد.')}</td></tr>`;

  // Membership history (subscriptions + legacy standalone renewals), newest first.
  const subRids = new Set((m.subscriptions || []).map(s => s._rid).filter(Boolean));
  const histSubs = [
    ...(m.subscriptions || []),
    ...((m.renewals || []).filter(r => !r._rid || !subRids.has(r._rid)).map(r => ({ ...r, manual: true }))),
  ].sort((a, b) => (b.start || '').localeCompare(a.start || ''));
  const histHtml = histSubs.length
    ? histSubs.map(s => `<tr style="border-top:1px solid var(--border)">
        <td style="padding:7px 8px">${escapeHtml(s.activity || '—')}</td>
        <td style="padding:7px 8px">${s.activity === SUMMER_CAMP ? '—' : escapeHtml(s.coach || (s.coachId != null ? coachName(s.coachId) : '—'))}</td>
        <td style="padding:7px 8px">${s.start ? fmtDate(s.start) : '—'}</td>
        <td style="padding:7px 8px">${s.end ? fmtDate(s.end) : '—'}</td>
        <td style="padding:7px 8px;text-align:center">${s.totalClasses || '—'}</td>
        <td style="padding:7px 8px;text-align:right">${s.amountPaid ? fmt(s.amountPaid) : '—'}</td>
      </tr>`).join('')
    : `<tr><td colspan="6" style="padding:10px" class="text-mute">${t('No subscription history on record.', 'لا يوجد سجل اشتراكات.')}</td></tr>`;

  // Advice from the member's coach(es).
  const myAdvice = (state.advices || []).filter(a => a.memberId === m.id).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  const adviceReplies = myAdvice.reduce((n, a) => n + ((a.comments || []).length), 0);
  const adviceHtml = myAdvice.length
    ? myAdvice.map(a => {
        const cms = (a.comments || []);
        const cmHtml = cms.length ? `<div style="margin-top:8px;padding-top:8px;border-top:1px dashed var(--border);display:flex;flex-direction:column;gap:6px">${cms.map(c => `<div style="font-size:12px"><b>${escapeHtml(c.name || (c.by === 'student' ? t('You', 'أنت') : t('Coach', 'المدرب')))}:</b> ${escapeHtml(c.text || '')} <span class="text-mute" style="font-size:10px">${c.date ? fmtDate(c.date) : ''}</span></div>`).join('')}</div>` : '';
        return `<div style="padding:10px 12px;border:1px solid var(--border);border-radius:8px;margin-bottom:8px;background:var(--surface-2)">
          <div style="font-size:11px;color:var(--text-mute);margin-bottom:3px">${escapeHtml(coachName(a.coachId) || t('Coach', 'المدرب'))} · ${a.date ? fmtDate(a.date) : ''}</div>
          <div style="font-size:13px;white-space:pre-wrap">${escapeHtml(a.text || '')}</div>
          ${cmHtml}
        </div>`;
      }).join('')
    : `<div class="text-mute" style="font-size:12px;padding:6px 0">${t('No advice from your coach yet.', 'لا توجد نصائح من مدربك بعد.')}</div>`;

  // Next class from the weekly schedule (their enrolled sports).
  const mySports = enrolled.map(e => e.sport).filter(Boolean);
  const DAY_TO_WD = { sat: 6, sun: 0, mon: 1, tue: 2, wed: 3, thu: 4, fri: 5 };
  const DAY_LABEL_EN = { sat: 'Saturday', sun: 'Sunday', mon: 'Monday', tue: 'Tuesday', wed: 'Wednesday', thu: 'Thursday', fri: 'Friday' };
  const DAY_LABEL_AR = { sat: 'السبت', sun: 'الأحد', mon: 'الإثنين', tue: 'الثلاثاء', wed: 'الأربعاء', thu: 'الخميس', fri: 'الجمعة' };
  const SLOT_LABEL = { 15: '3–4 PM', 16: '4–5 PM', 17: '5–6 PM', 18: '6–7 PM', 19: '7–8 PM', 20: '8–9 PM' };
  let nextClass = null;
  {
    const now = new Date(); const nowWd = now.getDay(); const nowHour = now.getHours();
    for (const c of (state.schedule || [])) {
      if (!mySports.includes(c.sport)) continue;
      const wd = DAY_TO_WD[c.day]; if (wd == null) continue;
      const hour = typeof c.slot === 'number' ? c.slot : parseInt(c.slot);
      let daysAhead = (wd - nowWd + 7) % 7;
      if (daysAhead === 0 && hour <= nowHour) daysAhead = 7;
      const score = daysAhead * 24 + hour;
      if (!nextClass || score < nextClass.score) nextClass = { score, daysAhead, hour, c };
    }
  }
  const nextClassHtml = nextClass ? (() => {
    const c = nextClass.c;
    const whenWord = nextClass.daysAhead === 0 ? t('Today', 'اليوم') : nextClass.daysAhead === 1 ? t('Tomorrow', 'غداً') : t(DAY_LABEL_EN[c.day], DAY_LABEL_AR[c.day]);
    const slotLabel = SLOT_LABEL[nextClass.hour] || (nextClass.hour + ':00');
    return `<div style="display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap">
      <div><div style="font-size:20px;font-weight:700">${escapeHtml(c.sport)}</div>
        <div class="text-mute" style="font-size:12px">${c.sport === SUMMER_CAMP ? '' : escapeHtml(coachName(c.coachId))}</div></div>
      <div style="text-align:right"><div style="font-size:16px;font-weight:700;color:var(--blue)">${whenWord} · ${slotLabel}</div>
        <div class="text-mute" style="font-size:11px">${t('See the Schedule tab for the full week', 'راجع تبويب الجدول للأسبوع كامل')}</div></div>
    </div>`;
  })() : `<div class="text-mute" style="font-size:13px">${t('No upcoming class found in the schedule for your sports.', 'لا توجد حصة قادمة في الجدول لرياضاتك.')}</div>`;

  // Payment history — this member's own invoices, newest first.
  const myInvoices = (state.invoices || []).filter(inv => inv.customerId === m.id)
    .sort((a, b) => (b.date || b.month || '').localeCompare(a.date || a.month || ''));
  const payHtml = myInvoices.length ? myInvoices.map(inv => {
    const paid = invoicePaid(inv);
    const due = invoiceBalance(inv);   // canonical (Σ lines − paid) — member sees the SAME due as reception
    return `<tr style="border-top:1px solid var(--border)">
      <td style="padding:7px 8px">${inv.date ? fmtDate(inv.date) : (inv.month || '—')}</td>
      <td style="padding:7px 8px">${escapeHtml(inv.ref || '—')}</td>
      <td style="padding:7px 8px">${escapeHtml(inv.sport || inv.description || inv.category || '—')}</td>
      <td style="padding:7px 8px;text-align:right">${fmt(inv.amount || 0)}</td>
      <td style="padding:7px 8px;text-align:right;color:var(--green)">${fmt(paid)}</td>
      <td style="padding:7px 8px;text-align:right;${due > 0 ? 'color:var(--red);font-weight:600' : ''}">${due > 0 ? fmt(due) : '—'}</td>
    </tr>`;
  }).join('') : `<tr><td colspan="6" style="padding:10px" class="text-mute">${t('No payments on record yet.', 'لا توجد مدفوعات مسجّلة بعد.')}</td></tr>`;

  // Self-service freeze card.
  const isFrozen = m.currentFreezeUntil && TODAY <= m.currentFreezeUntil;
  const fz = freezeAllowance(m);
  let freezeCardHtml = '';
  if (isFrozen) {
    freezeCardHtml = `<div class="card" style="margin-bottom:16px;border:1px solid rgba(91,141,239,.4)">
      <div style="display:flex;align-items:center;gap:12px">
        <div style="font-size:28px">❄️</div>
        <div><div style="font-weight:700;font-size:15px">${t('Your membership is frozen', 'عضويتك مجمّدة')}</div>
          <div class="text-mute" style="font-size:12px">${t('Resumes on', 'يُستأنف في')} <b>${fmtDate(m.currentFreezeUntil)}</b> · ${t('your expiry was extended', 'تم تمديد تاريخ انتهائك')}</div></div>
      </div></div>`;
  } else if (memberStatus(m) === 'Active') {
    // Members can no longer freeze themselves — freezes are handled by reception
    // (Admin/Reception only). Show an informational card instead of a button.
    freezeCardHtml = `<div class="card" style="margin-bottom:16px">
      <div style="display:flex;align-items:center;gap:12px;flex-wrap:wrap">
        <div style="font-size:28px">❄️</div>
        <div><div class="card-title">${t('Need to pause your membership?', 'تحتاج إلى إيقاف عضويتك مؤقتاً؟')}</div>
          <div class="card-subtitle">${t('Please contact reception to freeze your membership. Your allowance is', 'يرجى التواصل مع الاستقبال لتجميد عضويتك. رصيدك هو')} <b>${fz.remainingDays}</b> ${t('of', 'من')} ${fz.allowanceDays} ${t('days this cycle', 'يوم هذه الدورة')}.</div>
        </div>
      </div></div>`;
  }

  main.innerHTML = `
    <div class="topbar"><div><h1 style="color:${nameColor}">${escapeHtml(m.name)}</h1><div class="subtitle">${ageTxt}${m.gender ? escapeHtml(t(m.gender, m.gender === 'Female' ? 'أنثى' : 'ذكر')) + ' · ' : ''}${t('My Membership', 'عضويتي')}${isRealPhone && isRealPhone(m.phone) ? ' · ' + escapeHtml(m.phone) : ''}</div></div>
      <div class="topbar-actions">
        <button class="btn ghost" onclick="window._myScheduleICS(${m.id})" title="${t('Add your classes to your phone calendar', 'أضف حصصك إلى تقويم هاتفك')}">📅 ${t('Add to calendar', 'إضافة للتقويم')}</button>
        <button class="btn ghost" onclick="window._attPdfSubscription(${m.id})" title="${t('Download your attendance sheet', 'حمّل ورقة حضورك')}">📄 ${t('Attendance report', 'تقرير الحضور')}</button>
        <button class="btn ghost" onclick="promptPasswordChange(false)">🔐 ${t('Change password', 'تغيير كلمة المرور')}</button>
      </div>
    </div>
    ${(status === 'Expired' || (dLeft != null && dLeft >= 0 && dLeft <= 7)) ? `
    <div class="card" style="margin-bottom:16px;border:1px solid ${status === 'Expired' ? 'rgba(239,68,68,.5)' : 'rgba(245,158,11,.5)'};background:${status === 'Expired' ? 'rgba(239,68,68,.08)' : 'rgba(245,158,11,.08)'}">
      <div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap">
        <div style="font-size:30px">${status === 'Expired' ? '⛔' : '⏰'}</div>
        <div style="flex:1;min-width:160px">
          <div style="font-weight:800;font-size:16px">${status === 'Expired' ? t('Your membership has expired', 'انتهت عضويتك') : t('Your membership is expiring soon', 'عضويتك تنتهي قريباً')}</div>
          <div class="text-mute" style="font-size:13px">${status === 'Expired' ? t('Please renew at reception to keep attending classes.', 'يرجى التجديد في الاستقبال للاستمرار في حضور الحصص.') : t(`${dLeft} day${dLeft === 1 ? '' : 's'} left — renew to avoid any interruption.`, `باقٍ ${dLeft} يوم — جدّد لتجنّب أي انقطاع.`)}</div>
        </div>
      </div>
    </div>` : ''}
    <div class="kpi-grid" style="grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:16px">
      <div class="kpi"><div class="kpi-label">${t('Status', 'الحالة')}</div><div class="kpi-value" style="color:${statusColor}">${t(status, { Active: 'نشط', Expired: 'منتهٍ', Frozen: 'مجمّد', Withdrawn: 'منسحب', Completed: 'مكتمل' }[status] || status)}</div><div class="kpi-sub">${m.level || ''}</div></div>
      <div class="kpi"><div class="kpi-label">${t('Membership expiry', 'انتهاء العضوية')}</div><div class="kpi-value" style="font-size:20px">${m.expiryDate ? fmtDate(m.expiryDate) : '—'}</div><div class="kpi-sub">${dLeft == null ? '' : dLeft < 0 ? t(`expired ${-dLeft}d ago`, `انتهت قبل ${-dLeft} يوم`) : t(`${dLeft} day${dLeft === 1 ? '' : 's'} left`, `باقٍ ${dLeft} يوم`)}</div></div>
      <div class="kpi ${outstanding > 0 ? 'red' : 'green'}"><div class="kpi-label">${t('Balance due', 'الرصيد المستحق')}</div><div class="kpi-value">${fmt(outstanding)}</div><div class="kpi-sub">${outstanding > 0 ? t('please settle at reception', 'يرجى السداد في الاستقبال') : t('all paid', 'مدفوع بالكامل')}</div></div>
    </div>
    <div class="card" style="margin-bottom:16px;border:1px solid rgba(91,141,239,.35);background:linear-gradient(135deg,rgba(91,141,239,.10),rgba(91,141,239,.02))">
      <div class="card-header"><div><div class="card-title">⏱ ${t('Next class', 'حصتك القادمة')}</div></div></div>
      ${nextClassHtml}
    </div>
    ${freezeCardHtml}
    <div class="card">
      <div class="card-header"><div><div class="card-title" style="font-size:18px">🥋 ${t('My sports', 'رياضاتي')}</div><div class="card-subtitle">${t('Your enrolled activities and attendance this month', 'أنشطتك المسجّلة وحضورك هذا الشهر')}</div></div></div>
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(340px,1fr));gap:14px">${sportsHtml}</div>
      <div class="text-mute mt-3" style="font-size:12px;margin-top:14px">${t('See the <b>Schedule</b> tab for class times. For changes to your plan, please contact the club.', 'راجع تبويب <b>الجدول</b> لمواعيد الحصص. لأي تعديل على اشتراكك، يرجى التواصل مع النادي.')}</div>
    </div>

    <div class="card" style="margin-top:14px">
      <div class="card-header"><div><div class="card-title">💬 ${t('Advice from your coach', 'نصائح من مدربك')}</div><div class="card-subtitle">${t('Personal notes and tips from your coach', 'ملاحظات ونصائح شخصية من مدربك')}${adviceReplies ? ' · ' + adviceReplies + ' ' + t('replies', 'رد') : ''}</div></div>
        ${myAdvice.length ? `<button class="btn ghost sm" onclick="navigate('advice')">💬 ${t('Reply', 'رد')}</button>` : ''}
      </div>
      ${adviceHtml}
    </div>

    <div class="card" style="margin-top:14px">
      <div class="card-header"><div><div class="card-title">${t('Attendance log', 'سجل الحضور')}</div><div class="card-subtitle">${t(`${attendedTotal} class${attendedTotal === 1 ? '' : 'es'} attended · most recent first`, `${attendedTotal} حصة بالحضور · الأحدث أولاً`)}</div></div></div>
      <div style="max-height:320px;overflow:auto;border:1px solid var(--border);border-radius:8px">
        <table style="width:100%;border-collapse:collapse;font-size:13px">
          <thead style="position:sticky;top:0;background:var(--surface)"><tr style="text-align:left;color:var(--text-mute);font-size:11px"><th style="padding:7px 8px">${t('Date', 'التاريخ')}</th><th style="padding:7px 8px">${t('Sport', 'الرياضة')}</th><th style="padding:7px 8px;text-align:center">${t('Status', 'الحالة')}</th></tr></thead>
          <tbody>${attHtml}</tbody>
        </table>
      </div>
    </div>

    <div class="card" style="margin-top:14px">
      <div class="card-header"><div><div class="card-title">${t('Membership history', 'سجل العضوية')}</div><div class="card-subtitle">${t('Your subscriptions and renewals', 'اشتراكاتك وتجديداتك')}</div></div></div>
      <div style="max-height:320px;overflow:auto;border:1px solid var(--border);border-radius:8px">
        <table style="width:100%;border-collapse:collapse;font-size:13px">
          <thead style="position:sticky;top:0;background:var(--surface)"><tr style="text-align:left;color:var(--text-mute);font-size:11px"><th style="padding:7px 8px">${t('Sport', 'الرياضة')}</th><th style="padding:7px 8px">${t('Coach', 'المدرب')}</th><th style="padding:7px 8px">${t('Start', 'البداية')}</th><th style="padding:7px 8px">${t('End', 'النهاية')}</th><th style="padding:7px 8px;text-align:center">${t('Classes', 'الحصص')}</th><th style="padding:7px 8px;text-align:right">${t('Paid', 'المدفوع')}</th></tr></thead>
          <tbody>${histHtml}</tbody>
        </table>
      </div>
    </div>

    <div class="card" style="margin-top:14px">
      <div class="card-header"><div><div class="card-title">${t('Payment history', 'سجل المدفوعات')}</div><div class="card-subtitle">${t('Your invoices and payments', 'فواتيرك ومدفوعاتك')}</div></div></div>
      <div style="max-height:320px;overflow:auto;border:1px solid var(--border);border-radius:8px">
        <table style="width:100%;border-collapse:collapse;font-size:13px">
          <thead style="position:sticky;top:0;background:var(--surface)"><tr style="text-align:left;color:var(--text-mute);font-size:11px"><th style="padding:7px 8px">${t('Date', 'التاريخ')}</th><th style="padding:7px 8px">${t('Ref', 'المرجع')}</th><th style="padding:7px 8px">${t('For', 'البيان')}</th><th style="padding:7px 8px;text-align:right">${t('Amount', 'المبلغ')}</th><th style="padding:7px 8px;text-align:right">${t('Paid', 'المدفوع')}</th><th style="padding:7px 8px;text-align:right">${t('Due', 'المستحق')}</th></tr></thead>
          <tbody>${payHtml}</tbody>
        </table>
      </div>
    </div>`;
};

// ─── Coach Advice (coach writes → student reads) ───────────────
// ─── Zero-write exports (calendar / sign-in sheet / roster CSV) ─────────────
// Student: download enrolled classes as an .ics calendar file (weekly recurring).
window._myScheduleICS = function(memberId) {
  const m = state.members.find(x => x.id === memberId); if (!m) return;
  const sports = ((m.enrollments && m.enrollments.length) ? m.enrollments : []).map(e => e.sport).filter(Boolean);
  const W = { sat: 6, sun: 0, mon: 1, tue: 2, wed: 3, thu: 4, fri: 5 };
  const rows = (state.schedule || []).filter(c => sports.includes(c.sport));
  if (!rows.length) { toast(t('No classes found in the schedule for your sports.', 'لا توجد حصص في الجدول لرياضاتك.'), 'error'); return; }
  const pad = n => String(n).padStart(2, '0');
  const now = new Date();
  const nextDateFor = (wd, hour) => {
    const d = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    let add = (wd - d.getDay() + 7) % 7;
    if (add === 0 && hour <= now.getHours()) add = 7;
    d.setDate(d.getDate() + add);
    return d;
  };
  const fmtDT = (d, hour) => `${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}T${pad(hour)}0000`;
  const lines = ['BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//Black Stars CRM//EN', 'CALSCALE:GREGORIAN'];
  rows.forEach((c, i) => {
    const wd = W[c.day]; if (wd == null) return;
    const hour = typeof c.slot === 'number' ? c.slot : parseInt(c.slot);
    const d = nextDateFor(wd, hour);
    lines.push('BEGIN:VEVENT',
      `UID:bs-${m.id}-${c.id || i}@blackstars`,
      `DTSTART:${fmtDT(d, hour)}`,
      `DTEND:${fmtDT(d, hour + 1)}`,
      'RRULE:FREQ=WEEKLY',
      `SUMMARY:${c.sport}${c.sport !== SUMMER_CAMP ? ' - ' + (coachName(c.coachId) || '') : ''}`,
      'LOCATION:Black Stars Sports Club',
      'END:VEVENT');
  });
  lines.push('END:VCALENDAR');
  downloadFile(`${m.name.replace(/[^a-z0-9]+/gi, '_')}_classes.ics`, lines.join('\r\n'), 'text/calendar');
  toast(t('Calendar file downloaded', 'تم تنزيل ملف التقويم'));
};

// Coach: printable BLANK sign-in sheet — students × days of the current month.
window._coachSignInSheet = function(coachId) {
  const coach = state.coaches.find(c => c.id === coachId);
  if (!coach) { toast('Coach not found', 'error'); return; }
  const students = coachStudents(coach.id).filter(s => !s.deleted).sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  if (!students.length) { toast(t('No students to list.', 'لا يوجد طلاب لعرضهم.'), 'error'); return; }
  const mo = TODAY.slice(0, 7); const days = daysInMonth(mo);
  const dayHeads = Array.from({ length: days }, (_, i) => `<th style="border:1px solid #ccc;padding:2px;font-size:9px;width:20px">${i + 1}</th>`).join('');
  const body = students.map((s, idx) => `<tr>
    <td style="border:1px solid #ccc;padding:4px 6px;font-size:11px">${idx + 1}. ${escapeHtml(s.name)}</td>
    <td style="border:1px solid #ccc;padding:4px 6px;font-size:10px;color:#666">${escapeHtml((s.sports || []).join(', '))}</td>
    ${Array.from({ length: days }, () => '<td style="border:1px solid #ccc;height:22px"></td>').join('')}
  </tr>`).join('');
  const win = window.open('', '_blank');
  if (!win) { toast('Pop-up blocked — allow pop-ups to print', 'error'); return; }
  win.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>signin_sheet</title>
    <style>@page{size:A4 landscape;margin:10mm}body{font-family:Arial,sans-serif;padding:18px;color:#111}
    h1{font-size:16px;margin:0 0 2px}.sub{color:#666;font-size:12px;margin-bottom:12px}
    table{border-collapse:collapse;width:100%}th{background:#fafafa}</style></head><body>
    <h1>Black Stars Sports Club — Sign-in Sheet</h1>
    <div class="sub">Coach ${escapeHtml(coach.name)} · ${fmtMonth(mo)} · ${students.length} students</div>
    <table><thead><tr><th style="border:1px solid #ccc;padding:4px 6px;font-size:10px;text-align:left">Student</th><th style="border:1px solid #ccc;padding:4px 6px;font-size:10px;text-align:left">Sport</th>${dayHeads}</tr></thead>
    <tbody>${body}</tbody></table>
    <div style="margin-top:14px;font-size:10px;color:#999">Tick attendance per day, then enter into the system later. Generated ${fmtDate(TODAY)}.</div>
    <script>window.onload=()=>window.print();<\/script></body></html>`);
  win.document.close();
};

// Coach: export own roster (with this-month attendance + expiry) as CSV.
window._coachRosterCsv = function(coachId) {
  const coach = state.coaches.find(c => c.id === coachId);
  if (!coach) { toast('Coach not found', 'error'); return; }
  const students = coachStudents(coach.id).filter(s => !s.deleted).sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  if (!students.length) { toast(t('No students to export.', 'لا يوجد طلاب للتصدير.'), 'error'); return; }
  const mo = TODAY.slice(0, 7);
  const esc = v => `"${String(v == null ? '' : v).replace(/"/g, '""')}"`;
  const header = ['Student', 'Sports', 'Mobile', 'Attended', 'Marked', 'Rate%', 'Status', 'Expiry'];
  const lines = [header.join(',')];
  for (const s of students) {
    const mem = state.members.find(x => x.id === s.id) || {};
    let y = 0, n = 0;
    for (const sp of (s.sports || [])) { const dd = (mem.dailyAttendance?.[mo] || {})[sp] || {}; for (const d in dd) { if (dd[d] === 'Y') y++; else if (dd[d] === 'N') n++; } }
    const marked = y + n; const rate = marked ? Math.round(y / marked * 100) : '';
    lines.push([s.name, (s.sports || []).join(' / '), mem.phone || '', y, marked, rate,
      (typeof memberStatus === 'function' ? memberStatus(mem) : ''), mem.expiryDate || ''].map(esc).join(','));
  }
  downloadFile(`${coach.name.replace(/[^a-z0-9]+/gi, '_')}_roster_${mo}.csv`, lines.join('\n'), 'text/csv');
  toast(t('Roster exported', 'تم تصدير القائمة'));
};

// ─── Coach home: my students · my salary (this + previous months) · advice ──
PAGES.coachhome = (main) => {
  const coachId = (typeof effectiveCoachId === 'function') ? effectiveCoachId() : null;
  const coach = state.coaches.find(c => c.id === coachId);
  if (!coach) {
    main.innerHTML = `<div class="topbar"><div><h1>🧑‍🏫 ${t('My Dashboard', 'لوحة المدرب')}</h1></div></div>
      <div class="card"><div class="text-mute" style="font-size:13px">${t('No coach profile is linked to this account yet. Ask an admin to map your account to a coach in Users & Roles.', 'لا يوجد ملف مدرب مرتبط بهذا الحساب بعد. اطلب من المشرف ربط حسابك بمدرب من المستخدمين والصلاحيات.')}</div></div>`;
    return;
  }

  // Students (invoice-based, current roster)
  const students = coachStudents(coach.id).filter(s => !s.deleted).slice().sort((a, b) => (a.name || '').localeCompare(b.name || ''));

  // Salary: this month + previous months that have data, newest first.
  const months = availableMonths({ includeFuture: false }).slice().sort().reverse();
  const thisMonth = months[0] || null;

  // Per-student stats for THIS coach: attendance this month + last attended +
  // membership expiry — so the roster is an action list, not just names.
  const roster = students.map(s => {
    const mem = state.members.find(x => x.id === s.id) || {};
    const da = mem.dailyAttendance || {};
    let y = 0, n = 0;
    for (const sp of (s.sports || [])) {
      const dd = (da[thisMonth] || {})[sp] || {};
      for (const d in dd) { if (dd[d] === 'Y') y++; else if (dd[d] === 'N') n++; }
    }
    let last = null;
    for (const mk of Object.keys(da)) {
      for (const sp of (s.sports || [])) {
        const dd = (da[mk] || {})[sp] || {};
        for (const d of Object.keys(dd)) { if (dd[d] === 'Y') { const dt = mk + '-' + String(d).padStart(2, '0'); if (!last || dt > last) last = dt; } }
      }
    }
    const marked = y + n;
    const rate = marked ? Math.round(y / marked * 100) : null;
    const atRisk = marked >= 2 && rate < 50;
    const status = (typeof memberStatus === 'function') ? memberStatus(mem) : (mem.status || '');
    const dLeft = mem.expiryDate ? daysUntil(mem.expiryDate) : null;
    return { ...s, mem, y, n, marked, rate, last, atRisk, status, dLeft };
  });
  // Students of this coach needing a renewal nudge (expired or ≤14 days left).
  const expiringRoster = roster
    .filter(r => r.status === 'Expired' || (r.dLeft != null && r.dLeft <= 14))
    .sort((a, b) => (a.dLeft == null ? 1 : a.dLeft) - (b.dLeft == null ? 1 : b.dLeft));
  const earnRows = months.map(mo => ({ mo, e: coachEarnings(coach, mo) }))
    .filter(r => r.e.total > 0 || r.e.revenue > 0 || r.mo === thisMonth);
  const cur = thisMonth ? coachEarnings(coach, thisMonth) : { fixed: coach.fixedSalary || 0, commission: 0, total: coach.fixedSalary || 0, commissionBase: 0, rate: coach.rate || 0, revenue: 0 };

  // Advice this coach has sent (with any replies)
  const myAdvice = (state.advices || []).filter(a => a.coachId === coach.id).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  const replies = myAdvice.reduce((n, a) => n + (a.comments ? a.comments.length : 0), 0);

  // Next upcoming class for this coach (from the weekly schedule).
  const DAY_JS = { sun: 0, mon: 1, tue: 2, wed: 3, thu: 4, fri: 5, sat: 6 };
  const DAY_LABEL = { sat: t('Saturday', 'السبت'), sun: t('Sunday', 'الأحد'), mon: t('Monday', 'الإثنين'), tue: t('Tuesday', 'الثلاثاء'), wed: t('Wednesday', 'الأربعاء'), thu: t('Thursday', 'الخميس'), fri: t('Friday', 'الجمعة') };
  const SLOT_LABEL = { 15: '3:00 PM', 16: '4:00 PM', 17: '5:00 PM', 18: '6:00 PM', 19: '7:00 PM', 20: '8:00 PM' };
  function nextClassFor(cid) {
    const mine = (state.schedule || []).filter(c => c.coachId === cid);
    if (!mine.length) return null;
    const now = new Date();
    const nowDay = now.getDay();
    const nowHour = now.getHours() + now.getMinutes() / 60;
    let best = null;
    for (const c of mine) {
      const cd = DAY_JS[c.day]; if (cd == null) continue;
      let delta = (cd - nowDay + 7) % 7;
      if (delta === 0 && c.slot <= nowHour) delta = 7;  // already passed today → next week
      const score = delta * 24 + (c.slot || 0);
      if (!best || score < best.score) best = { c, delta, score };
    }
    return best;
  }
  const nx = nextClassFor(coach.id);
  // Today's classes for this coach + who's expected (active students enrolled in
  // that sport with this coach). View-only — reception/admin still mark attendance.
  const JS_TO_KEY = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];
  const todayKey = JS_TO_KEY[new Date().getDay()];
  const todayClasses = (state.schedule || [])
    .filter(c => c.coachId === coach.id && c.day === todayKey)
    .sort((a, b) => (a.slot || 0) - (b.slot || 0))
    .map(c => {
      const expected = roster.filter(r => (r.sports || []).includes(c.sport) && r.status !== 'Expired');
      return { c, expected };
    });
  const todayCard = `
    <div class="card" style="margin-bottom:16px">
      <div class="card-header"><div><div class="card-title">📅 ${t('Today\u2019s classes', 'حصص اليوم')} (${todayClasses.length})</div><div class="card-subtitle">${DAY_LABEL[todayKey]} · ${t('who\u2019s expected to attend', 'من المتوقع حضوره')}</div></div></div>
      ${todayClasses.length ? todayClasses.map(({ c, expected }) => `
        <div style="border:1px solid var(--border);border-radius:8px;padding:10px 12px;margin-bottom:8px">
          <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap">
            <div style="font-weight:700">${escapeHtml(c.sport)} <span class="text-mute" style="font-weight:400;font-size:12px">· ${SLOT_LABEL[c.slot] || ''}</span></div>
            <span class="badge" style="background:rgba(91,141,239,.12);color:var(--blue)">${expected.length} ${t('expected', 'متوقع')}</span>
          </div>
          ${expected.length ? `<div style="margin-top:6px;font-size:12px" class="text-mute">${expected.map(r => escapeHtml(r.name)).join(' · ')}</div>` : `<div style="margin-top:6px;font-size:12px" class="text-mute">${t('No active students enrolled in this class yet.', 'لا يوجد طلاب نشطون في هذه الحصة بعد.')}</div>`}
        </div>`).join('') : `<div class="text-mute" style="font-size:13px">${t('You have no classes scheduled for today.', 'لا توجد حصص مجدولة لك اليوم.')}</div>`}
    </div>`;
  const nxWhen = nx ? (nx.delta === 0 ? t('Today', 'اليوم') : nx.delta === 1 ? t('Tomorrow', 'غداً') : t('in', 'خلال') + ' ' + nx.delta + ' ' + t('days', 'أيام')) : '';
  const nextClassCard = nx ? `
    <div class="card" style="margin-bottom:16px;border:1px solid rgba(91,141,239,.35);background:linear-gradient(135deg,rgba(91,141,239,.12),rgba(91,141,239,.02))">
      <div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap">
        <div style="font-size:30px">⏰</div>
        <div style="flex:1;min-width:160px">
          <div class="text-mute" style="font-size:11px;text-transform:uppercase;letter-spacing:.5px">${t('Your next class', 'حصتك القادمة')}</div>
          <div style="font-size:18px;font-weight:800">${escapeHtml(nx.c.sport)} · ${DAY_LABEL[nx.c.day]} ${SLOT_LABEL[nx.c.slot] || ''}</div>
        </div>
        <div style="background:var(--blue);color:#fff;border-radius:20px;padding:6px 16px;font-weight:700;font-size:13px">${nxWhen}</div>
      </div>
    </div>` : '';

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>🧑‍🏫 ${escapeHtml(coach.name)}</h1>
        <div class="subtitle">${t('Your students, salary and advice', 'طلابك وراتبك ونصائحك')} · ${coach.rate ? coach.rate + '% ' + t('commission', 'عمولة') : ''}${coach.fixedSalary ? (coach.rate ? ' · ' : '') + t('Fixed', 'ثابت') + ' ' + fmt(coach.fixedSalary) : ''}</div>
      </div>
      <div class="topbar-actions">
        <button class="btn ghost" onclick="window._coachSignInSheet(${coach.id})" title="${t('Printable blank attendance sheet', 'ورقة حضور فارغة للطباعة')}">🖨 ${t('Sign-in sheet', 'ورقة الحضور')}</button>
        <button class="btn ghost" onclick="window._coachRosterCsv(${coach.id})" title="${t('Export your roster as CSV', 'تصدير قائمتك CSV')}">⬇ ${t('Roster CSV', 'تصدير القائمة')}</button>
      </div>
    </div>

    ${nextClassCard}

    ${todayCard}

    <div class="kpi-grid" style="margin-bottom:16px">
      <div class="kpi">
        <div class="kpi-icon">👥</div>
        <div class="kpi-label">${t('My Students', 'طلابي')}</div>
        <div class="kpi-value num">${students.length}</div>
        <div class="kpi-delta flat">${t('active roster', 'القائمة الحالية')}</div>
      </div>
      <div class="kpi">
        <div class="kpi-icon">💰</div>
        <div class="kpi-label">${t('This month salary', 'راتب هذا الشهر')}${thisMonth ? ' (' + fmtMonth(thisMonth).split(' ')[0] + ')' : ''}</div>
        <div class="kpi-value num">${fmt(cur.total)}</div>
        <div class="kpi-delta flat">${t('Fixed', 'ثابت')} ${fmt(cur.fixed)} + ${t('commission', 'عمولة')} ${fmt(cur.commission)}</div>
      </div>
      <div class="kpi">
        <div class="kpi-icon">💬</div>
        <div class="kpi-label">${t('Advice sent', 'نصائح مُرسلة')}</div>
        <div class="kpi-value num">${myAdvice.length}</div>
        <div class="kpi-delta flat">${replies} ${t('replies from students', 'رد من الطلاب')}</div>
      </div>
    </div>

    <div class="card" style="margin-bottom:16px">
      <div class="card-header"><div><div class="card-title">👥 ${t('My Students', 'طلابي')} (${students.length})</div><div class="card-subtitle">${t('Attendance this month · ⚠ = low attendance', 'الحضور هذا الشهر · ⚠ = حضور منخفض')}</div></div></div>
      ${roster.length ? `<div style="overflow:auto"><table class="data-table" style="width:100%"><thead><tr>
          <th>${t('Student', 'الطالب')}</th><th>${t('Sports', 'الرياضات')}</th>
          <th class="text-right">${t('This month', 'هذا الشهر')}</th><th class="text-right">${t('Rate', 'النسبة')}</th><th>${t('Last attended', 'آخر حضور')}</th>
        </tr></thead><tbody>
        ${roster.map(r => `<tr${r.atRisk ? ' style="background:rgba(239,68,68,.06)"' : ''}>
          <td>${escapeHtml(r.name)}${r.atRisk ? ` <span class="badge expired" title="${t('Low attendance', 'حضور منخفض')}">⚠ ${t('at risk', 'متعثّر')}</span>` : ''}</td>
          <td class="text-mute">${escapeHtml((r.sports || []).join(', ') || '—')}</td>
          <td class="text-right num">${r.marked ? r.y + '/' + r.marked : '—'}</td>
          <td class="text-right num" style="${r.rate == null ? '' : r.rate >= 75 ? 'color:var(--green)' : r.rate >= 50 ? 'color:var(--accent-2)' : 'color:var(--red);font-weight:600'}">${r.rate == null ? '—' : r.rate + '%'}</td>
          <td class="text-mute">${r.last ? fmtDate(r.last) : '—'}</td>
        </tr>`).join('')}
        </tbody></table></div>` : `<div class="text-mute" style="font-size:13px">${t('No students assigned to you yet.', 'لا يوجد طلاب مسندون إليك بعد.')}</div>`}
    </div>

    <div class="card" style="margin-bottom:16px;${expiringRoster.length ? 'border:1px solid rgba(242,163,60,.4)' : ''}">
      <div class="card-header"><div><div class="card-title">⏰ ${t('My students expiring', 'طلابي قرب الانتهاء')} (${expiringRoster.length})</div><div class="card-subtitle">${t('Expired or expiring within 14 days — give them a nudge', 'منتهية أو تنتهي خلال 14 يوماً — ذكّرهم')}</div></div></div>
      ${expiringRoster.length ? `<div style="overflow:auto"><table class="data-table" style="width:100%"><thead><tr>
          <th>${t('Student', 'الطالب')}</th><th>${t('Sports', 'الرياضات')}</th><th>${t('Expiry', 'الانتهاء')}</th><th class="text-right">${t('When', 'متى')}</th>
        </tr></thead><tbody>
        ${expiringRoster.map(r => `<tr>
          <td>${escapeHtml(r.name)}</td>
          <td class="text-mute">${escapeHtml((r.sports || []).join(', ') || '—')}</td>
          <td>${r.mem.expiryDate ? fmtDate(r.mem.expiryDate) : '—'}</td>
          <td class="text-right" style="${r.status === 'Expired' || (r.dLeft != null && r.dLeft < 0) ? 'color:var(--red);font-weight:600' : 'color:var(--accent-2)'}">${r.dLeft == null ? t('Expired', 'منتهية') : r.dLeft < 0 ? t(`${-r.dLeft}d ago`, `قبل ${-r.dLeft} يوم`) : r.dLeft === 0 ? t('today', 'اليوم') : t(`in ${r.dLeft}d`, `خلال ${r.dLeft} يوم`)}</td>
        </tr>`).join('')}
        </tbody></table></div>` : `<div class="text-mute" style="font-size:13px">${t('None of your students are expiring soon. 🎉', 'لا يوجد طلاب قرب الانتهاء. 🎉')}</div>`}
    </div>

    <div class="card" style="margin-bottom:16px">
      <div class="card-header"><div><div class="card-title">💰 ${t('My Salary', 'راتبي')}</div><div class="card-subtitle">${t('This month and previous months', 'هذا الشهر والأشهر السابقة')}</div></div></div>
      <div style="overflow:auto"><table class="data-table" style="width:100%"><thead><tr>
        <th>${t('Month', 'الشهر')}</th>
        <th class="text-right">${t('Fixed', 'ثابت')}</th>
        <th class="text-right">${t('Commission', 'العمولة')}</th>
        <th class="text-right">${t('Total', 'الإجمالي')}</th>
      </tr></thead><tbody>
      ${earnRows.map(({ mo, e }) => `<tr${mo === thisMonth ? ' style="background:rgba(16,185,129,.06)"' : ''}>
        <td>${fmtMonth(mo)}${mo === thisMonth ? ` <span class="text-mute" style="font-size:10px">· ${t('current', 'الحالي')}</span>` : ''}</td>
        <td class="text-right num">${fmt(e.fixed)}</td>
        <td class="text-right num" title="${fmt(e.commissionBase)} × ${e.rate}%">${fmt(e.commission)}</td>
        <td class="text-right num font-bold">${fmt(e.total)}</td>
      </tr>`).join('')}
      </tbody></table></div>
      <div class="text-mute" style="font-size:11px;margin-top:8px">${t('Commission = your rate × revenue from active members that month. Figures are estimates from recorded invoices.', 'العمولة = نسبتك × إيرادات الأعضاء النشطين في ذلك الشهر. الأرقام تقديرية من الفواتير المسجلة.')}</div>
    </div>

    <div class="card">
      <div class="card-header"><div><div class="card-title">💬 ${t('Advice', 'النصائح')}</div><div class="card-subtitle">${t('Recent notes you sent · students can reply', 'أحدث ملاحظاتك · يمكن للطلاب الرد')}</div></div>
        <button class="btn primary sm" id="ch-go-advice">${t('Write advice', 'كتابة نصيحة')} →</button>
      </div>
      ${myAdvice.length ? myAdvice.slice(0, 5).map(a => {
        const sName = (state.members.find(x => x.id === a.memberId) || {}).name || 'Student';
        const cc = (a.comments || []).length;
        return `<div style="padding:8px 10px;border:1px solid var(--border);border-radius:8px;margin-bottom:8px;background:var(--surface-2)">
          <div style="font-size:11px;color:var(--text-mute)">→ ${escapeHtml(sName)} · ${a.date ? fmtDate(a.date) : ''}${cc ? ` · 💬 ${cc}` : ''}</div>
          <div style="font-size:13px;white-space:pre-wrap;margin-top:3px">${escapeHtml(a.text || '')}</div>
        </div>`;
      }).join('') : `<div class="text-mute" style="font-size:13px">${t('You haven\u2019t sent any advice yet.', 'لم ترسل أي نصيحة بعد.')}</div>`}
    </div>`;

  const goAdv = main.querySelector('#ch-go-advice');
  if (goAdv) goAdv.addEventListener('click', () => navigate('advice'));
};

PAGES.advice = (main) => {
  const role = currentRole();
  const commentHtml = (a) => {
    const list = a.comments || [];
    const thread = list.map(c => {
      const mine = c.by === role;
      const who = c.by === 'student'
        ? ((state.members.find(x => x.id === a.memberId) || {}).name || t('Student', 'الطالب'))
        : (coachName(a.coachId) || t('Coach', 'المدرب'));
      return `<div style="margin-top:6px;padding:6px 9px;border-radius:7px;background:${c.by === 'coach' ? 'rgba(91,141,239,.10)' : 'rgba(16,185,129,.10)'};border:1px solid var(--border)">
        <div style="font-size:10px;color:var(--text-mute)">${c.by === 'coach' ? '🧑‍🏫' : '🧍'} ${escapeHtml(c.name || who)}${mine ? ' · ' + t('you', 'أنت') : ''} · ${c.date ? fmtDate(c.date) : ''}</div>
        <div style="font-size:12px;white-space:pre-wrap;margin-top:2px">${escapeHtml(c.text || '')}</div>
      </div>`;
    }).join('');
    // Both coach and student can reply; admin overview (no role match) is read-only.
    const canReply = role === 'student' || role === 'coach';
    const replyBox = canReply ? `<div style="display:flex;gap:6px;margin-top:8px">
        <input class="adv-c-input" data-aid="${a.id}" placeholder="${t('Write a reply…', 'اكتب رداً…')}" style="flex:1" />
        <button class="btn ghost sm adv-c-send" data-aid="${a.id}">${t('Reply', 'رد')}</button>
      </div>` : '';
    return (thread || replyBox) ? `<div style="margin-top:8px;padding-top:8px;border-top:1px dashed var(--border)">${thread}${replyBox}</div>` : '';
  };
  const fmtAdvice = a => {
    const who = role === 'student'
      ? (coachName(a.coachId) || 'Coach')
      : ((state.members.find(x => x.id === a.memberId) || {}).name || 'Student');
    return `<div style="padding:10px 12px;border:1px solid var(--border);border-radius:8px;margin-bottom:8px;background:var(--surface-2)">
      <div style="display:flex;justify-content:space-between;gap:8px;align-items:center">
        <div style="font-size:11px;color:var(--text-mute)">${escapeHtml(who)} · ${a.date ? fmtDate(a.date) : ''}</div>
        ${role !== 'student' && role === 'coach' ? `<button class="btn ghost" data-del-advice="${a.id}" style="padding:2px 8px;font-size:11px">${t('Delete', 'حذف')}</button>` : ''}
      </div>
      <div style="font-size:13px;white-space:pre-wrap;margin-top:4px">${escapeHtml(a.text || '')}</div>
      ${commentHtml(a)}
    </div>`;
  };

  // Add a reply to an advice thread (works for student and coach views).
  const wireReplies = () => {
    main.querySelectorAll('.adv-c-send').forEach(btn => btn.addEventListener('click', () => {
      const aid = parseInt(btn.dataset.aid);
      const inp = main.querySelector(`.adv-c-input[data-aid="${aid}"]`);
      const text = (inp && inp.value || '').trim();
      if (!text) { toast(t('Write a reply first', 'اكتب رداً أولاً'), 'error'); return; }
      const a = (state.advices || []).find(x => x.id === aid);
      if (!a) return;
      if (!Array.isArray(a.comments)) a.comments = [];
      const name = role === 'student'
        ? ((state.members.find(x => x.id === a.memberId) || {}).name || 'Student')
        : (coachName(a.coachId) || 'Coach');
      a.comments.push({ by: role, name, text, date: TODAY });
      if (typeof audit === 'function') audit('advice.comment', `advice:${aid}`, `${role} reply`);
      save(); render(); toast(t('Reply posted', 'تم نشر الرد'));
    }));
  };


  // Student: read-only list of advice addressed to them.
  if (role === 'student') {
    const meId = (typeof effectiveMemberId === 'function') ? effectiveMemberId() : (state.user && state.user.memberId);
    const list = (state.advices || []).filter(a => a.memberId === meId).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    main.innerHTML = `<div class="topbar"><div><h1>💬 ${t('My Advice', 'نصائحي')}</h1><div class="subtitle">${t('Notes and tips from your coach', 'ملاحظات ونصائح من مدربك')}</div></div></div>
      <div class="card">${list.length ? list.map(fmtAdvice).join('') : `<div class="text-mute" style="font-size:13px">${t('No advice from your coach yet.', 'لا توجد نصائح من مدربك بعد.')}</div>`}</div>`;
    wireReplies();
    return;
  }

  const coachId = (typeof effectiveCoachId === 'function') ? effectiveCoachId() : null;

  // Admin (not previewing a specific coach): read-only overview of all advice.
  if (coachId == null) {
    const all = (state.advices || []).slice().sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    main.innerHTML = `<div class="topbar"><div><h1>💬 Coach Advice</h1><div class="subtitle">All advice coaches have sent to students</div></div></div>
      <div class="card">
        <div class="text-mute" style="font-size:12px;margin-bottom:10px">To write advice, open the app as a specific coach (Users &amp; Roles → Preview as coach).</div>
        ${all.length ? all.map(a => `<div style="padding:8px 10px;border-top:1px solid var(--border);font-size:13px">
            <b>${escapeHtml((state.coaches.find(c => c.id === a.coachId) || {}).name || 'Coach')}</b> → ${escapeHtml((state.members.find(x => x.id === a.memberId) || {}).name || 'Student')}
            <span class="text-mute">· ${a.date ? fmtDate(a.date) : ''}</span>
            <div style="white-space:pre-wrap;margin-top:2px">${escapeHtml(a.text || '')}</div>
          </div>`).join('') : '<div class="text-mute" style="font-size:13px">No advice yet.</div>'}
      </div>`;
    return;
  }

  // Coach: compose + list of advice they've sent.
  const students = coachStudents(coachId).filter(s => !s.deleted).slice().sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  const sent = (state.advices || []).filter(a => a.coachId === coachId).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  main.innerHTML = `
    <div class="topbar"><div><h1>💬 Coach Advice</h1><div class="subtitle">Send advice to your students</div></div></div>
    <div class="card">
      <div class="card-header"><div><div class="card-title">${t('New advice', 'نصيحة جديدة')}</div></div></div>
      <div class="field"><label>Student</label>
        <select id="adv-student">${students.length ? students.map(s => `<option value="${s.id}">${escapeHtml(s.name)}</option>`).join('') : '<option value="">No students assigned to you</option>'}</select>
      </div>
      <div class="field"><label>Advice</label><textarea id="adv-text" rows="3" placeholder="Write a note for this student…" style="display:block;width:100%;min-height:84px;resize:vertical;padding:10px 14px;background:var(--surface-2);border:1.5px solid var(--border);border-radius:var(--r-md);color:var(--text);font-size:14px;box-sizing:border-box"></textarea></div>
      <button class="btn primary" id="adv-send" ${students.length ? '' : 'disabled'}>Send advice</button>
    </div>
    <div class="card" style="margin-top:14px">
      <div class="card-header"><div><div class="card-title">Sent advice (${sent.length})</div></div></div>
      ${sent.length ? sent.map(fmtAdvice).join('') : '<div class="text-mute" style="font-size:13px">You haven\u2019t sent any advice yet.</div>'}
    </div>`;
  const sendBtn = main.querySelector('#adv-send');
  if (sendBtn) sendBtn.addEventListener('click', () => {
    const mid = parseInt(main.querySelector('#adv-student').value);
    const text = (main.querySelector('#adv-text').value || '').trim();
    if (!mid) { toast('Pick a student', 'error'); return; }
    if (!text) { toast('Write some advice first', 'error'); return; }
    state.advices.push({ id: nextId(state.advices), memberId: mid, coachId, text, date: TODAY });
    if (typeof audit === 'function') audit('advice.create', `member:${mid}`, `Advice to ${(state.members.find(x => x.id === mid) || {}).name || mid}`);
    save(); render(); toast('Advice sent');
  });
  main.querySelectorAll('[data-del-advice]').forEach(btn => btn.addEventListener('click', () => {
    const id = parseInt(btn.dataset.delAdvice);
    if (!confirm('Delete this advice?')) return;
    state.advices = (state.advices || []).filter(a => !(a.id === id && a.coachId === coachId));
    save(); render(); toast('Advice deleted');
  }));
  wireReplies();
};

// ─── Advice & Articles (broadcast: coach→students, admin→coaches+members) ─────
// Audience targeting, read receipts and reply threads. Recipients auto-mark read
// on view; authors + admin see who has read each post.
PAGES.posts = (main) => {
  const role = currentRole();
  const meMemberId = (role === 'student') ? ((typeof effectiveMemberId === 'function') ? effectiveMemberId() : null) : null;
  const meCoachId  = (role === 'coach')   ? ((typeof effectiveCoachId  === 'function') ? effectiveCoachId()  : null) : null;
  const isAdmin = (role === 'admin');
  const isRecep = (role === 'receptionist');
  const TXTAREA = 'display:block;width:100%;min-height:84px;resize:vertical;padding:10px 14px;background:var(--surface-2);border:1.5px solid var(--border);border-radius:var(--r-md);color:var(--text);font-size:14px;box-sizing:border-box';

  // Recipients auto-mark posts as read when they open this screen.
  if (meMemberId != null) postsForUser('member', meMemberId).forEach(p => markPostRead(p.id, 'member', meMemberId));
  if (meCoachId  != null) postsForUser('coach',  meCoachId ).forEach(p => markPostRead(p.id, 'coach',  meCoachId));

  const audienceLabel = (p) => {
    const a = p.audience || {};
    if (p.authorRole === 'coach') {
      if (a.scope === 'sport') return t('Sport', 'رياضة') + ': ' + escapeHtml(a.sport || '');
      if (a.scope === 'custom') return t('Selected students', 'طلاب محددون') + ' (' + (a.memberIds || []).length + ')';
      return t('All my students', 'كل طلابي');
    }
    const co = a.includeCoaches ? ' + ' + t('coaches', 'المدربون') : '';
    if (a.scope === 'sport') return escapeHtml(a.sport || '') + co;
    if (a.scope === 'custom') return t('Specific people', 'أشخاص محددون');
    return t('Everyone', 'الجميع') + co;
  };
  const readBadge = (p) => { const r = postReadCount(p); return `<span class="badge" style="background:rgba(91,141,239,.15);color:var(--blue)">👁 ${r.read}/${r.total} ${t('read', 'قرؤوا')}</span>`; };
  const readList = (p) => {
    const recips = p.recipients || [];
    const readKeys = new Set(Object.keys(p.readBy || {}).filter(k => recips.includes(k)));
    const readNames = [...readKeys].map(postRecipientName);
    const unreadNames = recips.filter(k => !readKeys.has(k)).map(postRecipientName);
    return `<details style="margin-top:6px"><summary style="cursor:pointer;font-size:11px;color:var(--text-mute)">${t('Who read it', 'من قرأها')}</summary>
      <div style="font-size:11px;margin-top:4px">
        <div style="color:var(--green)">✓ ${t('Read', 'قرأ')} (${readNames.length}): ${readNames.map(escapeHtml).join(', ') || '—'}</div>
        <div style="color:var(--text-mute);margin-top:2px">○ ${t('Not yet', 'لم تُقرأ بعد')} (${unreadNames.length}): ${unreadNames.map(escapeHtml).join(', ') || '—'}</div>
      </div></details>`;
  };
  const threadHtml = (p, canReply) => {
    const list = p.comments || [];
    const thread = list.map(c => {
      const tone = c.by === 'admin' ? 'rgba(245,158,11,.12)' : c.by === 'coach' ? 'rgba(91,141,239,.10)' : 'rgba(16,185,129,.10)';
      const icon = c.by === 'admin' ? '🛡️' : c.by === 'coach' ? '🧑‍🏫' : '🧍';
      return `<div style="margin-top:6px;padding:6px 9px;border-radius:7px;background:${tone};border:1px solid var(--border)">
        <div style="font-size:10px;color:var(--text-mute)">${icon} ${escapeHtml(c.name || '')} · ${c.date ? fmtDate(c.date) : ''}</div>
        <div style="font-size:12px;white-space:pre-wrap;margin-top:2px">${escapeHtml(c.text || '')}</div>
      </div>`;
    }).join('');
    const box = canReply ? `<div style="display:flex;gap:6px;margin-top:8px">
        <input class="post-c-input" data-pid="${p.id}" placeholder="${t('Write a reply…', 'اكتب رداً…')}" style="flex:1" />
        <button class="btn ghost sm post-c-send" data-pid="${p.id}">${t('Reply', 'رد')}</button>
      </div>` : '';
    return (thread || box) ? `<div style="margin-top:8px;padding-top:8px;border-top:1px dashed var(--border)">${thread}${box}</div>` : '';
  };
  const postCard = (p, opts) => {
    opts = opts || {};
    const authorIcon = p.authorRole === 'admin' ? '🛡️' : '🧑‍🏫';
    return `<div style="padding:12px 14px;border:1px solid var(--border);border-radius:10px;margin-bottom:10px;background:var(--surface-2)">
      <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start">
        <div>${p.title ? `<div style="font-weight:700;font-size:14px">${escapeHtml(p.title)}</div>` : ''}
          <div style="font-size:11px;color:var(--text-mute)">${authorIcon} ${escapeHtml(p.authorName || '')} · ${p.date ? fmtDate(p.date) : ''} · ${audienceLabel(p)}</div></div>
        <div style="display:flex;gap:6px;align-items:center">${opts.showStats ? readBadge(p) : ''}${opts.canDelete ? `<button class="btn ghost sm" data-del-post="${p.id}" style="padding:2px 8px">${t('Delete', 'حذف')}</button>` : ''}</div>
      </div>
      <div style="font-size:13px;white-space:pre-wrap;margin-top:6px">${escapeHtml(p.text || '')}</div>
      ${opts.showStats ? readList(p) : ''}
      ${threadHtml(p, opts.canReply)}
    </div>`;
  };

  let html = '';

  // ── STUDENT (member): posts addressed to me ──
  if (role === 'student') {
    const list = (meMemberId != null) ? postsForUser('member', meMemberId) : [];
    html = `<div class="topbar"><div><h1>📢 ${t('Advice & Articles', 'النصائح والمقالات')}</h1><div class="subtitle">${t('Messages from your coach and the club', 'رسائل من مدربك ومن النادي')}</div></div></div>
      <div class="card">${list.length ? list.map(p => postCard(p, { canReply: true })).join('') : `<div class="text-mute" style="font-size:13px">${t('Nothing here yet.', 'لا يوجد شيء بعد.')}</div>`}</div>`;
  }
  // ── COACH: received (from admin) + composer + sent ──
  else if (role === 'coach' && meCoachId != null) {
    const received = postsForUser('coach', meCoachId);
    const sent = (state.posts || []).filter(p => p.authorRole === 'coach' && p.authorId === meCoachId).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    const mine = coachStudents(meCoachId).filter(s => !s.deleted);
    const sports = [...new Set(mine.flatMap(s => s.sports || []))].sort();
    html = `<div class="topbar"><div><h1>📢 ${t('Advice & Articles', 'النصائح والمقالات')}</h1><div class="subtitle">${t('Publish advice to your students', 'انشر نصائح لطلابك')}</div></div></div>
      ${received.length ? `<div class="card"><div class="card-header"><div><div class="card-title">📥 ${t('From the club', 'من النادي')}</div></div></div>${received.map(p => postCard(p, { canReply: true })).join('')}</div>` : ''}
      <div class="card" style="margin-top:14px">
        <div class="card-header"><div><div class="card-title">📢 ${t('Publish advice', 'نشر نصيحة')}</div><div class="card-subtitle">${t('Your students get a notification', 'يصل طلابك إشعار')}</div></div></div>
        <div class="field"><label>${t('Audience', 'الجمهور')}</label>
          <select id="post-scope">
            <option value="all">${t('All my students', 'كل طلابي')} (${mine.length})</option>
            <option value="sport">${t('By sport', 'حسب الرياضة')}</option>
            <option value="custom">${t('Pick students', 'اختيار طلاب')}</option>
          </select></div>
        <div class="field" id="post-sport-wrap" style="display:none"><label>${t('Sport', 'الرياضة')}</label>
          <select id="post-sport">${sports.map(s => `<option value="${escapeHtml(s)}">${escapeHtml(s)}</option>`).join('')}</select></div>
        <div class="field" id="post-pick-wrap" style="display:none"><label>${t('Students', 'الطلاب')}</label>
          <div style="max-height:160px;overflow:auto;border:1px solid var(--border);border-radius:8px;padding:8px">${mine.length ? mine.map(s => `<label style="display:block;font-size:13px;padding:2px 0"><input type="checkbox" class="post-mem" value="${s.id}"> ${escapeHtml(s.name)} <span class="text-mute" style="font-size:10px">${escapeHtml((s.sports || []).join(', '))}</span></label>`).join('') : `<span class="text-mute">${t('No students', 'لا يوجد طلاب')}</span>`}</div></div>
        <div class="field"><label>${t('Title (optional)', 'العنوان (اختياري)')}</label><input id="post-title" placeholder="${t('e.g. Training tips', 'مثال: نصائح تدريبية')}" /></div>
        <div class="field"><label>${t('Message', 'الرسالة')}</label><textarea id="post-text" rows="3" style="${TXTAREA}"></textarea></div>
        <button class="btn primary" id="post-publish" ${mine.length ? '' : 'disabled'}>📢 ${t('Publish', 'نشر')}</button>
      </div>
      <div class="card" style="margin-top:14px"><div class="card-header"><div><div class="card-title">${t('Published', 'المنشورة')} (${sent.length})</div></div></div>
        ${sent.length ? sent.map(p => postCard(p, { showStats: true, canReply: true, canDelete: true })).join('') : `<div class="text-mute" style="font-size:13px">${t('You have not published anything yet.', 'لم تنشر شيئاً بعد.')}</div>`}</div>`;
  }
  // ── ADMIN / RECEPTIONIST: composer (admin) + all posts (read stats) ──
  else {
    const allMembers = _activeMembersForPosts().slice().sort((a, b) => (a.name || '').localeCompare(b.name || ''));
    const allCoaches = (state.coaches || []).filter(c => !c.deleted).slice().sort((a, b) => (a.name || '').localeCompare(b.name || ''));
    const allSports = [...new Set([...(state.members || []).flatMap(m => [m.sport, ...((m.enrollments || []).map(e => e.sport))])].filter(Boolean))].sort();
    const myPosts = (state.posts || []).filter(p => p.authorRole === 'admin').sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    const coachPosts = (state.posts || []).filter(p => p.authorRole === 'coach').sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    const composer = isAdmin ? `
      <div class="card">
        <div class="card-header"><div><div class="card-title">📢 ${t('Publish advice / article', 'نشر نصيحة / مقال')}</div><div class="card-subtitle">${t('Coaches and members get a notification', 'يصل المدربين والأعضاء إشعار')}</div></div></div>
        <div class="field"><label>${t('Audience', 'الجمهور')}</label>
          <select id="post-scope">
            <option value="all">${t('Everyone', 'الجميع')}</option>
            <option value="sport">${t('By sport', 'حسب الرياضة')}</option>
            <option value="custom">${t('Specific people', 'أشخاص محددون')}</option>
          </select></div>
        <div class="field" id="post-coach-wrap"><label style="display:flex;align-items:center;gap:8px;font-weight:400"><input type="checkbox" id="post-inc-coaches" checked> ${t('Also notify coaches', 'إشعار المدربين أيضاً')}</label></div>
        <div class="field" id="post-sport-wrap" style="display:none"><label>${t('Sport', 'الرياضة')}</label>
          <select id="post-sport">${allSports.map(s => `<option value="${escapeHtml(s)}">${escapeHtml(s)}</option>`).join('')}</select></div>
        <div class="field" id="post-pick-wrap" style="display:none"><label>${t('Members', 'الأعضاء')}</label>
          <div style="max-height:140px;overflow:auto;border:1px solid var(--border);border-radius:8px;padding:8px">${allMembers.map(m => `<label style="display:block;font-size:13px;padding:2px 0"><input type="checkbox" class="post-mem" value="${m.id}"> ${escapeHtml(m.name || m.nameArabic || ('#' + m.id))}</label>`).join('') || `<span class="text-mute">${t('No members', 'لا يوجد أعضاء')}</span>`}</div>
          <label style="margin-top:8px">${t('Coaches', 'المدربون')}</label>
          <div style="max-height:120px;overflow:auto;border:1px solid var(--border);border-radius:8px;padding:8px">${allCoaches.map(c => `<label style="display:block;font-size:13px;padding:2px 0"><input type="checkbox" class="post-coach" value="${c.id}"> ${escapeHtml(c.name || ('#' + c.id))}</label>`).join('') || `<span class="text-mute">${t('No coaches', 'لا يوجد مدربون')}</span>`}</div></div>
        <div class="field"><label>${t('Title (optional)', 'العنوان (اختياري)')}</label><input id="post-title" placeholder="${t('e.g. Eid holiday schedule', 'مثال: جدول إجازة العيد')}" /></div>
        <div class="field"><label>${t('Message', 'الرسالة')}</label><textarea id="post-text" rows="3" style="${TXTAREA}"></textarea></div>
        <button class="btn primary" id="post-publish">📢 ${t('Publish', 'نشر')}</button>
      </div>` : '';
    html = `<div class="topbar"><div><h1>📢 ${t('Advice & Articles', 'النصائح والمقالات')}</h1><div class="subtitle">${t('Publish announcements and track who has read them', 'انشر الإعلانات وتابع من قرأها')}</div></div></div>
      ${composer}
      ${myPosts.length ? `<div class="card" style="margin-top:14px"><div class="card-header"><div><div class="card-title">🛡️ ${t('Club announcements', 'إعلانات النادي')} (${myPosts.length})</div></div></div>${myPosts.map(p => postCard(p, { showStats: true, canReply: isAdmin, canDelete: isAdmin })).join('')}</div>` : ''}
      <div class="card" style="margin-top:14px"><div class="card-header"><div><div class="card-title">💬 ${t('Coach advice (all)', 'نصائح المدربين (الكل)')} (${coachPosts.length})</div><div class="card-subtitle">${t('Read-only overview of what coaches have published', 'عرض للقراءة فقط لما نشره المدربون')}</div></div></div>
        ${coachPosts.length ? coachPosts.map(p => postCard(p, { showStats: true })).join('') : `<div class="text-mute" style="font-size:13px">${t('No coach advice yet.', 'لا توجد نصائح من المدربين بعد.')}</div>`}</div>`;
  }

  main.innerHTML = html;

  // ── Wire composer audience toggles ──
  const scopeSel = main.querySelector('#post-scope');
  const syncScope = () => {
    const v = scopeSel ? scopeSel.value : 'all';
    const sw = main.querySelector('#post-sport-wrap'); if (sw) sw.style.display = (v === 'sport') ? '' : 'none';
    const pw = main.querySelector('#post-pick-wrap'); if (pw) pw.style.display = (v === 'custom') ? '' : 'none';
    const cw = main.querySelector('#post-coach-wrap'); if (cw) cw.style.display = (v === 'custom') ? 'none' : '';
  };
  if (scopeSel) { scopeSel.addEventListener('change', syncScope); syncScope(); }

  // ── Wire publish ──
  const pubBtn = main.querySelector('#post-publish');
  if (pubBtn) pubBtn.addEventListener('click', () => {
    const scope = scopeSel ? scopeSel.value : 'all';
    const title = (main.querySelector('#post-title') || {}).value || '';
    const text = ((main.querySelector('#post-text') || {}).value || '').trim();
    if (!text) { toast(t('Write a message first', 'اكتب رسالة أولاً'), 'error'); return; }
    const audience = { scope };
    if (scope === 'sport') audience.sport = (main.querySelector('#post-sport') || {}).value || '';
    if (scope === 'custom') {
      audience.memberIds = [...main.querySelectorAll('.post-mem:checked')].map(x => parseInt(x.value));
      audience.coachIds = [...main.querySelectorAll('.post-coach:checked')].map(x => parseInt(x.value));
    }
    let res;
    if (role === 'coach') {
      res = publishPost({ authorRole: 'coach', authorId: meCoachId, authorName: coachName(meCoachId) || 'Coach', title, text, audience });
    } else {
      audience.includeCoaches = !!(main.querySelector('#post-inc-coaches') && main.querySelector('#post-inc-coaches').checked);
      res = publishPost({ authorRole: 'admin', authorId: null, authorName: t('Club Admin', 'إدارة النادي'), title, text, audience });
    }
    if (!res) { toast(t('No recipients match this audience', 'لا يوجد مستلمون لهذا الجمهور'), 'error'); return; }
    render(); toast(t('Published', 'تم النشر') + ' · ' + res.recipients.length + ' ' + t('recipients', 'مستلم'));
  });

  // ── Wire replies ──
  main.querySelectorAll('.post-c-send').forEach(btn => btn.addEventListener('click', () => {
    const pid = parseInt(btn.dataset.pid);
    const inp = main.querySelector(`.post-c-input[data-pid="${pid}"]`);
    const text = ((inp && inp.value) || '').trim();
    if (!text) { toast(t('Write a reply first', 'اكتب رداً أولاً'), 'error'); return; }
    const p = (state.posts || []).find(x => x.id === pid);
    if (!p) return;
    if (!Array.isArray(p.comments)) p.comments = [];
    const by = (role === 'student') ? 'member' : (role === 'coach' ? 'coach' : 'admin');
    const name = by === 'member' ? ((state.members.find(x => x.id === meMemberId) || {}).name || t('Member', 'عضو'))
      : by === 'coach' ? (coachName(meCoachId) || t('Coach', 'مدرب'))
      : t('Club Admin', 'إدارة النادي');
    p.comments.push({ by, name, text, date: TODAY });
    if (typeof audit === 'function') audit('post.comment', `post:${pid}`, `${by} reply`);
    save(); render(); toast(t('Reply posted', 'تم نشر الرد'));
  }));

  // ── Wire delete ──
  main.querySelectorAll('[data-del-post]').forEach(btn => btn.addEventListener('click', () => {
    const id = parseInt(btn.dataset.delPost);
    if (!confirm(t('Delete this post?', 'حذف هذا المنشور؟'))) return;
    state.posts = (state.posts || []).filter(p => p.id !== id);
    save(); render(); toast(t('Deleted', 'تم الحذف'));
  }));
};

// Change the signed-in account's password. Stored by Firebase Auth (never in our
// data). `force` = first-login default-password change.
window.promptPasswordChange = function(force) {
  const myMobile = (() => {
    const id = state.user && state.user.email;
    return isMemberEmail(id) ? id.split('@')[0].replace(/\D/g, '') : '';
  })();
  showModal({
    title: force ? t('🔐 Set a new password', '🔐 تعيين كلمة مرور جديدة') : t('🔐 Change password', '🔐 تغيير كلمة المرور'),
    body: `<div style="font-size:13px;line-height:1.7">
        ${force ? `<p>${t('For your security, please replace the default password (your mobile number) with one only you know.', 'لحماية حسابك، يرجى استبدال كلمة المرور الافتراضية (رقم جوالك) بكلمة تعرفها أنت فقط.')}</p>` : ''}
        <div class="field"><label>${t('New password', 'كلمة المرور الجديدة')}</label><input id="pw-new" type="password" placeholder="${t('at least 6 characters', '6 أحرف على الأقل')}" /></div>
        <div class="field"><label>${t('Confirm new password', 'تأكيد كلمة المرور')}</label><input id="pw-confirm" type="password" /></div>
        <div class="text-mute" style="font-size:11px">${t('Your password is stored securely by the sign-in system — not in the club database.', 'تُحفظ كلمة المرور بأمان في نظام الدخول — وليست في قاعدة بيانات النادي.')}</div>
      </div>`,
    actions: [
      { label: force ? t('Sign out instead', 'تسجيل الخروج بدلاً من ذلك') : t('Cancel', 'إلغاء'), class: 'btn ghost', onclick: () => { closeModal(); if (force) logout(); } },
      { label: t('Save password', 'حفظ كلمة المرور'), class: 'btn primary', onclick: async () => {
          const np = $('#pw-new').value, cf = $('#pw-confirm').value;
          if (!np || np.length < 6) { toast('Use at least 6 characters', 'error'); return; }
          if (np !== cf) { toast('Passwords don\u2019t match', 'error'); return; }
          if (myMobile && np.replace(/\D/g, '') === myMobile) { toast('Pick something other than your mobile number', 'error'); return; }
          try {
            await window.Storage.updatePassword(np);
            closeModal();
            toast('✓ Password updated');
          } catch (e) { toast(e.message || 'Could not update password', 'error'); }
        } },
    ],
  });
};

// ─── Users & Roles (admin) ─────────────────────────────────────────
// Bulk-create Firebase logins for every member (mobile number = login + default
// password). Runs client-side via a secondary Firebase app, throttled, skipping
// members who already have a login. For very large clubs the Admin-SDK script in
// tools/ is more reliable (no client rate limits).
// ─── Portal Onboarding (WhatsApp invite + auto account creation, req #6) ─────
// Account status for a member's portal login: 'Not Created' | 'Created' |
// 'Invitation Sent'. Prefers the tracked portalAccount, falls back to a userRoles
// mapping existing for the member's canonical email.
function memberAccountStatus(m) {
  const pa = m && m.portalAccount;
  if (pa && pa.status) return pa.status;
  const email = phoneToMemberEmail(m.phone);
  const map = (state.settings && state.settings.userRoles) || {};
  if (email && map[email]) return 'Created';
  return 'Not Created';
}

// Create the member's portal login (if missing), record invitation tracking, and
// open WhatsApp with the pre-filled welcome message. Admin/Reception only.
window.sendMemberInvite = async function(memberId) {
  if (!['admin', 'receptionist'].includes(currentRole())) { toast(t('Admins or receptionists only', 'للمسؤولين أو موظفي الاستقبال فقط'), 'error'); return; }
  const m = state.members.find(x => x.id === memberId);
  if (!m) return;
  const digits = canonicalMobile(m.phone);
  if (!digits || digits.length < 6) { toast(t('This member has no valid mobile number', 'لا يوجد رقم جوال صالح لهذا العضو'), 'error'); return; }
  const email = phoneToMemberEmail(m.phone);
  const pw = digits;
  if (!m.portalAccount) m.portalAccount = {};
  // Step 1 — create the login if it doesn't already exist (secondary Firebase app,
  // so the admin's own session is untouched). Role = Member (student), no extras.
  let createResult;
  try {
    createResult = await window.Storage.provisionMemberLogin(email, pw);
  } catch (err) {
    toast(t('Could not create the login (needs cloud sign-in): ', 'تعذّر إنشاء الحساب (يتطلب تسجيل الدخول السحابي): ') + (err.message || err.code || err), 'error');
    return;
  }
  if (!m.portalAccount.createdAt) m.portalAccount.createdAt = new Date().toISOString();
  if (!state.settings) state.settings = {};
  if (!state.settings.userRoles) state.settings.userRoles = {};
  if (!state.settings.userRoles[email]) {
    const entry = { role: 'student', memberId: m.id };   // Member role — no additional permissions
    stampUpdate(entry);
    state.settings.userRoles[email] = entry;
  }
  // Step 3 — invitation tracking (created date, sent date, sent by, status).
  m.portalAccount.invitedAt = new Date().toISOString();
  m.portalAccount.invitedBy = currentUserName();
  m.portalAccount.status = 'Invitation Sent';
  stampUpdate(m);
  audit('member.invite', `member:${m.id}`,
    `WhatsApp portal invite sent to ${m.name} (${email})`,
    { name: m.name, mobile: m.phone, membershipNo: m.qid || '', new: { account: email, status: 'Invitation Sent', created: createResult === 'created' } });
  save();
  // Step 2 — open WhatsApp with the pre-filled invitation message.
  const msg = [
    'Welcome to Black Stars Sports!',
    'Your account is now ready.',
    'Website: https://www.blackstarssports.com',
    'Username: ' + email,
    'Password: ' + pw,
    'Please change your password after your first login.',
  ].join('\n');
  const url = waLink(m.phone, msg);
  if (url) window.open(url, '_blank');
  toast('💬 ' + (createResult === 'created' ? t('Account created & invite opened', 'تم إنشاء الحساب وفتح الدعوة') : t('Invite opened', 'تم فتح الدعوة')) + ' — ' + m.name);
  const main = document.querySelector('.main'); if (main && typeof PAGES.onboarding === 'function') PAGES.onboarding(main);
};

PAGES.onboarding = (main) => {
  if (!['admin', 'receptionist'].includes(currentRole())) {
    main.innerHTML = `<div class="card" style="text-align:center;padding:40px"><div style="font-size:40px">🔒</div><h2>${t('Admins or receptionists only', 'للمسؤولين أو موظفي الاستقبال فقط')}</h2></div>`;
    return;
  }
  let filter = { search: '', status: 'all' };
  const pg = makePager(15);
  const STATUS_BADGE = {
    'Not Created': 'pending', 'Created': 'blue', 'Invitation Sent': 'green',
  };
  const cloudOn = !!(window.Storage && window.Storage.isCloud && window.Storage.isCloud());

  function eligible() {
    return (state.members || []).filter(m => !m.deleted && canonicalMobile(m.phone).length >= 6);
  }
  function applyFilter() {
    return eligible().filter(m => {
      const st = memberAccountStatus(m);
      if (filter.status !== 'all' && st !== filter.status) return false;
      if (filter.search) {
        const q = filter.search.toLowerCase();
        const hay = [m.name, m.nameArabic, m.phone, m.phone2, phoneToMemberEmail(m.phone)].filter(Boolean).join(' ').toLowerCase();
        if (!hay.includes(q) && !phoneQueryMatches(m.phone, filter.search)) return false;
      }
      return true;
    });
  }
  function refresh() {
    const all = applyFilter().sort((a, b) => (a.name || '').localeCompare(b.name || ''));
    const rows = paginate(all, pg);
    const counts = { 'Not Created': 0, 'Created': 0, 'Invitation Sent': 0 };
    eligible().forEach(m => { counts[memberAccountStatus(m)] = (counts[memberAccountStatus(m)] || 0) + 1; });
    $('#onb-count').textContent = `${all.length} ${t('members', 'عضو')} · ${counts['Invitation Sent']} ${t('invited', 'تمت دعوتهم')} · ${counts['Not Created']} ${t('not created', 'بدون حساب')}`;
    $('#onb-tbody').innerHTML = rows.length ? rows.map(m => {
      const st = memberAccountStatus(m);
      const pa = m.portalAccount || {};
      const email = phoneToMemberEmail(m.phone);
      const invited = pa.invitedAt ? `<div class="text-mute" style="font-size:10px">${t('Invited by', 'دعاه')} ${escapeHtml(pa.invitedBy || '—')} · ${fmtDate(pa.invitedAt.slice(0,10))}</div>` : '';
      return `<tr>
        <td><div class="font-bold">${escapeHtml(m.name || '—')}</div><div class="text-mute" style="font-size:10px;font-family:monospace">${escapeHtml(email)}</div></td>
        <td>${phoneCell(m.phone)}</td>
        <td><span class="badge ${STATUS_BADGE[st] || ''}">${t(st, st === 'Not Created' ? 'بدون حساب' : st === 'Created' ? 'تم الإنشاء' : 'تم إرسال الدعوة')}</span>${invited}</td>
        <td class="text-right">
          <button class="btn ${st === 'Invitation Sent' ? 'ghost' : 'primary'} sm" onclick="sendMemberInvite(${m.id})" style="color:${st==='Invitation Sent'?'#25D366':''}" title="${t('Create account (if needed) and open WhatsApp invite', 'إنشاء الحساب (إن لزم) وفتح دعوة واتساب')}">💬 ${st === 'Invitation Sent' ? t('Resend', 'إعادة إرسال') : t('Send WhatsApp', 'إرسال واتساب')}</button>
        </td>
      </tr>`;
    }).join('') : `<tr><td colspan="4" class="empty"><div class="empty-icon">📲</div>${t('No members match', 'لا يوجد أعضاء مطابقون')}</td></tr>`;
    $('#onb-pagination').innerHTML = paginationBar(pg, all.length, 'onb');
    bindPagination('onb', pg, all.length, refresh);
  }

  main.innerHTML = `
    <div class="topbar">
      <div>
        <h1>📲 ${t('Portal Onboarding', 'إعداد بوابة الأعضاء')}</h1>
        <div class="subtitle"><span id="onb-count">Loading…</span></div>
      </div>
    </div>
    ${cloudOn ? '' : `<div class="card" style="margin-bottom:12px;border-color:var(--accent-2);background:rgba(242,163,60,.08)"><div style="padding:10px 14px;font-size:13px">⚠️ ${t('Account creation needs the cloud (Firebase) site. On this local copy you can preview the list, but Send WhatsApp will not create logins.', 'إنشاء الحسابات يتطلب موقع Firebase السحابي. في هذه النسخة المحلية يمكنك معاينة القائمة فقط.')}</div></div>`}
    <div class="card">
      <div class="filter-bar">
        <div class="search"><input id="onb-search" type="text" placeholder="${t('Search name or mobile…', 'ابحث بالاسم أو الجوال…')}" value="${escapeHtml(filter.search)}" /></div>
        <select id="onb-status" class="btn ghost">
          <option value="all">${t('All statuses', 'كل الحالات')}</option>
          <option value="Not Created">${t('Not Created', 'بدون حساب')}</option>
          <option value="Created">${t('Created', 'تم الإنشاء')}</option>
          <option value="Invitation Sent">${t('Invitation Sent', 'تم إرسال الدعوة')}</option>
        </select>
      </div>
      <div class="table-wrap">
        <table>
          <thead><tr>
            <th>${t('Member', 'العضو')}</th>
            <th>${t('Mobile', 'الجوال')}</th>
            <th>${t('Account Status', 'حالة الحساب')}</th>
            <th class="text-right">${t('WhatsApp', 'واتساب')}</th>
          </tr></thead>
          <tbody id="onb-tbody"></tbody>
        </table>
      </div>
      <div id="onb-pagination"></div>
    </div>
  `;
  $('#onb-search').addEventListener('input', e => { filter.search = e.target.value; pg.page = 1; refresh(); });
  $('#onb-status').addEventListener('change', e => { filter.status = e.target.value; pg.page = 1; refresh(); });
  refresh();
};

window.generateMemberLogins = function() {
  if (!window.Storage.isCloud || !window.Storage.isCloud()) { toast('This only works on the cloud (Firebase) site.', 'error'); return; }
  const all = (state.members || []).filter(m => !m.deleted);
  // Anyone with a valid mobile gets a login (emails are unreliable placeholders).
  const eligible = all.filter(m => canonicalMobile(m.phone).length >= 6);
  const tooShort = all.length - eligible.length;
  showModal({
    title: '🔐 Generate member logins',
    body: `<div style="font-size:13px;line-height:1.7">
        <p>This creates a sign-in for <b>${eligible.length}</b> member${eligible.length === 1 ? '' : 's'} who have a mobile number.</p>
        <ul style="margin:6px 0 6px 18px;padding:0">
          <li>Login (username) = <b>mobile</b>@${MEMBER_EMAIL_DOMAIN} (e.g. 50413948@${MEMBER_EMAIL_DOMAIN})</li>
          <li>First-time password = their <b>mobile number</b> (they'll be asked to change it)</li>
          <li>Members who already have a login are skipped</li>
        </ul>
        ${tooShort ? `<p class="text-mute" style="font-size:12px">${tooShort} member(s) have a missing/short mobile and will be skipped.</p>` : ''}
        <p class="text-mute" style="font-size:12px">It runs in your browser and may take a minute. Keep this tab open. If you hit a rate limit, run it again later or use the script in <code>tools/</code>.</p>
        <div id="gml-progress" style="margin-top:8px;font-weight:600"></div>
      </div>`,
    actions: [
      { label: 'Cancel', class: 'btn ghost', onclick: closeModal },
      { label: 'Create logins', class: 'btn primary', onclick: async (ev) => {
          const prog = document.getElementById('gml-progress');
          let created = 0, existed = 0, failed = 0, i = 0;
          const btn = ev && ev.target; if (btn) { btn.disabled = true; btn.textContent = 'Working…'; }
          for (const m of eligible) {
            i++;
            const email = phoneToMemberEmail(m.phone);
            const pw = canonicalMobile(m.phone);
            try {
              const r = await window.Storage.provisionMemberLogin(email, pw);
              if (r === 'created') created++; else existed++;
            } catch (e) {
              failed++;
              if (e && e.code === 'auth/too-many-requests') { if (prog) prog.textContent = `Rate-limited after ${i}. Created ${created}, skipped ${existed}. Try again later for the rest.`; break; }
            }
            if (prog) prog.textContent = `${i}/${eligible.length} · created ${created}, existing ${existed}${failed ? `, failed ${failed}` : ''}`;
            await new Promise(res => setTimeout(res, 150));   // throttle to ease rate limits
          }
          audit('members.provision_logins', null, `Generated member logins (mobile@${MEMBER_EMAIL_DOMAIN}): created ${created}, existing ${existed}, failed ${failed}`);
          if (prog) prog.textContent = `Done. Created ${created}, already had a login ${existed}${failed ? `, failed ${failed}` : ''}.`;
          if (btn) { btn.textContent = 'Done'; }
          toast(`Member logins: ${created} created, ${existed} existing${failed ? `, ${failed} failed` : ''}`, failed ? 'error' : 'success');
        } },
    ],
  });
};

function userRolesListHtml() {
  const map = (state.settings && state.settings.userRoles) || {};
  const emails = Object.keys(map);
  if (!emails.length) return `<div class="text-mute" style="font-size:12px;padding:8px 0">No mappings yet — every signed-in account is currently <b>Admin</b>. Add your admin email plus your coach/member logins below.</div>`;
  const rows = emails.sort().map(e => {
    const r = map[e] || {};
    let linked;
    if (r.role === 'coach') linked = escapeHtml(coachName(r.coachId) || '— pick a coach —');
    else if (r.role === 'student') { const m = state.members.find(x => x.id === r.memberId); linked = m ? escapeHtml(m.name) : '<span class="text-mute">— pick a member —</span>'; }
    else if (r.role === 'receptionist') linked = '<span class="text-mute">front-desk, read-only finance</span>';
    else linked = '<span class="text-mute">full access</span>';
    return `<tr style="border-top:1px solid var(--border)${r.disabled ? ';opacity:.55' : ''}">
      <td style="padding:6px 8px;font-family:monospace;font-size:12px">${escapeHtml(e)}</td>
      <td style="padding:6px 8px"><span class="badge">${ROLE_LABELS[r.role] || r.role}</span>${r.disabled ? ' <span class="badge" style="background:var(--red);color:#fff">revoked</span>' : ''}</td>
      <td style="padding:6px 8px;font-size:12px">${linked}</td>
      <td style="padding:6px 8px;text-align:right;white-space:nowrap">
        <button class="btn ghost sm" onclick="editUserRole('${escapeHtml(e)}')" title="Edit">✏️</button>
        ${!e.endsWith('@' + MEMBER_EMAIL_DOMAIN) ? `<button class="btn ghost sm" onclick="sendUserReset('${escapeHtml(e)}')" title="Email a password-reset link">✉️</button>` : ''}
        <button class="btn ghost sm" onclick="toggleUserDisabled('${escapeHtml(e)}')" title="${r.disabled ? 'Restore access' : 'Revoke access (block sign-in)'}">${r.disabled ? '▶' : '⏸'}</button>
        <button class="btn ghost sm" onclick="removeUserRole('${escapeHtml(e)}')" title="Remove mapping">🗑</button>
      </td></tr>`;
  }).join('');
  return `<table style="width:100%;border-collapse:collapse"><thead><tr style="text-align:left;font-size:11px;color:var(--text-mute)"><th style="padding:4px 8px">Email</th><th style="padding:4px 8px">Role</th><th style="padding:4px 8px">Linked to</th><th></th></tr></thead><tbody>${rows}</tbody></table>`;
}
window.renderUserRolesList = function() { const elx = document.getElementById('user-roles-list'); if (elx) elx.innerHTML = userRolesListHtml(); const s = document.getElementById('user-roles-summary'); if (s) s.innerHTML = userRolesSummaryHtml(); };
function userRolesSummaryHtml() {
  const map = (state.settings && state.settings.userRoles) || {};
  let admins = 0, coaches = 0, students = 0, receptionists = 0, revoked = 0;
  for (const k in map) { const r = map[k] || {}; if (r.disabled) revoked++; if (r.role === 'admin') admins++; else if (r.role === 'coach') coaches++; else if (r.role === 'receptionist') receptionists++; else if (r.role === 'student') students++; }
  const memberCount = (state.members || []).filter(m => !m.deleted).length;
  const pill = (n, label, color) => `<span style="display:inline-flex;align-items:center;gap:4px;font-size:12px;padding:3px 9px;border-radius:20px;background:${color};color:#fff;font-weight:600">${n} ${label}</span>`;
  return `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:4px">
    ${pill(admins, admins === 1 ? 'Admin' : 'Admins', 'var(--accent-2)')}
    ${receptionists ? pill(receptionists, receptionists === 1 ? 'Receptionist' : 'Receptionists', '#0ea5e9') : ''}
    ${pill(coaches, coaches === 1 ? 'Coach' : 'Coaches', 'var(--blue)')}
    ${pill(students, 'mapped Students', 'var(--purple)')}
    ${pill(memberCount, 'Members → Student', 'var(--green)')}
    ${revoked ? pill(revoked, 'revoked', 'var(--red)') : ''}
  </div>`;
}
window.lookupUserRole = function() {
  const el = document.getElementById('ur-lookup'); const out = document.getElementById('ur-lookup-result');
  if (!el || !out) return;
  const raw = (el.value || '').trim();
  if (!raw) { out.innerHTML = ''; return; }
  // Resolve the same way login does: a phone-like entry becomes a member email.
  const looksPhone = !raw.includes('@') && raw.replace(/\D/g, '').length >= 6;
  const email = looksPhone ? phoneToMemberEmail(raw) : raw.toLowerCase();
  const map = (state.settings && state.settings.userRoles) || {};
  const mapped = map[email];
  const r = roleForEmail(email);
  let linked = '';
  if (r.role === 'coach') linked = ' · ' + (coachName(r.coachId) || 'unlinked coach');
  else if (r.role === 'student') { const m = state.members.find(x => x.id === r.memberId); linked = m ? ' · ' + escapeHtml(m.name) : (looksPhone ? ' · no member matches this mobile' : ''); }
  const how = mapped ? 'mapped explicitly' : (isMemberEmail(email) ? 'member mobile login' : 'not mapped → default');
  const revoked = mapped && mapped.disabled ? ' <span class="badge" style="background:var(--red);color:#fff">revoked</span>' : '';
  const upd = (mapped && mapped.updatedAt) ? `<div class="text-mute" style="font-size:11px;margin-top:2px">🕓 ${t('Last updated by', 'آخر تعديل بواسطة')} <b>${escapeHtml(mapped.updatedByName || mapped.updatedBy)}</b> · ${fmtDateTime(mapped.updatedAt)}</div>` : '';
  out.innerHTML = `<div style="padding:8px 10px;background:var(--surface);border:1px solid var(--border);border-radius:8px">
    <span style="font-family:monospace;font-size:12px">${escapeHtml(email)}</span> → <span class="badge">${ROLE_LABELS[r.role] || r.role}</span>${revoked}${escapeHtml(linked)}
    <div class="text-mute" style="font-size:11px;margin-top:2px">${how}</div>${upd}</div>`;
};
